// FASE 2: debounce — prevents excessive calls on rapid input events
function debounce(fn, ms = 120) {
  let timer;
  return function (...args) { clearTimeout(timer); timer = setTimeout(() => fn.apply(this, args), ms); };
}

// FASE 2: srch — O(1) search using pre-built _searchIdx (set at import time)
function srch(r, s) {
  if (!s) return true;
  return r._searchIdx ? r._searchIdx.includes(s) : Object.values(r).some(v => String(v).toLowerCase().includes(s));
}

// FASE 3: __DEV flag — set to true for verbose error logging
window.__DEV = (location.hostname === 'localhost' || location.hostname === '127.0.0.1' || location.search.includes('dev=1'));

// FASE 3: memoized aggStats — result cached per DB reference, invalidated on launchApp
const _aggStatsCache = new Map();
function _aggStatsCacheKey(arr) { return arr.length + '_' + (arr[0]?._uid || 0) + '_' + (arr[arr.length - 1]?._uid || 0); }

