function applyTheme(mode) {
  const t = (mode === 'light') ? 'light' : 'dark';
  document.documentElement.setAttribute('data-theme', t);
  updateSidebarFab();
  try { localStorage.setItem('nexus_theme', t); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  // Sync APP_CFG
  try {
    const cfg = window.APP_CFG || {};
    cfg.themeMode = t;
    window.APP_CFG = cfg;
    if (typeof saveAppCfg === 'function') saveAppCfg();
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  const lbl = document.getElementById('themeMode');
  if (lbl) lbl.textContent = t.toUpperCase();
  // Force Tabulator redraw on theme change
  try {
    if (window._etapaTabs) {
      if (window._etapaTabs.status) window._etapaTabs.status.redraw(true);
      if (window._etapaTabs.rota) window._etapaTabs.rota.redraw(true);
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  // refresh etapa visuals on theme change
  try {
    if (document.body.classList.contains('page-etapa') && typeof renderEtapa === 'function') {
      setTimeout(() => { try { renderEtapa(); } catch (e) { } }, 30);
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  // Refresh all Tabulator instances globally
  try {
    if (typeof Tabulator !== 'undefined') {
      const tbls = Tabulator.findTable('*');
      if (tbls && Array.isArray(tbls)) {
        tbls.forEach(t => { try { t.redraw(true); } catch (e) { } });
      } else if (tbls) {
        try { tbls.redraw(true); } catch (e) { }
      }
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}
function toggleTheme() {
  const cur = document.documentElement.getAttribute('data-theme') || 'dark';
  applyTheme(cur === 'light' ? 'dark' : 'light');
  try { toast('Tema', (cur === 'light' ? 'Dark ativado' : 'Light ativado')); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

