function _hexToRgb(hex) {
  const h = String(hex || '')?.trim().replace('#', '');
  if (!h) return null;
  const hh = (h.length === 3) ? h.split('').map(c => c + c).join('') : h;
  if (hh.length !== 6) return null;
  const n = parseInt(hh, 16);
  return { r: (n >> 16) & 255, g: (n >> 8) & 255, b: n & 255 };
}
function _rgba(hex, a) {
  const rgb = _hexToRgb(hex);
  if (!rgb) return `rgba(57,255,20,${a})`;
  return `rgba(${rgb.r},${rgb.g},${rgb.b},${a})`;
}

function applyAccentTheme(name, persist = true) {
  const preset = ACCENT_PRESETS[name] || ACCENT_PRESETS.industrial;
  const root = document.documentElement;

  // Accent vars (usadas em todo o UI)
  root.style.setProperty('--em', preset.primary);
  root.style.setProperty('--em2', preset.success);
  root.style.setProperty('--em3', preset.warning);
  root.style.setProperty('--em4', preset.danger);

  // Wire/glow derivados do primary
  root.style.setProperty('--wire', _rgba(preset.primary, .06));
  root.style.setProperty('--wire2', _rgba(preset.primary, .12));
  root.style.setProperty('--wire3', _rgba(preset.primary, .22));
  root.style.setProperty('--em-g', _rgba(preset.primary, .18));
  root.style.setProperty('--em2-g', _rgba(preset.primary, .10));
  root.style.setProperty('--shadow-glow', `0 0 24px ${_rgba(preset.primary, .15)}`);
  root.style.setProperty('--shadow-glow-strong', `0 0 40px ${_rgba(preset.primary, .25)}`);

  // Alphas para CSS (substituem hardcodes e permitem tema misto)
  root.style.setProperty('--em04', _rgba(preset.primary, .04));
  root.style.setProperty('--em08', _rgba(preset.primary, .08));
  root.style.setProperty('--em10', _rgba(preset.primary, .10));
  root.style.setProperty('--em12', _rgba(preset.primary, .12));
  root.style.setProperty('--em15', _rgba(preset.primary, .15));
  root.style.setProperty('--em18', _rgba(preset.primary, .18));
  root.style.setProperty('--em25', _rgba(preset.primary, .25));
  root.style.setProperty('--em28', _rgba(preset.primary, .28));
  root.style.setProperty('--em40', _rgba(preset.primary, .40));
  root.style.setProperty('--em60', _rgba(preset.primary, .60));

  root.setAttribute('data-accent', name);

  if (persist) {
    try { localStorage.setItem('nexus_accent', name); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try {
      const cfg = window.APP_CFG || {};
      cfg.accentTheme = name;
      window.APP_CFG = cfg;
      if (typeof saveAppCfg === 'function') saveAppCfg();
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  }

  // Força redraw (Tabulator e Etapa)
  try {
    if (window._etapaTabs) {
      if (window._etapaTabs.status) window._etapaTabs.status.redraw(true);
      if (window._etapaTabs.rota) window._etapaTabs.rota.redraw(true);
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try {
    if (typeof Tabulator !== 'undefined') {
      const tbls = Tabulator.findTable('*');
      if (tbls && Array.isArray(tbls)) {
        tbls.forEach(t => { try { t.redraw(true); } catch (e) { } });
      } else if (tbls) {
        try { tbls.redraw(true); } catch (e) { }
      }
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

