function goStep(n) {
  document.getElementById('step1').style.display = n === 1 ? '' : 'none';
  document.getElementById('step2').style.display = n === 2 ? '' : 'none';
  // Update step circles
  const s1 = document.getElementById('s1'), s2 = document.getElementById('s2'), s3 = document.getElementById('s3');
  const sl1 = document.getElementById('sl1'), sl2 = document.getElementById('sl2');
  if (n === 1) { s1.className = 'step-circle active'; s2.className = 'step-circle'; s3.className = 'step-circle'; sl1.className = 'step-line'; sl2.className = 'step-line'; }
  if (n === 2) {
    s1.className = 'step-circle done'; s2.className = 'step-circle active'; s3.className = 'step-circle';
    sl1.className = 'step-line done'; sl2.className = 'step-line';
    buildFilGrid();
    // Busca de filial (evita listeners duplicados em nova importação)
    const searchInput = document.getElementById('filialSearch');
    if (searchInput) {
      if (!searchInput.dataset.bound) {
        // FASE 2: debounce prevents rebuilding 45 pills on every keystroke
        searchInput.addEventListener('input', debounce(e => buildFilGrid(e.target.value), 120));
        searchInput.addEventListener('keydown', e => {
          if (e.key === 'Enter' && selFilial) {
            processData();
          }
        });
        searchInput.dataset.bound = '1';
      }
      setTimeout(() => searchInput.focus(), 100);
    }
    // FASE 2: event delegation — no onclick inline per pill
    const filGrid = document.getElementById('filGrid');
    if (filGrid && !filGrid.dataset.delegated) {
      filGrid.addEventListener('click', e => {
        const pill = e.target.closest('.fil-pill');
        if (pill) selFil(pill.dataset.value, pill);
      });
      filGrid.dataset.delegated = '1';
    }
  }
}
