async function loadDemoData() {
  showLoad('Carregando dados de demonstração...', 30);
  await sleep(100);
  try {
    const bin = atob(DEMO_B64);
    // FASE 2 FIX: Uint8Array.from() is ~10x faster than a manual loop
    const bytes = Uint8Array.from(bin, c => c.charCodeAt(0));
    showLoad('Descomprimindo...', 55);
    await sleep(50);
    const ds = new DecompressionStream('gzip');
    const w = ds.writable.getWriter(); w.write(bytes); w.close();
    const r = ds.readable.getReader();
    const chunks = [];
    while (true) { const { done, value } = await r.read(); if (done) break; chunks.push(value); }
    const total = chunks.reduce((a, c) => a + c.length, 0);
    const buf = new Uint8Array(total); let off = 0;
    for (const c of chunks) { buf.set(c, off); off += c.length; }
    showLoad('Processando registros...', 75);
    await sleep(50);
    const json = new TextDecoder().decode(buf);
    const compact = JSON.parse(json);
    // FASE 1 FIX: compute date constants once, not per-row
    const TODAY_BASE = new Date(); TODAY_BASE.setHours(0, 0, 0, 0);
    const TOMORROW_BASE = new Date(TODAY_BASE); TOMORROW_BASE.setDate(TODAY_BASE.getDate() + 1);
    DB = compact.map(r => { const row = {}; for (const [k, v] of Object.entries(KEY_MAP)) row[k] = r[v]; return row; });
    // Re-compute estoque based on selected filial
    DB = recomputeWithFilial(DB, FILIAL);
    showLoad('Construindo painéis...', 92);
    await sleep(100);
    launchApp();
  } catch (e) { hideLoad(); alert('Erro: ' + e.message); }
}

function getCalculatedSLA(row, TODAY, TOMORROW) {
  if (!TODAY) { TODAY = new Date(); TODAY.setHours(0, 0, 0, 0); }
  if (!TOMORROW) { TOMORROW = new Date(TODAY); TOMORROW.setDate(TODAY.getDate() + 1); }

  const parseDate = s => {
    if (!s) return null;
    s = String(s)?.trim().slice(0, 10);
    const m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/);
    if (m) {
      const yy = parseInt(m[3], 10);
      const yyyy = yy < 100 ? 2000 + yy : yy;
      const d = new Date(yyyy, parseInt(m[2], 10) - 1, parseInt(m[1], 10));
      return isNaN(d) ? null : d;
    }
    const m2 = s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
    if (m2) {
      const d = new Date(parseInt(m2[1], 10), parseInt(m2[2], 10) - 1, parseInt(m2[3], 10));
      return isNaN(d) ? null : d;
    }
    return null;
  };

  let prazo = 'Sem Data';
  let slaRaw = 1;

  const targetStr = (row.tipo_op === 'Entrega') ? row.dt_entrega : row.dt_prev;
  const dt = parseDate(targetStr);

  if (dt) {
    const dStr = dt.toDateString();
    const tStr = TODAY.toDateString();
    const tomStr = TOMORROW.toDateString();

    const diffDays = Math.ceil((dt - TODAY) / (1000 * 60 * 60 * 24));
    slaRaw = diffDays;

    if (dStr === tStr) prazo = 'Hoje';
    else if (dStr === tomStr) prazo = 'Amanhã';
    else if (dt > TOMORROW) prazo = 'No Prazo';
    else prazo = 'Atrasado';
  } else {
    if (row.situacao_prev && row.tipo_op !== 'Entrega') {
      prazo = row.situacao_prev;
    }
    slaRaw = (prazo === 'Atrasado') ? -1 : (prazo === 'Hoje' || prazo === 'Amanhã') ? 0 : 1;
  }
  return { prazo, slaRaw };
}
// ==========================================
// AGRUPAMENTO GLOBAL POR CTRC
// ==========================================
function aggregateDB(data) {
  const map = new Map();
  const prazoOrder = { 'Atrasado': 0, 'Hoje': 1, 'Amanhã': 2, 'No Prazo': 3, 'Sem Data': 4 };

  data.forEach(r => {
    const ctrc = r.ctrc || r.cod;
    if (!ctrc) {
      map.set(Math.random().toString(), r);
      return;
    }

    if (!map.has(ctrc)) {
      map.set(ctrc, { ...r });
    } else {
      const exist = map.get(ctrc);

      // Somar valores numéricos
      exist.qtd_vol += (r.qtd_vol || 0);
      exist.vl_nf += (r.vl_nf || 0);
      exist.p_oper += (r.p_oper || 0);

      // Pior cenário para Prazos e SLAs
      if ((prazoOrder[r.prazo] || 4) < (prazoOrder[exist.prazo] || 4)) {
        exist.prazo = r.prazo;
        exist.dt_prev = r.dt_prev;
        exist.dt_entrega = r.dt_entrega;
        exist.prio_num = r.prio_num;
        exist.risco = r.risco;
        exist.prio_fluxo = r.prio_fluxo;
        exist.slaRaw = r.slaRaw;
      }

      // Maior valor prevalece para equipamento
      if (r.equipamento > exist.equipamento) {
        exist.equipamento = r.equipamento;
      }

      // Propagar flags críticas
      exist.is_critico = exist.is_critico || r.is_critico;
      exist.is_agend = exist.is_agend || r.is_agend;
    }
  });

  return Array.from(map.values());
}

async function loadXLSXFile() {
  showLoad('Lendo arquivo XLSX...', 20);
  await sleep(50);
  try {
    const data = await uploadedFile.arrayBuffer();
    showLoad('Processando ' + uploadedFile.name + '...', 40);

    // FASE 4: Use Web Worker so the main thread stays responsive during heavy XLSX parsing
    // Falls back to synchronous processing if Worker creation fails (e.g., strict CSP)
    const canWorker = typeof Worker !== 'undefined' && typeof URL !== 'undefined' && typeof Blob !== 'undefined';

    if (canWorker) {
      showLoad('Parseando XLSX em background...', 50);
      const workerSrc = `
        self.importScripts('https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js');
        self.onmessage = function(e){
          try{
            const wb = XLSX.read(e.data.buffer, {type:'array'});
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, {defval:''});
            self.postMessage({ok:true, rows:rows});
          }catch(err){
            self.postMessage({ok:false, error: err.message||String(err)});
          }
        };
      `;
      const blob = new Blob([workerSrc], { type: 'application/javascript' });
      const url = URL.createObjectURL(blob);
      const wk = new Worker(url);

      wk.postMessage({ buffer: data }, [data]);
      await new Promise((resolve, reject) => {
        wk.onmessage = ({ data: res }) => {
          URL.revokeObjectURL(url); wk.terminate();
          if (!res.ok) { reject(new Error(res.error)); return; }
          showLoad('Mapeando ' + res.rows.length + ' registros...', 75);
          const TODAY_BASE = new Date(); TODAY_BASE.setHours(0, 0, 0, 0);
          const TOMORROW_BASE = new Date(TODAY_BASE); TOMORROW_BASE.setDate(TODAY_BASE.getDate() + 1);
          DB = res.rows.map(r => processXLSXRow(r, FILIAL, TODAY_BASE, TOMORROW_BASE)).filter(Boolean);
          DB = aggregateDB(DB);
          resolve();
        };
        wk.onerror = (err) => { URL.revokeObjectURL(url); wk.terminate(); reject(err); };
      });
    } else {
      // Fallback: synchronous (older browsers)
      const wb = XLSX.read(data, { type: 'array' });
      const wsName = wb.SheetNames[0];
      const ws = wb.Sheets[wsName];
      const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
      showLoad('Processando ' + rows.length + ' registros...', 60);
      await sleep(50);
      const TODAY_BASE = new Date(); TODAY_BASE.setHours(0, 0, 0, 0);
      const TOMORROW_BASE = new Date(TODAY_BASE); TOMORROW_BASE.setDate(TODAY_BASE.getDate() + 1);
      DB = rows.map(r => processXLSXRow(r, FILIAL, TODAY_BASE, TOMORROW_BASE)).filter(Boolean);
      DB = aggregateDB(DB);
    }

    showLoad('Finalizando...', 92);
    await sleep(80);
    launchApp();
  } catch (e) { hideLoad(); alert('Erro ao ler XLSX: ' + e.message); }
}

function processXLSXRow(r, filial, TODAY, TOMORROW) {
  // Ignorar linhas de somatório/lixo exportadas no final do Excel pelo ERP
  if (('COD_CONHECIMENTOS' in r) && !r['COD_CONHECIMENTOS']) return null;
  if (!r['COD_CONHECIMENTOS'] && !r['CTRC'] && !r['CTE']) return null;

  if (!TODAY) { TODAY = new Date(); TODAY.setHours(0, 0, 0, 0); }
  if (!TOMORROW) { TOMORROW = new Date(TODAY); TOMORROW.setDate(TODAY.getDate() + 1); }

  const orig_stock = String(r['Orig'] || '')?.trim();
  const sigla_orig = String(r['SIGLA_FILIAL_ORIGEM'] || '')?.trim();
  const sigla_dest = String(r['SIGLA_FILIAL_DESTINO'] || '')?.trim();
  const equip = parseFloat(r['Equipamento']) || 0;
  const mercp = String(r['Mercadoria_Planejada'] || '')?.trim();
  const ini = String(r['INICIO_DESCARREGAMENTO'] || '')?.trim();
  const fim = String(r['FIM_DESCARREGAMENTO'] || '')?.trim();
  const agend = String(r['AGENDAMENTO'] || '')?.trim();
  const contagem = String(r['Contagem'] || '')?.trim();
  const nr_coleta_raw = String(r['NR_COLETA'] || r['Nr_Coleta'] || r['NR_COLETA_SAIDA'] || '')?.trim();
  const motivo_raw = String(r['Motivo'] || r['MOTIVO'] || '')?.trim();
  const dt_prev_str = String(r['DT_PREV_EMBARQUE'] || '')?.trim();

  // NOVO: datas complementares (quando existirem no arquivo)
  let dt_entrega_str = String(
    r['Prazo_Entrega_Final'] ||
    r['Prazo Entrega Final'] ||
    r['Data_Entrega_Maxima'] ||
    r['DATA_ENTREGA_MAXIMA'] ||
    r['DATA_ENTREGA_MAXIMA '] ||
    r['Data Entrega Maxima'] ||
    r['DT_ENTREGA'] ||
    r['DT_ENTREGA_REAL'] ||
    r['DT_ENTREGA_PREV'] ||
    r['DT_PREV_ENTREGA'] ||
    r['DT_ENTREGA_AGENDADA'] ||
    ''
  )?.trim();

  // NOVO: Data (entrada/registro) para cálculo de Dias em estoque
  const data_str = String(
    r['Data'] ||
    r['DATA'] ||
    r['DATA_ENTRADA'] ||
    r['Data_Entrada'] ||
    r['DATA_ENTRADA_ARMAZEM'] ||
    r['DATA_CHEGADA'] ||
    r['DATA_ESTOQUE'] ||
    r['Emissao'] ||
    ''
  )?.trim();

  const equip_valido = equip > 0;
  const tem_mercp = !!(mercp && mercp !== 'None');
  const tem_ini = !!(ini && ini !== 'None');
  const tem_fim = !!(fim && fim !== 'None');
  const sem_ini_fim = !tem_ini && !tem_fim;

  // fallback: quando DT_ENTREGA não existir no arquivo, usar fim de descarga como proxy
  if (!dt_entrega_str && tem_fim) dt_entrega_str = String(fim)?.trim();

  // Use filial as estoque override if orig is empty
  const stock = orig_stock || filial;

  // ── TIPO DE OPERAÇÃO (baseado na filial LOGADA, não no estoque do registro) ──
  // Regra: Filial logada == Origem → Embarque
  //        Filial logada == Destino → Entrega
  //        Filial logada != Origem (e != Destino) → Reembarque
  let tipo_op;
  if (filial === sigla_orig) tipo_op = 'Embarque';
  else if (filial === sigla_dest) tipo_op = 'Entrega';
  else tipo_op = 'Reembarque';

  const sit_prev = String(r['SITUACAO_PREV_EMBARQUE'] || '')?.trim();
  const calcSLA = getCalculatedSLA({ dt_prev: dt_prev_str, dt_entrega: dt_entrega_str, tipo_op, situacao_prev: sit_prev }, TODAY, TOMORROW);
  const prazo = calcSLA.prazo;
  const slaRaw = calcSLA.slaRaw;

  const is_desc = (tem_ini && !tem_fim);

  let status;
  if (tem_mercp) status = 'PLANEJADO';
  else if (['Embarque', 'Entrega'].includes(tipo_op) && equip_valido) status = 'DISPONIVEL';
  else if (['Embarque', 'Entrega'].includes(tipo_op)) status = 'DESCARGA';
  else if (tipo_op === 'Reembarque' && equip_valido) status = 'DISPONIVEL';
  else if (tipo_op === 'Reembarque' && tem_ini && tem_fim && !equip_valido) status = 'INTERMEDIARIO';
  else if (tipo_op === 'Reembarque' && sem_ini_fim) status = 'NO PATIO';
  else status = 'DESCARGA';

  // CRITICAL_CLIENTS check — is_critico = remetente na lista de clientes críticos
  const _remUP = String(r['Remetente'] || '')?.trim().toUpperCase();
  const is_critico = CRITICAL_CLIENTS.some(c => _remUP.includes(c));
  const is_agend = agend === 'SIM';
  const prio_fluxo = (prazo === 'Atrasado' || prazo === 'Hoje' || is_agend || is_critico) ? 'Prioridade' : 'Fluxo';
  let risco = is_critico ? 'Cliente Crítico' : is_agend ? 'Agendamento' : prio_fluxo === 'Prioridade' ? 'Prazo Embarque' : 'Fluxo';
  let prio_num = is_critico ? 1 : is_agend ? 2 : prazo === 'Atrasado' ? 3 : prazo === 'Hoje' ? 4 : prazo === 'Amanhã' ? 5 : 6;

  const row = {
    ctrc: String(r['CTRC'] || ''), cod: String(r['COD_CONHECIMENTOS'] || ''),
    emissao: String(r['Emissao'] || ''), remetente: String(r['Remetente'] || ''),
    destinatario: String(r['Destinatario'] || ''), cidade: String(r['Cidade_Entrega'] || ''),
    rota: String(r['Rota'] || r['ROTA'] || ''),
    origem: sigla_orig, destino: sigla_dest, estoque: stock,
    p_oper: parseFloat(r['P_Operacional']) || 0, qtd_vol: parseInt(r['Qtde_Volumes']) || 0,
    vl_nf: parseFloat(r['Vl_Nota_Fiscal']) || 0, dt_prev: dt_prev_str, dt_entrega: dt_entrega_str, data: data_str,
    prazo, tipo_op, status, risco, prio_fluxo, prio_num, slaRaw, situacao_prev: sit_prev,
    is_agend, is_critico, agendamento: agend, equipamento: equip,
    mercadoria_planejada: mercp, ini_desc: ini, fim_desc: fim, is_desc,
    nr_mac: String(r['Nr_Mac'] || ''), dias: parseInt(r['Dias']) || 0,
    veiculo: String(r['VEICULO_TRACKING'] || ''), endereco: String(r['Endereco_Armazem'] || ''),
    nr_coleta: nr_coleta_raw, motivo: motivo_raw,
  };
  // FASE 2: Pre-build search index (once per row at import, not per-search)
  row._searchIdx = [
    row.ctrc, row.cod, row.remetente, row.destinatario,
    row.cidade, row.origem, row.destino, row.estoque,
    row.status, row.prazo, row.veiculo, row.nr_mac
  ].join(' ').toLowerCase();
  return row;
}

function recomputeWithFilial(data, filial) {
  const TODAY = new Date(); TODAY.setHours(0, 0, 0, 0);
  const TOMORROW = new Date(TODAY); TOMORROW.setDate(TODAY.getDate() + 1);
  return data.map(r => {
    const stock = r.estoque || filial;
    const sigla_orig = r.origem;
    const sigla_dest = r.destino;
    const equip_valido = r.equipamento > 0;
    const tem_mercp = !!(r.mercadoria_planejada && r.mercadoria_planejada !== 'None');
    const tem_ini = !!(r.ini_desc && r.ini_desc !== 'None');
    const tem_fim = !!(r.fim_desc && r.fim_desc !== 'None');
    const sem = !tem_ini && !tem_fim;

    // ── TIPO DE OPERAÇÃO (baseado na filial LOGADA, não no estoque do registro) ──
    // Regra: Filial logada == Origem → Embarque
    //        Filial logada == Destino → Entrega
    //        Filial logada != Origem (e != Destino) → Reembarque
    let tipo_op;
    if (filial === sigla_orig) tipo_op = 'Embarque';
    else if (filial === sigla_dest) tipo_op = 'Entrega';
    else tipo_op = 'Reembarque';

    let status;
    if (tem_mercp) status = 'PLANEJADO';
    else if (['Embarque', 'Entrega'].includes(tipo_op) && equip_valido) status = 'DISPONIVEL';
    else if (['Embarque', 'Entrega'].includes(tipo_op)) status = 'DESCARGA';
    else if (tipo_op === 'Reembarque' && equip_valido) status = 'DISPONIVEL';
    else if (tipo_op === 'Reembarque' && tem_ini && tem_fim && !equip_valido) status = 'INTERMEDIARIO';
    else if (tipo_op === 'Reembarque' && sem) status = 'NO PATIO';
    else status = 'DESCARGA';

    const calcSLA = getCalculatedSLA({ dt_prev: r.dt_prev, dt_entrega: r.dt_entrega, tipo_op, situacao_prev: r.situacao_prev }, TODAY, TOMORROW);
    const prazo = calcSLA.prazo;
    const slaRaw = calcSLA.slaRaw;
    const prio_fluxo = (prazo === 'Atrasado' || prazo === 'Hoje' || r.is_agend || r.is_critico) ? 'Prioridade' : 'Fluxo';
    const risco = r.is_critico ? 'Cliente Crítico' : r.is_agend ? 'Agendamento' : prio_fluxo === 'Prioridade' ? 'Prazo Embarque' : 'Fluxo';
    const prio_num = r.is_critico ? 1 : r.is_agend ? 2 : prazo === 'Atrasado' ? 3 : prazo === 'Hoje' ? 4 : prazo === 'Amanhã' ? 5 : 6;

    return { ...r, estoque: stock, tipo_op, status, prazo, slaRaw, prio_fluxo, risco, prio_num };
  });
}

async function launchApp() {
  try {
    animStage = 3;
    await delay(400);
    document.querySelectorAll('.step-circle').forEach(s => s.classList.add('done'));
    await delay(400);
    document.querySelector('.step-circle.active')?.classList.remove('active');
    await delay(500);
    document.getElementById('importScreen').style.display = 'none';
    document.getElementById('app').classList.add('visible');

    hideLoad();

    populateSelects();
    updateHeader();
    updateNavBadges();
    renderDashboard();
    try { renderEtapa(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try { etapaApplySearch(document.getElementById('etapaSrch')?.value || ''); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    renderEst();
    renderDesc();
    renderPat();
    renderAtras();

    toast('Sistema Carregado', `${DB.length} documentos importados`);
  } catch (error) {
    console.error('Launch error:', error);
    hideLoad();
    alert('Erro ao inicializar: ' + error.message);
  }
}

function resetApp() {
  // Reiniciar estado de importação (permite selecionar o MESMO arquivo novamente)
  DB = []; FILIAL = ''; planResults = []; planFiltState = 'all'; planPage = 1;
  estFiltState = 'all'; estPage = 1; patFiltState = 'all'; patPage = 1; atrFiltState = 'all'; atrPage = 1;
  uploadedFile = null; demoMode = false; selFilial = '';

  // UI import
  const fi = document.getElementById('fileInput');
  if (fi) { fi.value = ''; }
  const uz = document.getElementById('uzFileName');
  if (uz) { uz.textContent = '—'; }
  const b1 = document.getElementById('btnStep1');
  if (b1) { b1.disabled = true; }
  const b2 = document.getElementById('btnStep2');
  if (b2) { b2.disabled = true; }
  const fs = document.getElementById('filSelecionada');
  if (fs) { fs.textContent = '—'; }
  const si = document.getElementById('filialSearch');
  if (si) { si.value = ''; }
  try { document.querySelectorAll('.fil-pill').forEach(p => p.classList.remove('sel')); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // Fecha overlays e volta para o passo 1
  try { document.getElementById('modalBg').classList.remove('open'); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('loading').classList.remove('on'); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  toggleTele(false);
  goStep(1);
}

