function updateHeader() {
  const distinctCount = countDistinctKnowledges(DB);
  const p = DB.reduce((s, r) => s + (parseFloat(r.p_oper) || 0), 0);
  const v = DB.reduce((s, r) => s + (parseFloat(r.vl_nf) || 0), 0);
  const vol = DB.reduce((s, r) => s + (parseFloat(r.qtd_vol) || 0), 0);

  document.getElementById('hFilial').textContent = FILIAL || '—';
  document.getElementById('hTotal').textContent = fN(distinctCount);
  document.getElementById('hPeso').textContent = fN2(p / 1000) + ' t';
  document.getElementById('hValor').textContent = 'R$ ' + fM(v);

  // Atualizar volumes se elemento existir
  const volEl = document.getElementById('hVolumes');
  if (volEl) volEl.textContent = fN(vol);

  document.getElementById('hAtras').textContent = fN(DB.filter(r => r.prazo === 'Atrasado').length);
}

// Atualiza header com totais da aba/filtro atual
function updateHeaderWithFilteredTotals(data, label = '') {
  if (!data || !data.length) {
    updateHeader(); // fallback para totais globais
    return;
  }

  const distinctCount = countDistinctKnowledges(data);
  const p = data.reduce((s, r) => s + (parseFloat(r.p_oper) || 0), 0);
  const v = data.reduce((s, r) => s + (parseFloat(r.vl_nf) || 0), 0);
  const vol = data.reduce((s, r) => s + (parseFloat(r.qtd_vol) || 0), 0);

  // Atualiza com totais filtrados
  document.getElementById('hFilial').textContent = (FILIAL || '—') + (label ? ' · ' + label : '');
  document.getElementById('hTotal').textContent = fN(distinctCount);
  document.getElementById('hPeso').textContent = fN2(p / 1000) + ' t';
  document.getElementById('hValor').textContent = 'R$ ' + fM(v);

  // Atualizar volumes se elemento existir
  const volEl = document.getElementById('hVolumes');
  if (volEl) volEl.textContent = fN(vol);

  const atrasCount = data.filter(r => r.prazo === 'Atrasado').length;
  document.getElementById('hAtras').textContent = fN(atrasCount);
}

function updateNavBadges() {
  document.getElementById('nEst').textContent = DB.filter(r => r.status === 'DISPONIVEL').length;
  document.getElementById('nDesc').textContent = DB.filter(r => r.status === 'DESCARGA').length;
  document.getElementById('nPat').textContent = DB.filter(r => r.status === 'NO PATIO').length;
  document.getElementById('nAtr').textContent = DB.filter(r => r.prazo === 'Atrasado').length;
  // sidebar mirror
  try {
    document.getElementById('sbEst').textContent = document.getElementById('nEst').textContent;
    document.getElementById('sbDesc').textContent = document.getElementById('nDesc').textContent;
    document.getElementById('sbPat').textContent = document.getElementById('nPat').textContent;
    document.getElementById('sbAtr').textContent = document.getElementById('nAtr').textContent;
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function goPage(name, el) {
  // Activate top nav (existing)
  try {
    document.querySelectorAll('.nt').forEach(t => t.classList.remove('active'));
    const top = document.querySelector('.nt[data-page="' + name + '"]');
    if (top) { top.classList.add('active'); }
    else if (el && el.classList && el.classList.contains('nt')) { el.classList.add('active'); }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // Activate pages
  document.querySelectorAll('.pg').forEach(p => p.classList.remove('active'));
  const pg = document.getElementById('pg-' + name);
  if (pg) pg.classList.add('active');

  // Sync NEW sidebar active state (Claude.ai style)
  try {
    document.querySelectorAll('.nav-item').forEach(b => b.classList.remove('active'));
    const navItem = document.querySelector('.nav-item[data-page="' + name + '"]');
    if (navItem) navItem.classList.add('active');
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // Sync OLD sidebar active state (keeping backward compatibility)
  try {
    document.querySelectorAll('.sb-item').forEach(b => b.classList.remove('active'));
    const sb = document.querySelector('.sb-item[data-page="' + name + '"]');
    if (sb) sb.classList.add('active');
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // Mobile: fechar sidebar após navegação
  if (window.innerWidth <= 768) {
    const sidebar = document.getElementById('mainSidebar');
    if (sidebar) sidebar.classList.remove('open');
  }

  // page flag for responsive tweaks & theme refresh
  try {
    const keep = document.body.className.split(/\s+/).filter(c => !c.startsWith('page-'));
    document.body.className = keep.join(' ');
    document.body.classList.add('page-' + name);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  // ensure etapa grid modifier class
  try {
    const body = document.querySelector('.db-body');
    if (body) { body.classList.toggle('etapa-grid', name === 'etapa'); }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // ═══ ISOLAMENTO DE ABAS: Renderizar dados corretos para cada aba ═══
  // Isso garante que cada aba tenha seus próprios dados e filtros
  try {
    if (name === 'dashboard') {
      // Dashboard: resetar para totais globais
      updateHeader();
      renderDashboard();
    } else if (name === 'estoque') {
      // Estoque: renderizar dados do estoque
      renderEst();
    } else if (name === 'descarga') {
      // Descarga: renderizar dados de descarga
      renderDesc();
    } else if (name === 'patio') {
      // Pátio: renderizar dados do pátio
      renderPat();
    } else if (name === 'atrasados') {
      // Atrasados: renderizar dados de atrasados
      renderAtras();
    } else if (name === 'planejamento') {
      // Planejamento: manter estado (não forçar re-render)
      if (planResults && planResults.length) {
        renderPlan();
      }
    } else if (name === 'etapa') {
      // Etapa: renderizar pipeline
      if (typeof renderEtapa === 'function') {
        renderEtapa();
      }
      updateHeader(); // Etapa usa totais globais
    } else if (name === 'execucao-one') {
      if (window._execOneTable) {
        // Redraw para resolver bugs de exibição quando a div estava display:none
        setTimeout(() => window._execOneTable.redraw(true), 50);
      }
    }
  } catch (e) {
    if (window.__DEV) console.warn("[NX] Erro ao renderizar aba:", name, e);
  }
}

// ═══════════════════════════════════════════════════════
// SIDEBAR (v6-inspired)
// ═══════════════════════════════════════════════════════
function updateSidebarFab() {
  const fab = document.getElementById('sbFab');
  if (!fab) return;
  const open = document.body.classList.contains('sb-open');
  const ic = fab.querySelector('.sb-fab-ic');
  // icon: when open show arrow to hide; when closed show hamburger
  if (ic) ic.textContent = open ? '⇤' : '☰';
  fab.setAttribute('aria-label', open ? 'Ocultar menu' : 'Abrir menu');
  fab.title = (open ? 'Ocultar menu' : 'Abrir menu') + ' (Alt+M)';
}

function toggleSidebar(force) {
  const open = typeof force === 'boolean' ? force : !document.body.classList.contains('sb-open');
  document.body.classList.toggle('sb-open', open);
  updateSidebarFab();
}

// NOVA FUNÇÃO: Toggle da sidebar principal Claude.ai style
function toggleMainSidebar() {
  const sidebar = document.getElementById('mainSidebar');
  const app = document.getElementById('app');
  if (!sidebar || !app) return;

  if (window.innerWidth <= 768) {
    // Mobile: abre/fecha
    sidebar.classList.toggle('open');
  } else {
    // Desktop: colapsa/expande
    sidebar.classList.toggle('collapsed');
    app.classList.toggle('sidebar-collapsed');
  }
}

// Atalho Ctrl+B para toggle da sidebar
document.addEventListener('keydown', (e) => {
  if (e.ctrlKey && (e.key === 'b' || e.key === 'B')) {
    e.preventDefault();
    toggleMainSidebar();
  }

  // Alt+M toggles sidebar (mantém original)
  if (e.altKey && (e.key === 'm' || e.key === 'M')) {
    e.preventDefault();
    toggleSidebar();
  }
  // Esc closes sidebar (if open) and helps close modals gracefully
  if (e.key === 'Escape') {
    if (document.body.classList.contains('sb-open')) toggleSidebar(false);
    try {
      const mb = document.querySelector('.modal-bg.open');
      if (mb) { mb.classList.add('closing'); setTimeout(() => mb.classList.remove('closing'), 220); }
    } catch (err) { if (window.__DEV) console.warn("[NX]", err); }
  }
});

// ═══════════════════════════════════════════════════════
// DASHBOARD
// ═══════════════════════════════════════════════════════
window.DASH_FILTER = 'GERAL';
function setDashFilter(filterType) {
  // Manter compatibilidade com chamadas legadas (drilldown, etc.)
  window.DASH_FILTER = filterType;
  // Sincronizar NxMultiSelect se existir
  const ms = NxMS.get('dashTipo');
  if (ms) {
    if (filterType === 'GERAL') {
      ms.setValues([]); // Todos
    } else {
      const map = { 'COLETA': 'Embarque (Coleta)', 'REEMBARQUE': 'Reembarque', 'ENTREGA': 'Entrega' };
      ms.setValues(map[filterType] ? [map[filterType]] : []);
    }
  }
  renderDashboard();
}

function renderDashboard() {
  if (!DB.length) return;

  // Lê filtro de tipo do NxMultiSelect (multi-seleção)
  let dashDB = DB;
  const dashTipoSel = getMultiSel('dashTipo'); // [] = Todos
  if (dashTipoSel.length > 0) {
    // Mapear labels para campo tipo_op
    const tipoMap = { 'Embarque (Coleta)': 'Embarque', 'Reembarque': 'Reembarque', 'Entrega': 'Entrega' };
    const tiposSel = dashTipoSel.map(t => tipoMap[t] || t);
    dashDB = DB.filter(r => tiposSel.includes(r.tipo_op));
  } else if (window.DASH_FILTER && window.DASH_FILTER !== 'GERAL') {
    // Compatibilidade com setDashFilter legado
    if (window.DASH_FILTER === 'COLETA') dashDB = DB.filter(r => r.tipo_op === 'Embarque');
    else if (window.DASH_FILTER === 'REEMBARQUE') dashDB = DB.filter(r => r.tipo_op === 'Reembarque');
    else if (window.DASH_FILTER === 'ENTREGA') dashDB = DB.filter(r => r.tipo_op === 'Entrega');
  }

  const total = dashDB.length;

  // FASE 2 PERF: single O(n) pass instead of 7 separate filter() calls
  const groups = { disp: [], desc: [], atras: [], crits: [], planej: [], patio: [], inter: [] };
  let pesoT = 0, valorT = 0, volT = 0;
  for (const r of dashDB) {
    pesoT += r.p_oper; valorT += r.vl_nf; volT += r.qtd_vol;
    if (r.status === 'DISPONIVEL') groups.disp.push(r);
    if (r.status === 'DESCARGA') groups.desc.push(r);
    if (r.status === 'PLANEJADO') groups.planej.push(r);
    if (r.status === 'NO PATIO') groups.patio.push(r);
    if (r.status === 'INTERMEDIARIO') groups.inter.push(r);
    if (r.prazo === 'Atrasado') groups.atras.push(r);
    if (r.is_critico || r.is_agend) groups.crits.push(r);
  }
  const { disp, desc, atras, crits, planej, patio, inter } = groups;

  const ag = items => ({ c: items.length, p: items.reduce((s, r) => s + r.p_oper, 0), v: items.reduce((s, r) => s + r.vl_nf, 0), vol: items.reduce((s, r) => s + r.qtd_vol, 0) });

  // KPIs (Mission Control counters)
  const setText = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
  const setNum = (id, value, opt) => { const el = document.getElementById(id); if (!el) return; try { animateCounter(el, value, opt); } catch (e) { el.textContent = (opt?.prefix || '') + (opt?.fmt ? opt.fmt(value) : value) + (opt?.suffix || ''); } };

  // KPIs Básicos
  setNum('kTotal', total, { duration: 900, fmt: (x) => fN(Math.round(x)) });
  setNum('kPeso', pesoT / 1000, { duration: 900, fmt: (x) => fN2(x), suffix: ' t' });
  setNum('kValor', valorT, { duration: 900, prefix: 'R$ ', fmt: (x) => fM(x) });
  setNum('kVol', volT, { duration: 900, fmt: (x) => fN(Math.round(x)) });

  // KPIs Operacionais
  setNum('kDisp', disp.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kDispSub', fN2(ag(disp).p / 1000) + ' t · R$ ' + fM(ag(disp).v));

  setNum('kDesc', desc.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kDescSub', fN2(ag(desc).p / 1000) + ' t · R$ ' + fM(ag(desc).v));

  setNum('kPatio', patio.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kPatioSub', fN2(ag(patio).p / 1000) + ' t · ' + patio.length + ' veículos');

  setNum('kPlan', planej.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kPlanSub', fN2(ag(planej).p / 1000) + ' t · R$ ' + fM(ag(planej).v));

  // KPIs de Risco
  setNum('kAtras', atras.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kAtrasSub', fN2(ag(atras).p / 1000) + ' t · R$ ' + fM(ag(atras).v));

  setNum('kCrit', crits.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kCritSub', dashDB.filter(r => r.is_critico).length + ' críticos · ' + dashDB.filter(r => r.is_agend).length + ' agend.');

  // Embarque Hoje e Amanhã
  const hoje = dashDB.filter(r => r.prazo === 'Hoje');
  const amanh = dashDB.filter(r => r.prazo === 'Amanhã');
  setNum('kHoje', hoje.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kHojeSub', fN2(ag(hoje).p / 1000) + ' t · ' + hoje.filter(r => r.is_critico || r.is_agend).length + ' prioridade');
  setNum('kAmanh', amanh.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  setText('kAmanhSub', fN2(ag(amanh).p / 1000) + ' t');

  // SLA (No prazo) — alinhado ao ETAPA
  try {
    const aS = aggStats(dashDB);
    const inb = dashDB.filter(r => r.tipo_op === 'Entrega');
    const out = dashDB.filter(r => r.tipo_op === 'Embarque');
    const iS = aggStats(inb);
    const oS = aggStats(out);
    setText('kSlaGeral', fmtPct(aS.sla, 1)); setSlaTone('kSlaGeral', aS.sla);
    setText('kSlaIn', fmtPct(iS.sla, 1)); setSlaTone('kSlaIn', iS.sla);
    setText('kSlaOut', fmtPct(oS.sla, 1)); setSlaTone('kSlaOut', oS.sla);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // KPIs de Performance
  try {
    // Taxa de Ocupação (estimativa baseada em peso vs capacidade hipotética)
    const capacidadeEstimada = total * 500; // Assumindo 500kg de capacidade média por CT
    const ocupacao = total > 0 ? (pesoT / capacidadeEstimada) * 100 : 0;
    setText('kOcup', fmtPct(ocupacao / 100, 1));
    setSlaTone('kOcup', ocupacao / 100);

    // Lead Time Médio (dias entre dt_prev e hoje)
    const hoje_date = new Date();
    const lead_times = dashDB.filter(r => r.dt_prev).map(r => {
      const dt = parseDateSafe(r.dt_prev);
      if (!dt) return 0;
      const diff = Math.abs(dt - hoje_date);
      return Math.ceil(diff / (1000 * 60 * 60 * 24));
    }).filter(x => x > 0);
    const lead_medio = lead_times.length > 0 ? lead_times.reduce((a, b) => a + b, 0) / lead_times.length : 0;
    setText('kLead', lead_medio > 0 ? lead_medio.toFixed(1) + ' dias' : '—');

    // Reembarque
    setNum('kReemb', inter.length, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  } catch (e) { if (window.__DEV) console.warn("[NX] Performance KPIs:", e); }

  // KPIs Financeiros
  try {
    const ticket_medio = total > 0 ? valorT / total : 0;
    const peso_medio = total > 0 ? pesoT / total : 0;
    const vol_medio = total > 0 ? volT / total : 0;

    setText('kTicket', ticket_medio > 0 ? 'R$ ' + fM(ticket_medio) : '—');
    setText('kPesoMed', peso_medio > 0 ? fN2(peso_medio) + ' kg' : '—');
    setText('kVolMed', vol_medio > 0 ? fN2(vol_medio) : '—');
  } catch (e) { if (window.__DEV) console.warn("[NX] Financial KPIs:", e); }

  // KPIs de Destino
  try {
    const destinos_unicos = new Set(dashDB.map(r => r.destino).filter(x => x)).size;
    const remetentes_unicos = new Set(dashDB.map(r => r.remetente).filter(x => x)).size;
    const destinat_unicos = new Set(dashDB.map(r => r.destinatario).filter(x => x)).size;

    setNum('kDestinos', destinos_unicos, { duration: 850, fmt: (x) => fN(Math.round(x)) });
    setNum('kRemetentes', remetentes_unicos, { duration: 850, fmt: (x) => fN(Math.round(x)) });
    setNum('kDestinat', destinat_unicos, { duration: 850, fmt: (x) => fN(Math.round(x)) });
  } catch (e) { if (window.__DEV) console.warn("[NX] Destination KPIs:", e); }

  // Multi-metric status bars (Agora injetado no #spxPipeline)
  const pipelineEl = document.getElementById('spxPipeline');
  if (pipelineEl) {
    const maxV = Math.max(ag(disp).c, ag(desc).c, ag(planej).c, ag(patio).c, 1);
    pipelineEl.innerHTML = `
            <div class="pipe-stage" style="flex: ${0.5 + (ag(disp).c / maxV) * 0.5}">
              <div class="pipe-name">Disponível</div><div class="pipe-val">${fN(ag(disp).c)}</div><div class="pipe-sub">${fN2(ag(disp).p / 1000)} t</div><div class="pipe-glow"></div>
            </div>
            <div class="pipe-stage" style="flex: ${0.5 + (ag(desc).c / maxV) * 0.5}">
              <div class="pipe-name">Descarga</div><div class="pipe-val">${fN(ag(desc).c)}</div><div class="pipe-sub">${fN2(ag(desc).p / 1000)} t</div><div class="pipe-glow"></div>
            </div>
            <div class="pipe-stage" style="flex: ${0.5 + (ag(planej).c / maxV) * 0.5}">
              <div class="pipe-name">Planejado</div><div class="pipe-val">${fN(ag(planej).c)}</div><div class="pipe-sub">${fN2(ag(planej).p / 1000)} t</div><div class="pipe-glow"></div>
            </div>
            <div class="pipe-stage" style="flex: ${0.5 + (ag(patio).c / maxV) * 0.5}">
              <div class="pipe-name">No Pátio</div><div class="pipe-val">${fN(ag(patio).c)}</div><div class="pipe-sub">${fN2(ag(patio).p / 1000)} t</div><div class="pipe-glow"></div>
            </div>
         `;
  }

  // Donut
  const statusData = [
    { label: 'DISP', data: ag(disp), color: '#10a37f' },
    { label: 'DESC', data: ag(desc), color: '#f0b429' },
    { label: 'PLAN', data: ag(planej), color: '#19c37d' },
    { label: 'PÁTIO', data: ag(patio), color: '#94a3b8' },
    { label: 'INTER', data: ag(inter), color: '#64748b' },
  ];
  buildDonut(statusData, total);

  // Prazo bars (by peso) transformado
  const prazoMap = { 'Atrasado': '#f03d3d', 'Hoje': '#f0b429', 'Amanhã': '#19c37d', 'No Prazo': '#10a37f', 'Sem Data': '#64748b' };
  const prazoData = Object.entries(prazoMap).map(([l, c]) => {
    const items = dashDB.filter(r => r.prazo === l);
    return { label: l, data: ag(items), color: c };
  });
  const maxPP = Math.max(...prazoData.map(d => d.data.p), 1);
  const prBars = document.getElementById('spxPrazoBars');
  if (prBars) {
    prBars.innerHTML = prazoData.map(d => `
            <div style="display:flex; align-items:center; gap:8px; margin-bottom:6px;">
               <div style="width:65px; font-size:10px; color:var(--muted); text-align:right;">${d.label}</div>
               <div style="flex:1; height:6px; background:rgba(255,255,255,0.05); border-radius:3px; overflow:hidden;">
                  <div style="height:100%; width:${(d.data.p / maxPP * 100)}%; background:${d.color}; border-radius:3px;"></div>
               </div>
               <div style="width:40px; font-size:10px; color:var(--txt); font-weight:700;">${fN2(d.data.p / 1000)}t</div>
            </div>
         `).join('');
  }

  // SLA Radar Gauge
  try {
    const aS = aggStats(dashDB);
    const inb = dashDB.filter(r => r.tipo_op === 'Entrega');
    const out = dashDB.filter(r => r.tipo_op === 'Embarque');

    const rSla = Math.max(0, Math.min(100, aS.sla));
    setText('sgSlaVal', rSla.toFixed(0) + '%');

    const circ = document.getElementById('sgSlaCirc');
    if (circ) {
      const dash = 301.59; // 2 * pi * 48
      const offset = dash - (dash * (rSla / 100));
      circ.style.strokeDasharray = `${dash}`;
      circ.style.strokeDashoffset = `${offset}`;
      if (rSla >= 95) circ.style.stroke = '#10a37f';
      else if (rSla >= 85) circ.style.stroke = '#f0b429';
      else circ.style.stroke = '#f03d3d';
    }

    setText('sgSlaIn', fmtPct(aggStats(inb).sla, 1));
    setText('sgSlaOut', fmtPct(aggStats(out).sla, 1));
  } catch (e) { if (window.__DEV) console.warn("[NX SLA]:", e); }

  // Sparklines: Top Destinos
  const destMap = {};
  disp.forEach(r => { if (r.destino) { if (!destMap[r.destino]) destMap[r.destino] = { c: 0, p: 0, v: 0 }; destMap[r.destino].c++; destMap[r.destino].p += r.p_oper; destMap[r.destino].v += r.vl_nf; } });
  const topDest = Object.entries(destMap).sort((a, b) => b[1].p - a[1].p).slice(0, 5);
  const maxDP = topDest[0] ? topDest[0][1].p : 1;

  const destSparks = document.getElementById('spxDestinos');
  if (destSparks) {
    destSparks.innerHTML = topDest.map(([d, a]) => `
            <div class="spark-item">
               <div class="spark-info">
                  <span class="spark-name">${d}</span>
                  <span class="spark-vol">${fN2(a.p / 1000)}t · ${a.c} CTs</span>
               </div>
               <div class="spark-bar-wrap">
                  <div class="spark-bar-fill" style="width:${(a.p / maxDP * 100)}%;"></div>
               </div>
            </div>
         `).join('');
  }

  // Sparklines Extras
  try {
    const reembEl = document.getElementById('spkReembTxt');
    const reembBar = document.getElementById('spkReembBar');
    if (reembEl) {
      const rPct = Math.min(100, (inter.length / Math.max(1, total)) * 100 * 3); // x3 visual scale
      reembEl.textContent = `${inter.length} CTs pendentes`;
      if (reembBar) reembBar.style.width = `${rPct}%`;
    }

    const capEst = total * 500;
    const ocup = Math.min(100, (pesoT / Math.max(1, capEst)) * 100);
    const opEl = document.getElementById('spkOcupTxt');
    const opBar = document.getElementById('spkOcupBar');
    if (opEl) {
      opEl.textContent = `${ocup.toFixed(1)}%`;
      if (opBar) {
        opBar.style.width = `${ocup}%`;
        if (ocup > 85) opBar.style.background = '#f0b429';
        if (ocup > 95) opBar.style.background = '#f03d3d';
      }
    }

    const cEl = document.getElementById('spkCritTxt');
    const cBar = document.getElementById('spkCritBar');
    if (cEl) {
      const crPct = Math.min(100, (crits.length / Math.max(1, total)) * 100 * 5); // x5 visual scale
      cEl.textContent = `${crits.length} urgências`;
      if (cBar) cBar.style.width = `${crPct}%`;
    }

  } catch (e) { if (window.__DEV) console.warn("[NX Sparks]:", e); }
  // Mission Control overlays (pipeline, heatmap, ticker, pulse)
  try {
    if (window.MC && typeof MC.updateFromDashboard === 'function') {
      MC.updateFromDashboard({
        total, pesoT, valorT, volT,
        disp, desc, planej, patio, inter, atras,
        forced: dashDB.filter(r => r.is_critico || r.is_agend).sort((a, b) => a.prio_num - b.prio_num).slice(0, 30),
        topDest,
      });
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

}

// ═══════════════════════════════════════════════════════
// ETAPA (Prazo de Embarque) — visão consolidada
// ═══════════════════════════════════════════════════════
const REGION_MAP = (function () {
  const m = {};
  const add = (name, arr) => { arr.forEach(k => m[k] = name); };

  add('Sao Paulo', ['ACP', 'BAU', 'BGI', 'CPQ', 'EXA', 'FRC', 'GR2', 'GRU', 'ITP', 'JDI', 'LIM', 'MNV', 'PIR', 'PP1', 'PPB', 'PPY', 'RAO', 'SAO', 'SCA', 'SJ1', 'SJK', 'SJP', 'SOD', 'SSZ']);
  add('Nordeste', ['AFS', 'AJU', 'ASG', 'BAR', 'CAU', 'ENP', 'FEC', 'FOR', 'IMP', 'INT', 'JDO', 'JPA', 'MCZ', 'NAT', 'PBA', 'PNZ', 'REC', 'SLZ', 'SSA', 'THE', 'VDC']);
  add('Norte-Co', ['AMI', 'AML', 'BEL', 'BSB', 'BVB', 'CGB', 'CGR', 'GOI', 'GYN', 'HMT', 'JPR', 'MAO', 'MCP', 'MSI', 'MTN', 'MTS', 'PMW', 'PVH', 'RBR', 'STM', 'TLG', 'TO2']);
  add('Sudeste', ['BHZ', 'DIV', 'GVR', 'IPN', 'ITA', 'JDF', 'MOC', 'RIO', 'RSD', 'SR2', 'SRR', 'TFL', 'UD2', 'UDI', 'VIX']);
  add('Sul', ['BNU', 'CA1', 'CAC', 'CCM', 'CWB', 'CXJ', 'FBE', 'FLN', 'IGU', 'JCB', 'JLL', 'LDO', 'MGF', 'PET', 'PFB', 'POA', 'RIA', 'SCZ', 'UMU', 'XAP']);

  return m;
})();

function fmtPct(v, dec = 1) {
  const n = (isFinite(v) ? v : 0);
  const s = n.toFixed(dec).replace('.', ',');
  return s + '%';
}
function fmtShortBRL(v) {
  const n = toNum(v);
  const abs = Math.abs(n);
  if (abs >= 1e9) return 'R$ ' + fmtNum(n / 1e9, 1) + 'B';
  if (abs >= 1e6) return 'R$ ' + fmtNum(n / 1e6, 0) + 'M';
  if (abs >= 1e3) return 'R$ ' + fmtNum(n / 1e3, 0) + 'K';
  return fmtMoeda(n);
}

function fmtIntShort(v) {
  const n = toNum(v);
  const abs = Math.abs(n);
  if (abs >= 1e9) return fmtNum(n / 1e9, 1) + 'B';
  if (abs >= 1e6) return fmtNum(n / 1e6, 1) + 'M';
  if (abs >= 1e3) return fmtNum(n / 1e3, 1) + 'K';
  return fmtNum(n, 0);
}


// ═══════════════════════════════════════════════════════
// LOCAL STORAGE RESILIENTE (Tracking Prevention Safe)
// ═══════════════════════════════════════════════════════
const safeLocalStorage = {
  _cache: {},

  getItem(key) {
    // Tenta localStorage (pode falhar com Tracking Prevention)
    try {
      const val = localStorage.getItem(key);
      if (val !== null) this._cache[key] = val;
      return val;
    } catch (e) {
      // Fallback para cache em memória
      return this._cache[key] || null;
    }
  },

  setItem(key, value) {
    try {
      localStorage.setItem(key, value);
      this._cache[key] = value;
    } catch (e) {
      // Tracking Prevention ou quota exceeded: apenas cache em memória
      this._cache[key] = value;
    }
  },

  removeItem(key) {
    try {
      localStorage.removeItem(key);
      delete this._cache[key];
    } catch (e) {
      delete this._cache[key];
    }
  }
};

