try { saved = localStorage.getItem('nexus_accent') || 'industrial'; } catch (e) { saved = safeLocalStorage.getItem('nexus_accent') || 'industrial'; }
try { saved = localStorage.getItem('nexus_theme') || 'dark'; } catch (e) { saved = safeLocalStorage.getItem('nexus_theme') || 'dark'; }

