function applyResponsiveFlags() {
  const w = window.innerWidth || 1200;
  document.body.classList.toggle('is-mobile', w <= 720);
  document.body.classList.toggle('is-tablet', w > 720 && w <= 1024);
  document.body.classList.toggle('is-desktop', w > 1024);
}
applyResponsiveFlags();
window.addEventListener('resize', applyResponsiveFlags, { passive: true });

function autoFitEtapaLayout() {
  // Uses viewport to set stable heights for ETAPA tables (prevents cramped / overflow on laptop/tablet/mobile)
  try {
    const vh = window.innerHeight || 900;
    const w = window.innerWidth || 1200;
    const isMob = w <= 720;
    const isTab = (w > 720 && w <= 1024);
    const base = isMob ? 0.34 : isTab ? 0.32 : 0.30;
    const h = Math.max(240, Math.min(540, Math.round(vh * base)));
    document.documentElement.style.setProperty('--et-table-h', h + 'px');
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function initEtapaTabs() {
  const tabs = document.getElementById('etapaTabs');
  if (!tabs || tabs.dataset.init) return;
  tabs.dataset.init = '1';

  const panels = {
    status: document.getElementById('etapaPanelStatus'),
    rota: document.getElementById('etapaPanelRota'),
    riscos: document.getElementById('etapaPanelRiscos'),
  };

  const setPane = (pane) => {
    // Always switch panels (show only selected panel)
    for (const [k, el] of Object.entries(panels)) {
      if (el) el.style.display = (k === pane ? '' : 'none');
    }
    tabs.querySelectorAll('.etab').forEach(b => b.classList.toggle('on', b.dataset.pane === pane));
    try {
      window._etapaTabs?.status?.redraw?.(true);
      window._etapaTabs?.rota?.redraw?.(true);
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  };

  tabs.addEventListener('click', (e) => {
    const b = e.target.closest('.etab');
    if (!b) return;
    tabs.dataset.pane = b.dataset.pane || 'status';
    try { localStorage.setItem('nexus_etapa_pane', tabs.dataset.pane); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    setPane(tabs.dataset.pane);
  });

  // Restore saved pane
  try { tabs.dataset.pane = tabs.dataset.pane || localStorage.getItem('nexus_etapa_pane') || 'status'; } catch (e) { tabs.dataset.pane = tabs.dataset.pane || 'status'; }
  setPane(tabs.dataset.pane);
}

window.addEventListener('resize', () => {
  if (document.body.classList.contains('page-etapa')) autoFitEtapaLayout();
}, { passive: true });


