function _tierColor(tier) {
  return (tier === 'ok') ? 'var(--em2)' : (tier === 'warn') ? 'var(--em3)' : 'var(--em4)';
}

/**
 * ETAPA SLA card (offline, legible, auto-fit)
 * - label: GERAL / INBOUND / OUTBOUND
 * - stats: {tot,atras,hoje,amanha,nop,sla,...}
 */
function renderEtapaGauge(hostId, label, stats) {
  const host = document.getElementById(hostId);
  if (!host) return;
  const s = stats || {};
  const pct = Math.max(0, Math.min(100, (isFinite(s.sla) ? s.sla : 0)));
  const tier = (pct < 80) ? 'bad' : (pct < 90) ? 'warn' : 'ok';
  const color = _tierColor(tier);
  const val = fmtPct(pct, 1);

  host.innerHTML = `
    <div class="sla-card" style="--p:${pct.toFixed(3)}" role="img" aria-label="${label} SLA ${val}">
      <div class="sla-top">
        <span class="sla-label">${label}</span>
        <span class="sla-badge" style="border-color:${color};color:${color}">${val}</span>
      </div>

      <div class="sla-main">
        <div class="sla-val" style="color:${color}">${val}</div>
        <div class="sla-unit">${fmtNum(s.tot || 0, 0)} CTE</div>
      </div>

      <div class="sla-bar" aria-hidden="true">
        <div class="sla-fill"></div>
        <div class="sla-pin"></div>
      </div>

      <div class="sla-meta">
        <span class="sla-chip bad">Atrasado <b>${fmtNum(s.atras || 0, 0)}</b></span>
        <span class="sla-chip warn">Hoje <b>${fmtNum(s.hoje || 0, 0)}</b></span>
        <span class="sla-chip">Amanhã <b>${fmtNum(s.amanha || 0, 0)}</b></span>
        <span class="sla-chip ok">No prazo <b>${sanitizeHTML(fmtNum(s.nop || 0, 0))}</b></span>
      </div>
    </div>
  `;
}


function groupBy(arr, keyFn) {
  const m = new Map();
  for (const r of arr) {
    const k = keyFn(r);
    if (!m.has(k)) m.set(k, []);
    m.get(k).push(r);
  }
  return m;
}
function aggStats(rows) {
  // ✅ CORREÇÃO (Auditoria): Sincronizar com countDistinctKnowledges para consistência
  // FASE 3: memoized — avoids re-scanning dataset on every tab switch
  const key = _aggStatsCacheKey(rows);
  if (_aggStatsCache.has(key)) return _aggStatsCache.get(key);
  // Usar CONHECIMENTOS DISTINTOS em vez de linhas (critério único)
  const tot = countDistinctKnowledges(rows);
  let atras = 0, hoje = 0, amanha = 0, nop = 0, peso = 0, vol = 0, val = 0;
  // Usar Set para contar atrasados DISTINTOS também (para SLA consistente)
  const atravSet = new Set(), hojeSet = new Set(), amanhaSet = new Set(), nopSet = new Set();
  for (const r of rows) {
    const cod = String(r.cod || r.ctrc || '').trim();
    if (!cod || cod === 'None') continue;
    if (r.prazo === 'Atrasado' && !atravSet.has(cod)) { atras++; atravSet.add(cod); }
    else if (r.prazo === 'Hoje' && !hojeSet.has(cod)) { hoje++; hojeSet.add(cod); }
    else if (r.prazo === 'Amanhã' && !amanhaSet.has(cod)) { amanha++; amanhaSet.add(cod); }
    else if (r.prazo === 'No Prazo' && !nopSet.has(cod)) { nop++; nopSet.add(cod); }
    peso += toNum(r.p_oper); vol += toNum(r.qtd_vol); val += toNum(r.vl_nf);
  }
  // SLA = (Total - Atrasados) / Total * 100
  const sla = (tot && tot > 0) ? ((tot - atras) / tot * 100) : 0;
  const result = { tot, atras, hoje, amanha, nop, peso, vol, val, sla };
  _aggStatsCache.set(key, result);
  return result;
}

function setSlaTone(id, sla) {
  const el = (typeof id === 'string') ? document.getElementById(id) : id;
  if (!el) return;
  el.classList.remove('cg', 'co', 'cr', 'cb');
  const p = Number(sla);
  if (!isFinite(p)) return;
  // thresholds aligned with operational tiers
  if (p < 80) el.classList.add('cr');
  else if (p < 90) el.classList.add('co');
  else el.classList.add('cg');
}

// ── Funções auxiliares de drilldown e filtros (escopo correto) ──
function _navEl(pageName) {
  return document.querySelector(`.nav .nt[onclick*="goPage('${pageName}'"]`) || document.querySelector(`.nav .nt`);
}
function _setSel(id, val) {
  const el = document.getElementById(id);
  if (!el) return;
  if (val == null || val === '') { el.value = ''; return; }
  const vv = String(val);
  let opt = [...el.options].find(o => o.value === vv);
  if (!opt) {
    opt = document.createElement('option');
    opt.value = vv;
    opt.textContent = vv;
    el.appendChild(opt);
  }
  el.value = vv;
}
function _setEstQuickFilter(status) {
  _estF = status || 'all';
  const wrap = document.querySelector('#pg-estoque .tb-left');
  if (!wrap) return;
  const btns = [...wrap.querySelectorAll('.tf')];
  btns.forEach(b => b.classList.remove('active'));
  const tgt = btns.find(b => (b.getAttribute('onclick') || '').includes(`'${_estF}'`)) || btns[0];
  if (tgt) tgt.classList.add('active');
}
function _prazoFromField(field) {
  if (field === 'atrasado') return 'Atrasado';
  if (field === 'hoje') return 'Hoje';
  if (field === 'amanha') return 'Amanhã';
  if (field === 'nop') return 'No Prazo';
  return '';
}
function drillToEstoque({ dest = null, status = null, prazo = null, search = null, region = null } = {}) {
  try {
    // region drilldown (ex.: Resumo por Rota / Totais)
    window._estDrillRegion = region || '';

    _setEstQuickFilter(status);
    // se veio região, limpa destino explícito (prioriza região)
    _setSel('estDest', (region ? '' : (dest || '')));
    _setSel('estPrazo', prazo || '');
    const sr = document.getElementById('estSrch'); if (sr) sr.value = search || '';
    estPage = 1;
    const nav = _navEl('estoque');
    if (nav) goPage('estoque', nav);
    renderEst();
  } catch (e) { console.warn(e); }
}
function initEtapaScopeFilter() {
  const root = document.getElementById('pg-etapa');
  if (!root || root.dataset.scopeInit) return;
  root.dataset.scopeInit = '1';

  // restore persisted scope
  try {
    const saved = localStorage.getItem('nexus_etapa_scope');
    if (saved) window._etapaScope = saved;
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  const scopes = [...root.querySelectorAll('.kpi-scope')];
  const applyUI = () => {
    const sc = window._etapaScope || 'all';
    scopes.forEach(k => k.classList.toggle('on', k.dataset.scope === sc));
  };

  const setScope = (sc) => {
    window._etapaScope = sc;
    try { localStorage.setItem('nexus_etapa_scope', sc); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    applyUI();
    try { renderEtapa(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  };

  applyUI();

  root.addEventListener('click', (e) => {
    const k = e.target.closest('.kpi-scope');
    if (!k) return;
    setScope(k.dataset.scope || 'all');
  });
  root.addEventListener('keydown', (e) => {
    if (e.key !== 'Enter' && e.key !== ' ') return;
    const k = e.target.closest('.kpi-scope');
    if (!k) return;
    e.preventDefault();
    setScope(k.dataset.scope || 'all');
  });

  // drilldown árvore (duplo clique em Atrasado/Hoje/Amanhã/No Prazo)
  root.addEventListener('dblclick', (e) => {
    const sum = e.target.closest('#etapaTree summary');
    if (!sum) return;
    const txt = (sum.textContent || '')?.trim().toLowerCase();
    let pr = null;
    if (txt.startsWith('atrasado')) pr = 'Atrasado';
    else if (txt.startsWith('hoje')) pr = 'Hoje';
    else if (txt.startsWith('aman')) pr = 'Amanhã';
    else if (txt.startsWith('no prazo')) pr = 'No Prazo';
    if (pr) drillToEstoque({ prazo: pr });
  });
}

function renderEtapa() {
  if (!DB.length) return;

  const all = DB;
  window._etapaQuickPrazo = window._etapaQuickPrazo || 'all';
  window._etapaSearch = window._etapaSearch || '';

  // scope filter (Geral / Inbound / Outbound)
  const saved = (window._etapaScope || (function () { try { return localStorage.getItem('nexus_etapa_scope'); } catch (e) { return null; } })() || 'all');
  window._etapaScope = (saved === 'inbound' || saved === 'outbound') ? saved : 'all';

  const inbound = all.filter(r => r.tipo_op === 'Entrega');
  const outbound = all.filter(r => r.tipo_op === 'Embarque');

  const a = aggStats(all);
  const ai = aggStats(inbound);
  const ao = aggStats(outbound);

  // KPIs — sempre mostram os 3 SLAs (e servem como filtro)
  setText('eSlaGeral', fmtPct(a.sla, 1)); setSlaTone('eSlaGeral', a.sla);
  setText('eSlaInbound', fmtPct(ai.sla, 1)); setSlaTone('eSlaInbound', ai.sla);
  setText('eSlaOutbound', fmtPct(ao.sla, 1)); setSlaTone('eSlaOutbound', ao.sla);

  const scopeRows = (window._etapaScope === 'inbound') ? inbound : (window._etapaScope === 'outbound') ? outbound : all;
  // toolbar filters (search + prazo quick chips) applied here so it works with and without Tabulator
  const q = String(window._etapaSearch || '').toLowerCase();
  const prazoQuick = window._etapaQuickPrazo || 'all';
  const qMatch = (r) => {
    if (!q) return true;
    const txt = (String(r.status || '') + ' ' + String(r.origem || '') + ' ' + String(r.destino || '') + ' ' + String(r.regiao || '') + ' ' + String(r.ctrc || '') + ' ' + String(r.remetente || '') + ' ' + String(r.destinatario || '')).toLowerCase();
    return txt.includes(q);
  };
  const prazoMatch = (r) => {
    if (prazoQuick === 'all') return true;
    const pr = String(r.prazo || '').toUpperCase();
    if (prazoQuick === 'Atrasado') return pr === 'ATRASADO';
    if (prazoQuick === 'Hoje') return pr === 'HOJE';
    if (prazoQuick === 'Amanhã') return pr === 'AMANHÃ' || pr === 'AMANHA';
    if (prazoQuick === 'No Prazo') return pr === 'NO PRAZO';
    return true;
  };
  const tipoOpMatch = (r) => {
    if (!window._etapaTipoOp || window._etapaTipoOp === 'all') return true;
    return r.tipo_op === window._etapaTipoOp;
  };
  const filteredRows = scopeRows.filter(r => qMatch(r) && prazoMatch(r) && tipoOpMatch(r));

  const sAgg = aggStats(filteredRows);

  setText('eTotal', fmtNum(sAgg.tot, 0));
  setText('eAtras', fmtNum(sAgg.atras, 0));
  setText('eHoje', fmtNum(sAgg.hoje, 0));
  setText('eAmanha', fmtNum(sAgg.amanha, 0));

  try {
    document.querySelectorAll('#pg-etapa .kpi-scope').forEach(k => k.classList.toggle('on', k.dataset.scope === window._etapaScope));
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try {
    document.querySelectorAll('#etapaToolbar .xchip').forEach(b => b.classList.toggle('on', (b.dataset.etp || 'all') === window._etapaQuickPrazo));
    const inp = document.getElementById('etapaSrch'); if (inp && String(inp.value || '') !== String(window._etapaSearch || '')) inp.value = window._etapaSearch || '';
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  // Status + Rota grids (Tabulator com fallback CSS Grid)
  const canTab = (typeof Tabulator !== 'undefined');
  window._etapaTabs = window._etapaTabs || { status: null, rota: null };

  // ---------- Status ----------
  const stMap = groupBy(filteredRows, r => String(r.status || '').toUpperCase() || '—');
  const order = ['DESCARGA', 'DISPONIVEL', 'INTERMEDIARIO', 'NO PATIO', 'PLANEJADO'];
  const keys = [...stMap.keys()].sort((x, y) => (order.indexOf(x) < 0 ? 999 : order.indexOf(x)) - (order.indexOf(y) < 0 ? 999 : order.indexOf(y)));

  const statusData = keys.map(k => {
    const s = aggStats(stMap.get(k));
    const accent = (k === 'DISPONIVEL') ? 'ok' : (k === 'DESCARGA' ? 'warn' : '');
    return { estoque: k, cte: s.tot, atrasado: s.atras, hoje: s.hoje, amanha: s.amanha, nop: s.nop, ton: (s.peso / 1000), volumes: s.vol, val: s.val, sla: s.sla, _accent: accent };
  });

  statusData.push({ estoque: 'Total Geral', cte: sAgg.tot, atrasado: sAgg.atras, hoje: sAgg.hoje, amanha: sAgg.amanha, nop: sAgg.nop, ton: (sAgg.peso / 1000), volumes: sAgg.vol, val: sAgg.val, sla: sAgg.sla, _total: true, _accent: 'bad' });

  const statusCols = [
    { title: 'Estoque', field: 'estoque', sorter: 'string', widthGrow: 2, frozen: true, headerTooltip: 'Estoque Atual' },
    { title: 'CTE', field: 'cte', sorter: 'number', hozAlign: 'right', minWidth: 74, formatter: (c) => fmtNum(c.getValue(), 0) },
    { title: 'Atra.', field: 'atrasado', sorter: 'number', hozAlign: 'right', minWidth: 74, formatter: (c) => `<span class="cr">${fmtNum(c.getValue(), 0)}</span>`, headerTooltip: 'Atrasado' },
    { title: 'Hoje', field: 'hoje', sorter: 'number', hozAlign: 'right', minWidth: 72, formatter: (c) => fmtNum(c.getValue(), 0) },
    { title: 'Aman.', field: 'amanha', sorter: 'number', hozAlign: 'right', minWidth: 72, formatter: (c) => fmtNum(c.getValue(), 0), headerTooltip: 'Amanhã' },
    { title: 'No P.', field: 'nop', sorter: 'number', hozAlign: 'right', minWidth: 72, formatter: (c) => fmtNum(c.getValue(), 0), headerTooltip: 'No Prazo' },
    { title: 'Ton', field: 'ton', responsive: 2, sorter: 'number', hozAlign: 'right', minWidth: 70, formatter: (c) => fmtNum(c.getValue(), 0), headerTooltip: 'Toneladas (Peso/1000)' },
    {
      title: 'Vol', field: 'volumes', responsive: 2, sorter: 'number', hozAlign: 'right', minWidth: 70,
      formatter: (c) => fmtIntShort(c.getValue()),
      tooltip: (c) => fmtNum(c.getValue(), 0),
      headerTooltip: 'Volumes'
    },
    { title: 'Vl', field: 'val', responsive: 1, sorter: 'number', hozAlign: 'right', minWidth: 92, formatter: (c) => fmtShortBRL(c.getValue()), headerTooltip: 'Valor Mercadoria' },
    { title: 'SLA', field: 'sla', sorter: 'number', hozAlign: 'right', minWidth: 74, formatter: (c) => fmtPct(c.getValue(), 2), headerTooltip: 'SLA Estoque' },
  ];

  function cssGridHTML(cols, data) {
    const head = cols.map(c => `<div class="cg-h">${c.title}</div>`).join('');
    const body = data.map(r => cols.map(c => {
      let v = r[c.field];
      if (c.field === 'sla') v = fmtPct(v, 2);
      else if (c.field === 'val') v = fmtShortBRL(v);
      else if (['cte', 'atrasado', 'hoje', 'amanha', 'nop', 'ton', 'volumes'].includes(c.field)) v = fmtNum(v, 0);
      else v = (v ?? '');
      const extra = (r._total ? ' cg-t' : '');
      return `<div class="cg-c${extra}">${v}</div>`;
    }).join('')).join('');
    return `<div class="cgrid" style="--cols:${cols.length}">${head}${body}</div>`;
  }

  const stEl = document.getElementById('etapaStatusGrid');
  if (stEl) {
    if (canTab) {
      if (!window._etapaTabs.status) {
        window._etapaTabs.status = new Tabulator(stEl, {
          data: statusData,
          layout: "fitColumns",
          height: "100%",
          reactiveData: false,
          selectable: false,
          placeholder: "Sem dados para exibir",
          responsiveLayout: (document.body.classList.contains('is-mobile') ? 'collapse' : 'hide'),
          rowHeight: 34,
          columns: statusCols,
          columnDefaults: { resizable: false, headerSort: true, headerSortTristate: true },
          rowFormatter: function (row) {
            const d = row.getData(); const el = row.getElement();
            if (d._total) el.classList.add('row-total');
            if (d._accent) { el.classList.add('row-accent'); if (d._accent === 'bad') el.classList.add('bad'); if (d._accent === 'warn') el.classList.add('warn'); }
          }

          ,
          rowClick: function (e, row) {
            const d = row.getData();
            if (!d || d._total) return;
            openEtapaGroupDetail('status', d);
          },

          rowDblClick: function (e, row) {
            const d = row.getData();
            if (!d || d._total) return;
            drillToEstoque({ status: d.estoque });
          },
          cellDblClick: function (e, cell) {
            const d = cell.getRow().getData();
            if (!d || d._total) return;
            const pr = _prazoFromField(cell.getField());
            drillToEstoque({ status: d.estoque, prazo: pr || null });
          }
        });
      } else {
        window._etapaTabs.status.setData(statusData);
      }
    } else {
      stEl.innerHTML = cssGridHTML(statusCols, statusData);
    }
  }

  // ---------- Rota (Tree / Totais em colunas + Drilldown) ----------
  const _regionOf = (code) => {
    const k = String(code || '').toUpperCase()?.trim();
    return REGION_MAP[k] || 'Outros';
  };

  // monta árvore: Região (totais) -> Destinos (linhas)
  const byRegion = groupBy(filteredRows, r => _regionOf(r.destino));
  const rotaData = [...byRegion.entries()].map(([region, rowsRegion]) => {
    const byDest = groupBy(rowsRegion, r => String(r.destino || '—').toUpperCase()?.trim() || '—');
    const children = [...byDest.entries()].map(([dest, rows]) => {
      const s = aggStats(rows);
      return {
        region, dest,
        cte: s.tot, atrasado: s.atras, hoje: s.hoje, amanha: s.amanha, nop: s.nop,
        ton: (s.peso / 1000), sla: s.sla,
        _leaf: true
      };
    }).sort((a, b) => (b.cte - a.cte));

    const sr = aggStats(rowsRegion);
    return {
      region, dest: region, _count: children.length,
      cte: sr.tot, atrasado: sr.atras, hoje: sr.hoje, amanha: sr.amanha, nop: sr.nop,
      ton: (sr.peso / 1000), sla: sr.sla,
      _node: true,
      _children: children
    };
  }).sort((a, b) => a.region.localeCompare(b.region));

  const rotaCols = [
    {
      title: 'Destino / Região', field: 'dest', sorter: 'string', minWidth: 180, widthGrow: 3, frozen: true, headerTooltip: 'Filial Destino / Região',
      formatter: (c) => {
        const d = c.getRow().getData();
        if (d && d._node) {
          const ct = isFinite(d._count) ? d._count : 0;
          return `<span class="muted2">${(d.region || d.dest || '—')}</span> <span class="muted">(${ct})</span>`;
        }
        return (c.getValue() || '—');
      }
    },
    {
      title: 'CTE', field: 'cte', sorter: 'number', hozAlign: 'right', minWidth: 70,
      formatter: (c) => {
        const d = c.getRow().getData(); const v = c.getValue();
        const txt = fmtNum(v, 0);
        if (d && d._node) return `<span class="cell-link" title="Abrir ESTOQUE filtrado">${txt}</span>`;
        return txt;
      }
    },
    {
      title: 'Atrasado', field: 'atrasado', sorter: 'number', hozAlign: 'right', minWidth: 90,
      formatter: (c) => `<span class="cr">${fmtNum(c.getValue(), 0)}</span>`, headerTooltip: 'Atrasado'
    },
    { title: 'Hoje', field: 'hoje', sorter: 'number', hozAlign: 'right', minWidth: 70, formatter: (c) => fmtNum(c.getValue(), 0) },
    { title: 'Amanhã', field: 'amanha', sorter: 'number', hozAlign: 'right', minWidth: 80, formatter: (c) => fmtNum(c.getValue(), 0), headerTooltip: 'Amanhã' },
    { title: 'No Prazo', field: 'nop', sorter: 'number', hozAlign: 'right', minWidth: 85, formatter: (c) => fmtNum(c.getValue(), 0), headerTooltip: 'No Prazo' },
    { title: 'Ton.', field: 'ton', sorter: 'number', hozAlign: 'right', minWidth: 70, formatter: (c) => fmtNum(c.getValue(), 0), headerTooltip: 'Toneladas (Peso/1000)' },
    { title: 'SLA %', field: 'sla', sorter: 'number', hozAlign: 'right', minWidth: 80, formatter: (c) => fmtPct(c.getValue(), 2) },
  ];

  const rtEl = document.getElementById('etapaRotaGrid');
  if (rtEl) {
    if (canTab) {
      if (!window._etapaTabs.rota) {
        window._etapaTabs.rota = new Tabulator(rtEl, {
          data: rotaData,
          layout: "fitDataFill",
          height: "100%",
          reactiveData: false,
          selectable: false,
          placeholder: "Sem dados para exibir",
          responsiveLayout: (document.body.classList.contains('is-mobile') ? 'collapse' : 'hide'),
          rowHeight: 34,
          columns: rotaCols,
          columnDefaults: { resizable: false, headerSort: true, headerSortTristate: true },

          dataTree: true,
          dataTreeChildField: "_children",
          dataTreeStartExpanded: false,
          dataTreeIndent: 18,

          rowFormatter: function (row) {
            const d = row.getData(); const el = row.getElement();
            if (d && d._node) el.classList.add('row-total');
          },
          rowClick: function (e, row) {
            const d = row.getData();
            if (!d || d._node) return; // only leaf (destino)
            openEtapaGroupDetail('rota', d);
          },

          // Drilldown: clique no TOTAL (CTE) abre ESTOQUE filtrado
          cellClick: function (e, cell) {
            const d = cell.getRow().getData();
            if (!d) return;
            if (cell.getField() === 'cte' && d._node) {
              drillToEstoque({ region: d.region });
              return;
            }
          },

          // Drilldown: duplo clique na linha/célula
          rowDblClick: function (e, row) {
            const d = row.getData();
            if (!d) return;
            if (d._node) { drillToEstoque({ region: d.region }); return; }
            drillToEstoque({ dest: d.dest });
          },
          cellDblClick: function (e, cell) {
            const d = cell.getRow().getData();
            if (!d) return;
            const pr = _prazoFromField(cell.getField());
            if (d._node) {
              drillToEstoque({ region: d.region, prazo: pr || null });
              return;
            }
            drillToEstoque({ dest: d.dest, prazo: pr || null });
          }
        });
      } else {
        window._etapaTabs.rota.setData(rotaData);
      }
    } else {
      rtEl.innerHTML = cssGridHTML(rotaCols, rotaData);
    }
  }


  // Tree view

  const tree = document.getElementById('etapaTree');
  if (tree) {
    const rootTitle = (FILIAL || 'HUB') + ' · ' + fmtNum(sAgg.tot, 0) + ' CTE' + (window._etapaScope === 'inbound' ? ' · INBOUND' : window._etapaScope === 'outbound' ? ' · OUTBOUND' : '');
    const rootMeta = `${fmtNum(sAgg.peso / 1000, 0)} ton · ${fmtNum(sAgg.vol, 0)} vol · ${fmtShortBRL(sAgg.val)} · SLA ${fmtPct(sAgg.sla, 1)}`;
    const byPrazo = ['Atrasado', 'Hoje', 'Amanhã', 'No Prazo', 'Sem Data'];

    const prazoDetails = byPrazo.map(p => {
      const subset = scopeRows.filter(r => (r.prazo || 'Sem Data') === p);
      if (!subset.length) return '';
      const s = aggStats(subset);
      const dotColor = p === 'Atrasado' ? 'var(--bad,#ef4444)' : (p === 'Hoje' ? 'var(--warn,#f0b429)' : 'var(--em)');
      const sumMeta = `${fmtNum(s.tot, 0)} · ${fmtNum(s.peso / 1000, 0)} ton · ${fmtNum(s.vol, 0)} vol · ${fmtShortBRL(s.val)} · SLA ${fmtPct(s.sla, 1)}`;

      // second level: by date (dt_prev)
      const byDate = groupBy(subset, r => {
        const d = parseDateSafe(r.dt_prev);
        if (!d) return 'Sem Data';
        const dd = String(d.getDate()).padStart(2, '0');
        const mm = String(d.getMonth() + 1).padStart(2, '0');
        const yy = d.getFullYear();
        return `${dd}/${mm}/${yy}`;
      });
      const dateEntries = [...byDate.entries()].sort((a, b) => a[0].localeCompare(b[0])).slice(0, 14);
      const datesHtml = dateEntries.map(([dt, rows]) => {
        const ds = aggStats(rows);
        const rowsByFlag = [];
        const ag = rows.filter(r => !!r.is_agend);
        const cr = rows.filter(r => !!r.is_critico);
        if (ag.length) {
          const as = aggStats(ag);
          rowsByFlag.push(`<div class="row"><div class="nm">Agendamento</div><div class="mv">${fmtNum(as.tot, 0)} · ${fmtNum(as.peso / 1000, 0)} ton · SLA ${fmtPct(as.sla, 1)}</div></div>`);
        }
        if (cr.length) {
          const cs = aggStats(cr);
          rowsByFlag.push(`<div class="row"><div class="nm">Cliente crítico</div><div class="mv">${fmtNum(cs.tot, 0)} · ${fmtNum(cs.peso / 1000, 0)} ton · SLA ${fmtPct(cs.sla, 1)}</div></div>`);
        }
        // top destinos in date
        const gDest = [...groupBy(rows, r => String(r.destino || '—').toUpperCase()).entries()]
          .map(([k, v]) => ({ k, s: aggStats(v) }))
          .sort((x, y) => y.s.tot - x.s.tot)
          .slice(0, 6)
          .map(x => `<div class="row"><div class="nm">${x.k}</div><div class="mv">${fmtNum(x.s.tot, 0)} · ${fmtNum(x.s.peso / 1000, 0)} ton · SLA ${fmtPct(x.s.sla, 1)}</div></div>`)
          .join('');
        const inner = (rowsByFlag.join('') + (gDest ? (`<div class="indent">${gDest}</div>`) : ''));
        return `<details>
          <summary>
            <div class="t-title">
              <span class="t-dot" style="background:${dotColor};box-shadow:0 0 0 3px rgba(16,163,127,.08)"></span>
              <span class="t-name">${dt}</span>
            </div>
            <div class="t-meta"><span class="pill">${fmtNum(ds.tot, 0)} CTE</span><span class="pill">${fmtNum(ds.peso / 1000, 0)} ton</span></div>
          </summary>
          <div class="indent">${inner || `<div class="row"><div class="nm">Sem detalhamento</div><div class="mv">${fmtNum(ds.tot, 0)} CTE</div></div>`}</div>
        </details>`;
      }).join('');

      return `<details open>
        <summary>
          <div class="t-title">
            <span class="t-dot" style="background:${dotColor}"></span>
            <span class="t-name">${p}</span>
          </div>
          <div class="t-meta"><span class="pill">${sumMeta}</span></div>
        </summary>
        <div class="indent">${datesHtml || `<div class="row"><div class="nm">Sem detalhamento</div><div class="mv">${sumMeta}</div></div>`}</div>
      </details>`;
    }).join('');

    tree.innerHTML = `<div class="tree">
      <details open>
        <summary>
          <div class="t-title"><span class="t-dot"></span><span class="t-name">${rootTitle}</span></div>
          <div class="t-meta"><span class="pill">${rootMeta}</span></div>
        </summary>
        <div class="indent">${prazoDetails}</div>
      </details>
    </div>`;

    // Adicionar evento de duplo clique aos elementos t-title para drill-down do Risco
    const tTitles = tree.querySelectorAll('.t-title');
    tTitles.forEach(el => {
      el.style.cursor = 'pointer';
      el.title = "Duplo clique para filtrar no Estoque";
      el.addEventListener('dblclick', function (e) {
        e.stopPropagation();
        const tName = this.querySelector('.t-name');
        if (tName) {
          // O texto retornado é o prazo (Hoje, Amanhã, Atrasado, etc) ou a data
          let pr = tName.textContent.trim();
          // Identificar se for a raiz da filial ignora
          if (pr.includes('HUB') || pr.includes('CTE')) return;
          drillToEstoque({ prazo: pr });
        }
      });
    });
  }
}

