let _estF = 'all', _patF = 'all', _atrF = 'all';

function estFilter(f, el) {
  // Atualizar o NxMultiSelect de status se existir
  const ms = NxMS.get('estStatus');
  if (ms) {
    if (f === 'all') ms.setValues([]);
    else ms.setValues([f]);
  }
  _estF = f; estPage = 1;
  renderEst();
}
function patioFilter(f, el) {
  // Atualizar o NxMultiSelect de prio se existir
  const ms = NxMS.get('patPrio');
  if (ms) {
    if (f === 'all') ms.setValues([]);
    else ms.setValues([f]);
  }
  _patF = f; patPage = 1;
  renderPat();
}
function atrasFilter(f, el) {
  // Atualizar o NxMultiSelect de status/motivo se existir
  const ms = NxMS.get('atrStatus');
  if (ms) {
    if (f === 'all') ms.setValues([]);
    else ms.setValues([f]);
  }
  _atrF = f; atrPage = 1;
  renderAtras();
}

function getEstData() {
  let d = [...DB];

  // Status: usa NxMultiSelect se disponível, fallback para _estF
  const statusSel = getMultiSel('estStatus');
  if (statusSel.length > 0) {
    d = d.filter(r => statusSel.includes(r.status));
  } else if (_estF !== 'all') {
    d = d.filter(r => r.status === _estF);
  }

  // Filial, Destino, Prazo: multi-select
  const fiSel = getMultiSel('estFilial');
  const deSel = getMultiSel('estDest');
  const prSel = getMultiSel('estPrazo');
  const sr = (document.getElementById('estSrch')?.value || '').toLowerCase();

  if (fiSel.length) d = d.filter(r => fiSel.includes(r.estoque));
  if (deSel.length) {
    d = d.filter(r => deSel.includes(r.destino));
    window._estDrillRegion = ''; // limpa drilldown de região quando filtro manual
  }
  if (prSel.length) d = d.filter(r => prSel.includes(r.prazo));

  const rg = (window._estDrillRegion || '');
  if (rg) d = d.filter(r => ((REGION_MAP[String(r.destino || '').toUpperCase()?.trim()] || 'Outros') === rg));
  if (sr) d = d.filter(r => srch(r, sr));
  try { d.forEach(r => { r.dias_estoque = calcDiasEstoque(r?.data || r?.emissao || ''); }); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  d.sort((a, b) => a.prio_num - b.prio_num);
  return applySortToData(d, 'estBody');
}
