function openEtapaGroupDetail(kind, data) {
  try {
    if (!DB || !DB.length || !data) return;
    const scope = window._etapaScope || 'all';
    let rows = DB;
    if (scope === 'inbound') rows = DB.filter(r => r.tipo_op === 'Entrega');
    else if (scope === 'outbound') rows = DB.filter(r => r.tipo_op === 'Embarque');

    let filtered = rows;
    if (kind === 'status') {
      filtered = rows.filter(r => String(r.status || '').toUpperCase() === String(data.estoque || '').toUpperCase());
    } else if (kind === 'rota') {
      filtered = rows.filter(r => String(r.destino || '').toUpperCase() === String(data.destino || '').toUpperCase());
    }
    // apply quick prazo when set (optional)
    if (window._etapaQuickPrazo && window._etapaQuickPrazo !== 'all') {
      filtered = filtered.filter(r => String(r.prazo || '') === window._etapaQuickPrazo);
    }

    const ag = (items) => ({
      c: items.length,
      p: items.reduce((s, r) => s + (r.p_oper || 0), 0),
      v: items.reduce((s, r) => s + (r.vl_nf || 0), 0),
      vol: items.reduce((s, r) => s + (r.qtd_vol || 0), 0),
      atras: items.filter(r => r.prazo === 'Atrasado').length
    });

    const a = ag(filtered);
    const sample = filtered
      .slice()
      .sort((x, y) => (x.prio_num || 9999) - (y.prio_num || 9999))
      .slice(0, 80);

    openDetail({
      title: kind === 'status' ? `ETAPA — ${data.estoque}` : `ETAPA — ${data.destino || 'DESTINO'}`,
      subtitle: `Escopo: ${scope === 'all' ? 'Geral' : scope === 'inbound' ? 'Inbound' : 'Outbound'} · Linhas: ${a.c} · Peso: ${fN2(a.p / 1000)} t · Valor: R$ ${fM(a.v)} · Vol: ${fmtIntShort(a.vol)}`,
      kv: [
        ['Atrasados', String(a.atras)],
        ['Filtro rápido', window._etapaQuickPrazo === 'all' ? '(nenhum)' : window._etapaQuickPrazo],
        ['Busca', window._etapaSearch ? window._etapaSearch : '(vazia)'],
      ],
      rows: sample
    });
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

