function closeDetail() {
  const bg = document.getElementById('detailBg');
  if (bg) bg.classList.remove('open');
  try { bg.setAttribute('aria-hidden', 'true'); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}
function openDetail(payload) {
  const bg = document.getElementById('detailBg');
  const title = document.getElementById('detailTitle');
  const sub = document.getElementById('detailSub');
  const body = document.getElementById('detailBody');
  if (!bg || !title || !sub || !body) return;
  title.textContent = payload?.title || 'DETALHES';
  sub.textContent = payload?.subtitle || '—';

  const kv = Array.isArray(payload?.kv) ? payload.kv : [];
  const rows = Array.isArray(payload?.rows) ? payload.rows : [];
  let defaultDateCol = 'PRAZO';
  if (window._etapaTipoOp === 'Entrega') defaultDateCol = 'ENTREGA MÁXIMA';

  const cols = Array.isArray(payload?.cols) ? payload.cols : ['CTRC', 'ORIGEM → DESTINO', defaultDateCol, 'STATUS', 'PESO (kg)', 'VL NF'];

  const kvHtml = kv.length ? `<div class="detail-grid">${kv.map(([k, v]) => `
      <div class="dkv"><div class="k">${escHtml(k)}</div><div class="v">${escHtml(v)}</div></div>`).join('')}</div>` : '';

  const listHtml = rows.length ? `
    <div class="detail-list">
      <div class="dl-head">
        <div style="font-weight:800;letter-spacing:.1em;text-transform:uppercase;font-size:11px">Itens (amostra)</div>
        <div class="has-text-muted" style="font-size:11px">${rows.length} linhas</div>
      </div>
      <div style="max-height:420px;overflow:auto">
        <table>
          <thead><tr>${cols.map(c => `<th>${escHtml(c)}</th>`).join('')}</tr></thead>
          <tbody>
            ${rows.map(r => `<tr>
              <td>${escHtml(r.ctrc || r.cod || '—')}</td>
              <td>${escHtml((r.origem || '—') + ' → ' + (r.destino || '—'))}</td>
              <td>${escHtml(r.prazo || '—')}</td>
              <td>${escHtml(r.status || '—')}</td>
              <td style="text-align:right">${fmtNum(r.p_oper || 0, 0)}</td>
              <td style="text-align:right">${fmtShortBRL(r.vl_nf || 0)}</td>
            </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>` : '';

  body.innerHTML = kvHtml + listHtml + (rows.length ? '' : `<div class="has-text-muted" style="padding:14px;font-size:12px">Nenhum detalhe disponível.</div>`);
  bg.classList.add('open');
  try { bg.setAttribute('aria-hidden', 'false'); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}


