function applySortToData(data, bodyId) {
  const state = window._sortState && window._sortState[bodyId];
  if (!state || !state.key) return data;
  const k = state.key, asc = state.dir === 'asc';
  return [...data].sort((a, b) => {
    let va = a[k], vb = b[k];
    if (va === null || va === undefined || va === 'None') va = '';
    if (vb === null || vb === undefined || vb === 'None') vb = '';

    const sa = String(va)?.trim(), sb = String(vb)?.trim();

    // 1) Números
    const na = parseFloat(sa), nb = parseFloat(sb);
    const bothNum = sa !== '' && sb !== '' && !isNaN(na) && !isNaN(nb);
    if (bothNum) return asc ? na - nb : nb - na;

    // 2) Datas (dd/mm/yyyy, dd-mm-yyyy, yyyy-mm-dd, ISO)
    const maybeDate = (k.startsWith('dt_') || k.includes('data') || /[\/\-]/.test(sa) || /[\/\-]/.test(sb));
    if (maybeDate) {
      const da = parseDateSafe(sa);
      const db = parseDateSafe(sb);
      if (da && db) {
        return asc ? (da.getTime() - db.getTime()) : (db.getTime() - da.getTime());
      }
    }

    // 3) Texto
    const la = sa.toLowerCase(), lb = sb.toLowerCase();
    return asc ? la.localeCompare(lb) : lb.localeCompare(la);
  });
}

function renderTbl(hId, bId, rows, cols, totalsData = null) {
  const h = document.getElementById(hId), b = document.getElementById(bId);
  if (!h || !b) return;
  // Get sort state from table element
  const tbl = h.closest('table');
  const sortKey = tbl ? tbl.dataset.sortKey : '';
  const sortDir = tbl ? tbl.dataset.sortDir : '';
  h.innerHTML = cols.map(c => {
    const isSorted = c.k === sortKey;
    const arrow = isSorted ? (sortDir === 'asc' ? ' ▲' : ' ▼') : '';
    const sortCls = isSorted ? (sortDir === 'asc' ? ' sa' : ' sd') : '';
    return `<th class="${sortCls?.trim()}" onclick="tblSort(this,'${hId}','${bId}','${c.k}')" data-key="${c.k}" style="cursor:pointer">${c.l}${arrow}</th>`;
  }).join('');
  const rowAttrs = (r) => {
    if (bId === 'planBody') return ` data-idx="${r.__i ?? ''}" onclick="openPlanDetail(${r.__i ?? -1})"`;
    return '';
  };

  // ✅ CORREÇÃO: Mensagem clara quando não há dados
  if (!rows || rows.length === 0) {
    b.innerHTML = '<tr><td colspan="' + cols.length + '" style="text-align:center;color:var(--muted);padding:40px;font-size:13px">Nenhum resultado</td></tr>';
    return;
  }

  // Render regular rows
  let html = rows.map((r, i) => `<tr${rowAttrs(r)} class="${rowCls(r)}" style="animation-delay:${Math.min(i * .005, .25)}s">${cols.map(c => `<td>${fc(c.k, r[c.k], r)}</td>`).join('')}</tr>`).join('');

  // Add totals row if totalsData is provided
  if (totalsData) {
    // ✅ CORREÇÃO: Primeira coluna relevante para TOTAIS (pode ser 'flag' ou 'ctrc')
    let firstColKey = cols[0].k;
    const totalsRow = `<tr class="totals-row" style="font-weight:600;background:var(--em08);border-top:2px solid var(--em25)">${cols.map(c => {
      if (c.k === firstColKey) return '<td style="color:var(--em);text-transform:uppercase">TOTAIS</td>';
      if (totalsData[c.k] !== undefined && totalsData[c.k] !== null) {
        return `<td>${fcTotal(c.k, totalsData[c.k])}</td>`;
      }
      return '<td></td>';
    }).join('')}</tr>`;
    html += totalsRow;
  }

  b.innerHTML = html;
}

window._sortState = {};
function tblSort(th, hId, bId, key) {
  const state = window._sortState[bId] || { key: '', dir: 'asc' };
  const dir = (state.key === key && state.dir === 'asc') ? 'desc' : 'asc';
  window._sortState[bId] = { key, dir };
  const tbl = th.closest('table');
  if (tbl) { tbl.dataset.sortKey = key; tbl.dataset.sortDir = dir; }
  // find and sort the data source
  const sortFns = { estBody: () => renderEst(), patBody: () => renderPat(), atrBody: () => renderAtras(), planBody: () => renderPlan(), descBody: () => renderDesc() };
  if (sortFns[bId]) { sortFns[bId](); }
}

function rowCls(r) {
  let c = '';
  if (r.is_critico) c += ' bl';
  else if (r.is_agend) c += ' bla';
  else if (r.prazo === 'Atrasado') c += ' bld';
  else if (r.prazo === 'Hoje') c += ' blh';
  if (r.status === 'DISPONIVEL') c += ' blv';
  // Planejamento: destacar selecionados sem criar coluna extra
  if (r.flag === 1) c += ' bls';
  return c?.trim();
}

function escHtml(s) {
  return String(s ?? '').replace(/[&<>"'`]/g, c => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;', '`': '&#96;'
  }[c]));
}
function escAttr(s) { return escHtml(s); }

// Dias em estoque = Data vs hoje()
function calcDiasEstoque(dataStr) {
  const d = parseDateSafe(dataStr);
  if (!d) return null;
  const t = new Date(); t.setHours(0, 0, 0, 0);
  d.setHours(0, 0, 0, 0);
  const diff = Math.round((t.getTime() - d.getTime()) / 86400000);
  return isFinite(diff) ? diff : null;
}

function fc(k, v, r) {
  // dias_estoque é derivado: tenta calcular mesmo quando não veio pronto
  if (k === 'dias_estoque') {
    const d = (typeof v === 'number' && isFinite(v)) ? v : calcDiasEstoque(r?.data || r?.Data || r?.emissao || '');
    if (d === null || d === undefined) return '<span style="color:var(--muted)">—</span>';
    const col = d >= 15 ? 'var(--em4)' : d >= 7 ? 'var(--em3)' : 'var(--muted2)';
    return `<span style="color:${col}">${escHtml(d)}</span>`;
  }

  if (v === null || v === undefined || v === '' || v === 'None') return '<span style="color:var(--muted)">—</span>';
  switch (k) {
    case 'status': return bSt(v);
    case 'prazo': return bPr(v);
    case 'risco': return bRi(v);
    case 'tipo_op': return bTo(v);
    case 'prio_fluxo': return v === 'Prioridade' ? '<span class="b br">PRIO.</span>' : '<span class="b bm">FLUXO</span>';
    case 'vl_nf': return `<span style="color:var(--em2)">R$ ${fM(v)}</span>`;
    case 'p_oper': return `<span class="num">${fN2(v)}</span>`;
    case 'qtd_vol': return `<span class="num">${fN(v)}</span>`;
    case 'flag': return v === 1 ? '<span class="b bg">✓ SIM</span>' : '<span class="b br">✕ NÃO</span>';
    case 'is_critico': return v ? '<span class="b br">⚡ SIM</span>' : '<span style="color:var(--muted)">—</span>';
    case 'is_agend': return v ? '<span class="b bo">📅 SIM</span>' : '<span style="color:var(--muted)">—</span>';
    case '_print_flag': return `<label class="switch dsc-pr-sw" title="Imprimir"><input type="checkbox" data-id="${escAttr(r.ctrc || '')}" ${v !== false ? 'checked' : ''} onchange="toggleDescPrint(this, '${escAttr(r.ctrc || '')}')"><span class="slider"></span></label>`;
    case 'equipamento': return v && v > 0 ? `<span style="color:var(--em2)">${escHtml(v)}</span>` : '<span style="color:var(--muted)">—</span>';
    case 'dias': return `<span style="color:${v < 0 ? 'var(--em4)' : v === 0 ? 'var(--em3)' : 'var(--muted2)'}">${escHtml(v)}</span>`;
    case 'dt_prev':
    case 'dt_entrega':
      return `<span style="color:var(--muted2)">${escHtml(String(v).slice(0, 16))}</span>`;
    case 'ctrc': return `<span style="font-size:10px;color:var(--txt)">${escHtml(v)}</span>`;
    default: {
      const s = String(v ?? '');
      if (s.length > 28) {
        return `<span title="${escAttr(s)}">${escHtml(s.slice(0, 26))}…</span>`;
      }
      return escHtml(s);
    }
  }
}

// ═══════════════════════════════════════════════════════
// TOTALS CALCULATION & FORMATTING
// ═══════════════════════════════════════════════════════

// Conta conhecimentos DISTINTOS (um COD pode ter múltiplas NFs)
function countDistinctKnowledges(data) {
  if (!data || !data.length) return 0;
  const uniqueCods = new Set();
  data.forEach(r => {
    // Priorizar COD, depois CTRC (conhecimento identificador único)
    const cod = String(r.cod || r.ctrc || '').trim();
    if (cod && cod !== 'None') uniqueCods.add(cod);
  });
  return uniqueCods.size;
}

function calculateTotals(data, keys) {
  // ✅ CORREÇÃO (Auditoria): Unificado para usar SEMPRE lógica consistente
  const totals = {};
  const numericKeys = ['p_oper', 'qtd_vol', 'vl_nf', 'equipamento', 'dias_estoque'];

  numericKeys.forEach(key => {
    if (keys.includes(key)) {
      const sum = data.reduce((acc, row) => {
        const val = parseFloat(row[key]);
        return acc + (isNaN(val) ? 0 : val);
      }, 0);
      totals[key] = sum;
    }
  });

  // Count DISTINCT conhecimentos (SEMPRE - critério unificado)
  totals._count = countDistinctKnowledges(data);

  // Adicionar contagem de registros para referência (interna)
  totals._rows = data.length;

  return totals;
}

function fcTotal(k, v) {
  // ✅ CORREÇÃO (Auditoria): Formatação consistente de totais
  if (v === null || v === undefined) return '';
  switch (k) {
    case 'vl_nf': return `<span style="color:var(--em2);font-weight:700">R$ ${fM(v)}</span>`;
    case 'p_oper': return `<span class="num" style="font-weight:700">${fN2(v)}</span>`;
    case 'qtd_vol': return `<span class="num" style="font-weight:700">${fN(v)}</span>`;
    case 'equipamento': return `<span style="color:var(--em2);font-weight:700">${fN(v)}</span>`;
    case 'dias_estoque': return `<span class="num" style="font-weight:700">${fN(v)}</span>`;
    case 'flag': return '';
    default: return escHtml(String(v));
  }
}

window.toggleDescPrint = function (el, ctrc) {
  const g = window._descGroups[window._descSelectedId];
  if (g && g.rows) {
    g.rows.forEach(r => {
      if (String(r.ctrc || r.cod || '') === String(ctrc)) r._print_flag = el.checked;
    });

    // Update "select all" header checkbox state dynamically
    const tbl = document.getElementById('descDetailHead');
    if (tbl) {
      const allToggle = tbl.querySelector('#dscPrintAll');
      if (allToggle) {
        const allChecked = g.rows.every(row => row._print_flag !== false);
        allToggle.checked = allChecked;
      }
    }
  }
};

window.toggleAllDescPrint = function (el) {
  const g = window._descGroups[window._descSelectedId];
  if (g && g.rows) {
    g.rows.forEach(r => {
      r._print_flag = el.checked;
    });
    // Re-render detail table to visually update all rows instantly
    renderDescDetail(g.rows);
  }
};

function bSt(v) { const m = { DISPONIVEL: 'bg', DESCARGA: 'bo', PLANEJADO: 'bb', 'NO PATIO': 'bm', INTERMEDIARIO: 'bw', 'PLAN. SIMULADO': 'bb' }; return `<span class="b ${m[v] || 'bm'}">${v}</span>`; }
function bPr(v) { const m = { Atrasado: 'br', Hoje: 'bo', Amanhã: 'bb', 'No Prazo': 'bg', 'Sem Data': 'bm' }; return `<span class="b ${m[v] || 'bm'}">${v}</span>`; }
function bRi(v) { if (v === 'Cliente Crítico') return `<span class="b br">⚡ ${v}</span>`; if (v === 'Agendamento') return `<span class="b bo">📅 ${v}</span>`; if (v === 'Prazo Embarque') return `<span class="b bo">⚠ ${v}</span>`; return `<span class="b bm">${v}</span>`; }
function bTo(v) { const m = { Embarque: 'bg', Reembarque: 'bb', Entrega: 'bo' }; return `<span class="b ${m[v] || 'bm'}">${v}</span>`; }

// ═══════════════════════════════════════════════════════
// DESCARGA v8.2 — PAINEL INTERATIVO (TWO-COLUMN)
// ═══════════════════════════════════════════════════════
window._descTypeFilter = 'geral';
window._descGroups = [];
window._descSelectedId = null;

function descTypeFilter(type, el) {
  window._descTypeFilter = type;
  document.querySelectorAll('.desc-type-btn').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  window._descSelectedId = null;
  renderDesc();
}

function buildDescGroups(rows, keyFn) {
  const map = new Map();
  rows.forEach(r => {
    const k = keyFn(r) || '—';
    if (!map.has(k)) map.set(k, []);
    map.get(k).push(r);
  });
  return [...map.entries()].map(([id, rows]) => ({ id, rows }));
}

function calcDescScores(groups) {
  const now = Date.now();
  // Compute raw values per group
  groups.forEach(g => {
    g.pesoTotal = g.rows.reduce((s, r) => s + (r.p_oper || 0), 0);
    g.volTotal = g.rows.reduce((s, r) => s + (r.qtd_vol || 0), 0);
    g.valorTotal = g.rows.reduce((s, r) => s + (r.vl_nf || 0), 0);
    g.qtdCtes = g.rows.length;
    g.hasCrit = g.rows.some(r => r.is_critico);
    g.hasAgend = g.rows.some(r => r.is_agend);
    // SLA raw: count fraction NOT in prazo (Atrasado=0 → worst score)
    const total = g.rows.length || 1;
    const noPrazo = g.rows.filter(r => r.prazo === 'Atrasado' || r.prazo === 'Hoje').length;
    g.slaRaw = 1 - (noPrazo / total); // 0=bad, 1=good; for score: menor sla = mais urgente
    // MinutosFilaRaw: rows where motivo = 'Cheg.real MAC'
    const macRows = g.rows.filter(r => String(r.motivo || '')?.trim() === 'Cheg.real MAC');
    if (macRows.length > 0) {
      // Use earliest data entry as reference
      let earliest = now;
      macRows.forEach(r => {
        if (r.data) {
          const d = parseDateSafe ? parseDateSafe(r.data) : null;
          if (d && d.getTime() < earliest) earliest = d.getTime();
        }
      });
      g.minutosFilaRaw = Math.max(0, (now - earliest) / 60000);
    } else {
      g.minutosFilaRaw = 0;
    }
  });

  if (groups.length <= 1) {
    groups.forEach(g => { g.score = g.slaRaw; });
    return groups;
  }

  const mn = arr => Math.min(...arr);
  const mx = arr => Math.max(...arr);
  const norm = (v, lo, hi) => hi === lo ? 0 : (v - lo) / (hi - lo);

  const slaVals = groups.map(g => g.slaRaw);
  const minuVals = groups.map(g => g.minutosFilaRaw);
  const pesoVals = groups.map(g => g.pesoTotal);
  const volVals = groups.map(g => g.volTotal);

  groups.forEach(g => {
    // SLA: invertido (menor sla_raw = mais urgente = maior score)
    const nSla = 1 - norm(g.slaRaw, mn(slaVals), mx(slaVals));
    const nFila = norm(g.minutosFilaRaw, mn(minuVals), mx(minuVals));
    const nPeso = norm(g.pesoTotal, mn(pesoVals), mx(pesoVals));
    const nVol = norm(g.volTotal, mn(volVals), mx(volVals));
    g.score = nSla * 0.45 + nFila * 0.10 + nPeso * 0.35 + nVol * 0.10;
  });
  return groups;
}

function renderDescCards(groups) {
  const list = document.getElementById('descCardList');
  if (!list) return;
  if (!groups.length) {
    list.innerHTML = '<div style="padding:14px;text-align:center;color:var(--muted);font-size:11px">Nenhum grupo encontrado</div>';
    return;
  }
  list.innerHTML = groups.map((g, idx) => {
    const tagCls = g.hasCrit ? 'crit' : g.hasAgend ? 'agend' : 'ok';
    const tagTxt = g.hasCrit ? '⚡ CRÍTICO' : g.hasAgend ? '📅 AGENDADO' : '✓ NO PRAZO';
    const cardCls = g.id === window._descSelectedId ? ' selected' : '';
    const borderCls = g.hasCrit ? ' tag-crit' : g.hasAgend ? ' tag-agend' : ' tag-prazo';
    const scorePct = (g.score * 100).toFixed(0);
    const safeId = escAttr(g.id);

    let fatores = [];
    if (g.hasCrit) fatores.push('<span style="color:var(--em4);font-weight:600">Crítico</span>');
    if (g.hasAgend) fatores.push('<span style="color:var(--em3);font-weight:600">Agendado</span>');
    if (g.slaRaw < 1) fatores.push('<span style="color:var(--em2);font-weight:600">Atraso/Hoje</span>');

    let fatorText = fatores.length > 0
      ? `<div class="dsc-ct" style="font-size:9.5px; color:var(--muted)">Atributos: ${fatores.join(', ')}</div>`
      : `<div class="dsc-ct" style="font-size:9.5px; color:var(--muted)">Atributos: Fila Normal</div>`;

    return `<div class="desc-score-card${borderCls}${cardCls}" id="dcard-${idx}"
          onclick="selectDescCard(${idx})"
          style="animation-delay:${Math.min(idx * .04, .5)}s">
          <div class="dsc-top">
            <div class="dsc-id" title="${safeId}">${escHtml(g.id.replace('||', ' · ').slice(0, 36))}</div>
            <span class="dsc-tag ${tagCls}">${tagTxt}</span>
          </div>
          <div class="dsc-ct" style="margin-bottom:3px">${g.qtdCtes} CT-e(s) · Score: ${scorePct}%</div>
          ${fatorText}
          <div class="dsc-kpis">
            <div class="dsc-kpi">
              <div class="dsc-kl">Peso</div>
              <div class="dsc-kv">${fN2(g.pesoTotal / 1000)}<span style="font-size:9px;color:var(--muted)"> t</span></div>
            </div>
            <div class="dsc-kpi">
              <div class="dsc-kl">Valor NF</div>
              <div class="dsc-kv" style="color:var(--em2);font-size:10px">R$ ${fM(g.valorTotal)}</div>
            </div>
            <div class="dsc-kpi">
              <div class="dsc-kl">Volumes</div>
              <div class="dsc-kv">${fN(g.volTotal)}</div>
            </div>
          </div>
          <div class="dsc-score-bar">
            <div class="dsc-score-fill" style="width:${scorePct}%"></div>
          </div>
        </div>`;
  }).join('');
}

function selectDescCard(idx) {
  window._descSelectedId = idx;
  // Update highlight
  document.querySelectorAll('.desc-score-card').forEach((c, i) => {
    c.classList.toggle('selected', i === idx);
  });
  const g = window._descGroups[idx];
  if (!g) return;
  document.getElementById('descDetailTitle').textContent = g.id.replace('||', ' · ').slice(0, 60);
  document.getElementById('descDetailSub').textContent = `${g.qtdCtes} CT-e(s) · ${fN2(g.pesoTotal / 1000)} t · R$ ${fM(g.valorTotal)}`;
  document.getElementById('descDetailWrap').style.display = '';
  document.getElementById('descDetailEmpty').style.display = 'none';
  renderDescDetail(g.rows);
}

function deduplicateByCTRC(rows) {
  // Agrupa por CTRC e soma os totais (peso, volumes, valor)
  // Preserva o registro mais prioritário como base (menor prio_num)
  const map = new Map();
  rows.forEach(r => {
    const key = String(r.ctrc || r.cod || '')?.trim();
    if (!key) return;
    if (!map.has(key)) {
      // preserve _print_flag state if exists, otherwise true
      const pf = r._print_flag !== undefined ? r._print_flag : true;
      map.set(key, { ...r, p_oper: 0, qtd_vol: 0, vl_nf: 0, _print_flag: pf });
    }
    const agg = map.get(key);
    agg.p_oper += (r.p_oper || 0);
    agg.qtd_vol += (r.qtd_vol || 0);
    agg.vl_nf += (r.vl_nf || 0);
    // keep most urgent prio_num
    if ((r.prio_num || 99) < (agg.prio_num || 99)) {
      const saved_p = agg.p_oper, saved_v = agg.qtd_vol, saved_vl = agg.vl_nf;
      Object.assign(agg, r);
      agg.p_oper = saved_p; agg.qtd_vol = saved_v; agg.vl_nf = saved_vl;
    }
  });
  return [...map.values()];
}

function renderDescDetail(rows) {
  const deduped = deduplicateByCTRC(rows);
  deduped.sort((a, b) => (a.prio_num || 99) - (b.prio_num || 99));

  const allChecked = deduped.length > 0 && deduped.every(r => r._print_flag !== false);
  const toggleAllHtml = `<label class="switch dsc-pr-sw" title="Selecionar Todos" onclick="event.stopPropagation()"><input type="checkbox" id="dscPrintAll" ${allChecked ? 'checked' : ''} onchange="toggleAllDescPrint(this)"><span class="slider"></span></label>`;

  const cols = [
    { k: '_print_flag', l: toggleAllHtml },
    { k: 'ctrc', l: 'CTRC' },
    { k: 'nr_coleta', l: 'NR_COLETA' },
    { k: 'equipamento', l: 'Equipamento' },
    { k: 'dt_prev', l: 'DT. PREV' },
    { k: 'dt_entrega', l: 'DT ENTREGA' },
    { k: 'remetente', l: 'remetente' },
    { k: 'destinatario', l: 'destinatario' },
    { k: 'origem', l: 'origem' },
    { k: 'destino', l: 'destino' },
    { k: 'p_oper', l: 'p_oper' },
    { k: 'qtd_vol', l: 'qtd_vol' },
    { k: 'vl_nf', l: 'vl_nf' },
    { k: 'prazo', l: 'prazo' },
    { k: 'status', l: 'status' },
    { k: 'risco', l: 'risco' },
    { k: 'is_critico', l: 'is_critico' },
  ];
  const totals = calculateTotals(deduped, cols.map(c => c.k));
  renderTbl('descDetailHead', 'descDetailBody', deduped, cols, totals);
}

function renderDesc() {
  const fiSel = getMultiSel('descFilial');
  const prSel = getMultiSel('descPrazo');
  const riSel = getMultiSel('descRisco');
  const tiSel = getMultiSel('descTipo'); // Geral/Coleta/Reembarque/Entrega

  // Mapear seleção de tipo para typeFilter (compatibilidade)
  let typeFilter = window._descTypeFilter || 'geral';
  if (tiSel.length === 1) {
    // Se single-select de tipo: usar esse valor
    const tipoMap = { 'Geral': 'geral', 'Coleta': 'coleta', 'Reembarque': 'reembarque', 'Entrega': 'entrega' };
    typeFilter = tipoMap[tiSel[0]] || 'geral';
  }

  // Pool: somente DESCARGA + NO PATIO
  let pool = DB.filter(r => {
    if (r.status !== 'DESCARGA' && r.status !== 'NO PATIO') return false;
    if (fiSel.length && !fiSel.includes(r.estoque) && !fiSel.includes(r.origem)) return false;
    if (prSel.length && !prSel.includes(r.prazo)) return false;
    if (riSel.length) {
      // Risco: mapear o campo risco ao valor esperado
      const risco = (r.risco || '').toUpperCase();
      if (!riSel.some(rs => risco.includes(rs.toUpperCase()))) return false;
    }
    return true;
  });

  let groups = [];
  if (typeFilter === 'coleta') {
    // COLETA: agrupa por NR_COLETA + Remetente (sem fallback para ctrc)
    const sub = pool.filter(r => r.estoque === r.origem);
    groups = buildDescGroups(sub, r =>
      `${r.nr_coleta || '—'}||${r.remetente || '—'}`
    );
  } else if (typeFilter === 'reembarque') {
    // REEMBARQUE: Orig (estoque = campo Orig do relatório) + Nr_Mac
    const sub = pool.filter(r => r.origem !== r.estoque && r.destino !== r.estoque);
    groups = buildDescGroups(sub, r =>
      `${r.estoque || '—'}||${r.nr_mac || '—'}`
    );
  } else if (typeFilter === 'entrega') {
    // ENTREGA: destino == estoque → Orig + Nr_Mac
    const sub = pool.filter(r => r.destino === r.estoque);
    groups = buildDescGroups(sub, r =>
      `${r.estoque || '—'}||${r.nr_mac || '—'}`
    );
  } else {
    // GERAL: todos misturados
    groups = buildDescGroups(pool, r => {
      if (r.estoque === r.origem)
        return `COL·${r.nr_coleta || '—'}||${r.remetente || '—'}`;
      return `REM·${r.estoque || '—'}||${r.nr_mac || '—'}`;
    });
  }

  groups = calcDescScores(groups);

  // NOVO: Filtro Risco Descarga (pós-grupo)
  const rk = document.getElementById('descRisco')?.value;
  if (rk) {
    groups = groups.filter(g => {
      if (rk === 'CRÍTICO') return g.hasCrit;
      if (rk === 'ALTO') return !g.hasCrit && (g.hasAgend || g.slaRaw < 1);
      if (rk === 'MÉDIO') return !g.hasCrit && !g.hasAgend && g.slaRaw >= 1;
      return true;
    });
  }

  // Extratificar os fatores de cada grupo para exibição visual na UI (sem alterar a ordem)
  groups.forEach(g => {
    g.orderTier = 0;
    if (g.hasCrit) g.orderTier = 3;
    else if (g.hasAgend) g.orderTier = 2;
    else if (g.slaRaw < 1) g.orderTier = 1; // SLA comprometido (Atrasado/Hoje)
  });

  // Ordenar ESTRITAMENTE pelo Score Operacional (0 a 100%) conforme regra de classificacao
  groups.sort((a, b) => b.score - a.score);
  window._descGroups = groups;

  const total = groups.reduce((s, g) => s + g.qtdCtes, 0);
  const pesoT = groups.reduce((s, g) => s + g.pesoTotal, 0);
  const el = document.getElementById('descCnt');
  if (el) el.textContent = `${groups.length} grupos · ${fN(total)} CT-es · ${fN2(pesoT / 1000)} t`;

  renderDescCards(groups);

  // Re-select previously selected (by index) or first
  const selIdx = (window._descSelectedId !== null && window._descSelectedId < groups.length)
    ? window._descSelectedId : (groups.length ? 0 : null);
  if (selIdx !== null) {
    selectDescCard(selIdx);
  } else {
    document.getElementById('descDetailWrap').style.display = 'none';
    document.getElementById('descDetailEmpty').style.display = '';
  }
}

function exportDescPDF() {
  const g = window._descGroups[window._descSelectedId !== null ? window._descSelectedId : 0];
  if (!g || !g.rows) { toast('Nenhum grupo selecionado', 'Clique em um card primeiro', 'warn'); return; }

  const dedupedRows = deduplicateByCTRC(g.rows);
  const toPrint = dedupedRows.filter(r => r._print_flag !== false);

  if (!toPrint.length) { toast('Seleção Vazia', 'Marque ao menos um CTRC na coluna 🖨', 'warn'); return; }
  printReport('descarga_grupo', toPrint, g.id.replace('||', ' · '));
}

