function downloadFile(name, type, content) {
  // ✅ CORREÇÃO: Download robusto contra Tracking Prevention
  try {
    // Método 1: Blob + URL.createObjectURL (melhor compatibilidade com Tracking Prevention)
    const blob = new Blob([content], { type: type + ';charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = name;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    toast('✓ Arquivo baixado', name, 'ok');
  } catch (e) {
    // Fallback: data: URL (quando Blob/URL falha)
    try {
      const a = document.createElement('a');
      a.href = 'data:' + type + ';charset=utf-8,' + encodeURIComponent(content);
      a.download = name;
      a.click();
      toast('✓ Arquivo criado', name, 'ok');
    } catch (e2) {
      // Último recurso: abrir em nova janela (usuário copia manualmente)
      const w = window.open();
      w.document.write(content);
      w.document.close();
      toast('⚠ Aberto em nova janela', 'Copie e salve manualmente', 'warn');
    }
  }
}

function paginate(id, total, page, ps, cb) {
  const el = document.getElementById(id); if (!el) return;
  const pages = Math.ceil(total / ps);
  if (pages <= 1) { el.innerHTML = ''; return; }
  el.innerHTML = `<button class="pg-b" ${page <= 1 ? 'disabled' : ''} onclick="(${cb})(${page - 1})">‹ Anterior</button><span class="pg-info"> Página ${page} de ${pages} · ${fN(total)} registros </span><button class="pg-b" ${page >= pages ? 'disabled' : ''} onclick="(${cb})(${page + 1})">Próxima ›</button>`;
}

