// Fuzzy score: higher = better match
function __cpFuzzy(str, query) {
  if (!query) return 1;
  str = str.toLowerCase(); query = query.toLowerCase();
  if (str.includes(query)) return 2;
  // character sequence match
  let si = 0, qi = 0, score = 0;
  while (si < str.length && qi < query.length) {
    if (str[si] === query[qi]) { score++; qi++; }
    si++;
  }
  return qi === query.length ? safeAverage(score, query.length) : 0;
}

let __cpHistory = [];
try { __cpHistory = JSON.parse(localStorage.getItem('nexus_cp_history') || '[]'); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
let __cpActive = 0;

function openCP() {
  const bg = document.getElementById('cpBg'); if (!bg) return;
  bg.classList.add('open');
  const input = document.getElementById('cpIn');
  if (input) { input.value = ''; input.focus(); }
  __cpActive = 0;
  renderCP('');
}
function closeCP() {
  document.getElementById('cpBg')?.classList.remove('open');
}
function renderCP(q) {
  const list = document.getElementById('cpList');
  if (!list) return;
  const query = (q || '')?.trim().toLowerCase();

  let items;
  if (!query && __cpHistory.length) {
    // Show recent commands first
    const recent = __cpHistory.slice(-5).reverse().map(k => __cpCmds.find(c => c.key === k)).filter(Boolean);
    const rest = __cpCmds.filter(c => !recent.includes(c));
    items = [...recent, ...rest];
  } else if (query) {
    items = __cpCmds
      .map(c => ({ c, score: __cpFuzzy(c.key + ' ' + c.name + ' ' + c.desc, query) }))
      .filter(x => x.score > 0)
      .sort((a, b) => b.score - a.score)
      .map(x => x.c);
  } else {
    items = [...__cpCmds];
  }

  if (!items.length) {
    list.innerHTML = `<div class="cp-empty">Nenhum comando encontrado para "<strong>${sanitizeHTML(q)}</strong>"</div>`;
    return;
  }

  // Build markup with keyboard active state
  const recentKeys = __cpHistory.slice(-5);
  list.innerHTML = items.map((c, i) => `
    <div class="cp-item${i === __cpActive ? ' active' : ''}" data-i="${i}" data-key="${c.key}" role="option" aria-selected="${i === __cpActive}">
      <div class="cp-l">
        <div class="cp-a">${recentKeys.includes(c.key) ? '<span style="color:var(--em3);font-size:9px;margin-right:6px">RECENTE</span>' : ''}${c.name}</div>
        <div class="cp-b">${c.desc}</div>
      </div>
      <div class="cp-r"><span class="cp-tag">${c.tag}</span></div>
    </div>
  `).join('');

  // Event delegation on list
  list.onclick = (e) => {
    const el = e.target.closest('.cp-item');
    if (!el) return;
    const idx = Number(el.dataset.i);
    __cpExec(items[idx]);
  };

  // Store items for keyboard nav
  list._items = items;
  __cpActive = Math.min(__cpActive, items.length - 1);
  __cpScrollActive(list);
}

function __cpScrollActive(list) {
  const active = list.querySelector('.cp-item.active');
  if (active) active.scrollIntoView({ block: 'nearest' });
}

function __cpExec(cmd) {
  if (!cmd) return;
  // Save to history
  __cpHistory = __cpHistory.filter(k => k !== cmd.key);
  __cpHistory.push(cmd.key);
  if (__cpHistory.length > 10) __cpHistory.shift();
  try { localStorage.setItem('nexus_cp_history', JSON.stringify(__cpHistory)); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  cmd.fn?.();
  closeCP();
  toast('Comando', cmd.name);
}

document.addEventListener('keydown', (e) => {
  const bg = document.getElementById('cpBg');
  const isOpen = bg?.classList.contains('open');
  const inInput = ['INPUT', 'TEXTAREA', 'SELECT'].includes(document.activeElement?.tagName || '');

  if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'k') {
    e.preventDefault(); openCP(); return;
  }
  if (e.ctrlKey && e.key === '`') {
    e.preventDefault(); toggleTele(); return;
  }
  if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'l') {
    e.preventDefault(); toggleTheme(); return;
  }

  // CP keyboard navigation
  if (isOpen) {
    const list = document.getElementById('cpList');
    const items = list?._items || [];
    if (e.key === 'ArrowDown') { e.preventDefault(); __cpActive = Math.min(__cpActive + 1, items.length - 1); renderCP(document.getElementById('cpIn')?.value || ''); return; }
    if (e.key === 'ArrowUp') { e.preventDefault(); __cpActive = Math.max(__cpActive - 1, 0); renderCP(document.getElementById('cpIn')?.value || ''); return; }
    if (e.key === 'Enter' && items[__cpActive]) { e.preventDefault(); __cpExec(items[__cpActive]); return; }
  }

  if (e.key === 'Escape') {
    closeCP();
    document.getElementById('modalBg')?.classList.remove('open');
    document.getElementById('loading')?.classList.remove('on');
    toggleTele(false);
    return;
  }
});
document.getElementById('cpBg')?.addEventListener('click', (e) => { if (e.target?.id === 'cpBg') closeCP(); });
document.getElementById('cpIn')?.addEventListener('input', (e) => { __cpActive = 0; renderCP(e.target.value); });

