// ══════════════ MISSION CONTROL ENGINE (v5) ══════════════
function animateCounter(el, target, { duration = 900, prefix = '', suffix = '', fmt = (x) => x, asTextNode = false } = {}) {
  const now = performance.now();
  const key = '__mc_anim';
  const prev = el[key] || { v: 0, t: now };
  const start = (typeof prev.v === 'number' && isFinite(prev.v)) ? prev.v : 0;
  const from = Number(start) || 0;
  const to = Number(target) || 0;
  const t0 = performance.now();

  const set = (val) => {
    const txt = `${prefix}${fmt(val)}${suffix}`;
    if (asTextNode) {
      // SVG <text> uses textContent too, but keep option explicit
      el.textContent = txt;
    } else {
      el.textContent = txt;
    }
  };

  // restart pulse if alert kpi
  if (el.classList && (el.id === 'kCrit' || el.id === 'kAtras') && to > 0) {
    el.classList.add('pulse');
  } else if (el.classList) {
    el.classList.remove('pulse');
  }

  const ease = (p) => 1 - Math.pow(1 - p, 3);
  const tick = () => {
    const p = Math.min(1, (performance.now() - t0) / duration);
    const v = from + (to - from) * ease(p);
    set(v);
    if (p < 1) requestAnimationFrame(tick);
    else el[key] = { v: to, t: performance.now() };
  };
  requestAnimationFrame(tick);
}

const MC = (function () {
  const S = {
    started: false,
    missionAt: null,
    canvas: null, ctx: null, w: 0, h: 0, dpr: 1,
    p: [],                 // particles
    intensity: 0.18, targetIntensity: 0.18,
    pipe: null, pipePaths: [], pipeParticles: [],
    tickerEl: null,
    clockEls: { clock: null, met: null },
    heatEl: null,
    lastDash: null
  };

  function init() {
    if (S.started) return;
    S.started = true;


    initPlanStatusPills();
    S.canvas = document.getElementById('bgCanvas');
    S.tickerEl = document.getElementById('tickerContent');
    S.heatEl = document.getElementById('destHeat');
    S.clockEls.clock = document.getElementById('hClock');
    S.clockEls.met = document.getElementById('hMET');

    if (S.canvas) {
      S.ctx = S.canvas.getContext('2d', { alpha: true });
      onResize();
      seedParticles();
      window.addEventListener('resize', onResize, { passive: true });
      S._rafBg = requestAnimationFrame(loopBg);
      // Pause RAF when tab is hidden to save CPU
      document.addEventListener('visibilitychange', () => {
        if (document.hidden) {
          if (S._rafBg) cancelAnimationFrame(S._rafBg);
          if (S._rafPipe) cancelAnimationFrame(S._rafPipe);
        } else {
          S._rafBg = requestAnimationFrame(loopBg);
          if (S.pipePaths && S.pipePaths.length) S._rafPipe = requestAnimationFrame(loopPipe);
        }
      });
    }

    // pipeline SVG
    S.pipe = document.getElementById('pipeSvg');
    if (S.pipe) buildPipeline();

    // clocks
    S.missionAt = performance.now();
    setInterval(updateClocks, 250);
    updateClocks();

    // keep ticker alive
    if (S.tickerEl) setTicker([{ t: 'Sistema armado — aguardando dataset', lvl: 'info' }]);
  }

  function onResize() {
    if (!S.canvas) return;
    S.dpr = Math.max(1, Math.min(2, window.devicePixelRatio || 1));
    S.w = Math.floor(window.innerWidth);
    S.h = Math.floor(window.innerHeight);
    S.canvas.width = Math.floor(S.w * S.dpr);
    S.canvas.height = Math.floor(S.h * S.dpr);
    S.canvas.style.width = S.w + 'px';
    S.canvas.style.height = S.h + 'px';
    S.ctx.setTransform(S.dpr, 0, 0, S.dpr, 0, 0);
  }

  function seedParticles() {
    const n = Math.min(140, Math.max(90, Math.floor((window.innerWidth * window.innerHeight) / 22000)));
    S.p = Array.from({ length: n }, () => ({
      x: Math.random() * window.innerWidth,
      y: Math.random() * window.innerHeight,
      vx: (Math.random() - .5) * 0.22,
      vy: (Math.random() - .5) * 0.18,
      r: 1.1 + Math.random() * 1.6
    }));
  }

  function loopBg() {
    if (!S.ctx) return;
    const ctx = S.ctx;
    ctx.clearRect(0, 0, S.w, S.h);

    // ease intensity toward target
    S.intensity += (S.targetIntensity - S.intensity) * 0.04;
    const linkDist = 120 + 160 * S.intensity;
    const drift = 0.12 + 0.24 * S.intensity;

    // particles
    for (const a of S.p) {
      a.x += a.vx * drift; a.y += a.vy * drift;
      if (a.x < -20) a.x = S.w + 20;
      if (a.x > S.w + 20) a.x = -20;
      if (a.y < -20) a.y = S.h + 20;
      if (a.y > S.h + 20) a.y = -20;
    }

    // links
    for (let i = 0; i < S.p.length; i++) {
      const A = S.p[i];
      for (let j = i + 1; j < S.p.length; j++) {
        const B = S.p[j];
        const dx = A.x - B.x, dy = A.y - B.y;
        const d = Math.hypot(dx, dy);
        if (d < linkDist) {
          const o = (1 - d / linkDist) * (0.08 + 0.16 * S.intensity);
          ctx.strokeStyle = `rgba(16,163,127,${o.toFixed(3)})`;
          ctx.beginPath(); ctx.moveTo(A.x, A.y); ctx.lineTo(B.x, B.y); ctx.stroke();
        }
      }
    }

    // nodes + subtle streams
    for (const a of S.p) {
      const o = 0.12 + 0.20 * S.intensity;
      ctx.fillStyle = `rgba(231,231,231,${o.toFixed(3)})`;
      ctx.beginPath(); ctx.arc(a.x, a.y, a.r, 0, Math.PI * 2); ctx.fill();
      // tiny falling stream
      if (Math.random() < 0.04 * S.intensity) {
        ctx.strokeStyle = `rgba(25,195,125,${(0.12 * S.intensity).toFixed(3)})`;
        ctx.beginPath(); ctx.moveTo(a.x, a.y - 6); ctx.lineTo(a.x, a.y + 18); ctx.stroke();
      }
    }

    S._rafBg = requestAnimationFrame(loopBg);
  }

  function updateClocks() {
    const d = new Date();
    const clock = d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    if (S.clockEls.clock) S.clockEls.clock.textContent = clock;

    const ms = Math.max(0, performance.now() - (S.missionAt || performance.now()));
    const h = Math.floor(ms / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    const met = `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
    if (S.clockEls.met) S.clockEls.met.textContent = met;
  }

  function buildPipeline() {
    const svg = S.pipe;
    if (!svg) return;
    svg.innerHTML = '';
    S.pipePaths = [];
    S.pipeParticles = [];

    const NS = 'http://www.w3.org/2000/svg';

    const nodes = [
      { k: 'NO PATIO', x: 110, y: 92, c: '#94a3b8' },
      { k: 'DESCARGA', x: 330, y: 92, c: '#f0b429' },
      { k: 'DISPONIVEL', x: 550, y: 92, c: '#10a37f' },
      { k: 'PLANEJADO', x: 770, y: 92, c: '#19c37d' }
    ];

    // paths (curved)
    const mkPath = (x1, y1, x2, y2) => {
      const p = document.createElementNS(NS, 'path');
      const mx = (x1 + x2) / 2;
      p.setAttribute('d', `M ${x1} ${y1} C ${mx} ${y1 - 34}, ${mx} ${y2 + 34}, ${x2} ${y2}`);
      return p;
    };

    for (let i = 0; i < nodes.length - 1; i++) {
      const bg = mkPath(nodes[i].x + 44, nodes[i].y, nodes[i + 1].x - 44, nodes[i + 1].y);
      bg.classList.add('pipe-path-bg');
      svg.appendChild(bg);

      const fg = mkPath(nodes[i].x + 44, nodes[i].y, nodes[i + 1].x - 44, nodes[i + 1].y);
      fg.classList.add('pipe-path');
      fg.setAttribute('stroke', 'rgba(16,163,127,.22)');
      fg.setAttribute('data-i', String(i));
      svg.appendChild(fg);

      S.pipePaths.push(fg);
    }

    // nodes
    nodes.forEach(n => {
      const g = document.createElementNS(NS, 'g');
      const box = document.createElementNS(NS, 'rect');
      box.setAttribute('x', n.x - 58); box.setAttribute('y', n.y - 30);
      box.setAttribute('width', 116); box.setAttribute('height', 64);
      box.setAttribute('rx', '16'); box.classList.add('pipe-node');
      g.appendChild(box);

      const lab = document.createElementNS(NS, 'text');
      lab.setAttribute('x', n.x); lab.setAttribute('y', n.y - 8);
      lab.setAttribute('text-anchor', 'middle'); lab.classList.add('pipe-label');
      lab.textContent = n.k.replace('NO PATIO', 'NO PÁTIO').replace('DISPONIVEL', 'DISPONÍVEL');
      g.appendChild(lab);

      const count = document.createElementNS(NS, 'text');
      count.setAttribute('x', n.x); count.setAttribute('y', n.y + 18);
      count.setAttribute('text-anchor', 'middle'); count.classList.add('pipe-count');
      count.setAttribute('id', 'pipe_' + n.k.replace(' ', '_'));
      count.textContent = '—';
      g.appendChild(count);

      // halo dot
      const dot = document.createElementNS(NS, 'circle');
      dot.setAttribute('cx', n.x - 46); dot.setAttribute('cy', n.y - 18);
      dot.setAttribute('r', '5');
      dot.setAttribute('fill', n.c);
      dot.setAttribute('opacity', '0.85');
      g.appendChild(dot);

      svg.appendChild(g);
    });

    // particles per segment
    for (let i = 0; i < S.pipePaths.length; i++) {
      for (let j = 0; j < 12; j++) {
        const c = document.createElementNS(NS, 'circle');
        c.setAttribute('r', (1.6 + Math.random() * 1.6).toFixed(2));
        c.setAttribute('fill', 'rgba(231,231,231,.95)');
        c.classList.add('pipe-particle');
        svg.appendChild(c);
        S.pipeParticles.push({ el: c, seg: i, t: Math.random(), v: 0.0025 + Math.random() * 0.002 });
      }
    }

    S._rafPipe = requestAnimationFrame(loopPipe);
  }

  function loopPipe() {
    if (!S.pipe || !S.pipePaths.length) return;
    const boost = 0.6 + 1.2 * S.intensity;
    for (const p of S.pipeParticles) {
      const path = S.pipePaths[p.seg];
      if (!path) continue;
      const len = path.getTotalLength();
      p.t = (p.t + p.v * boost) % 1;
      const pt = path.getPointAtLength(p.t * len);
      p.el.setAttribute('cx', pt.x);
      p.el.setAttribute('cy', pt.y + Math.sin((p.t * 6.28) + (p.seg * 1.3)) * 2.2);
      p.el.setAttribute('opacity', (0.35 + 0.55 * Math.sin(p.t * 3.14)).toFixed(2));
    }
    S._rafPipe = requestAnimationFrame(loopPipe);
  }

  function setTicker(items) {
    if (!S.tickerEl) return;
    const list = (items || []).slice(0, 14);
    const parts = list.length ? list.map(a => `<span>${a.icon || ''}${a.t}</span>`).join('') :
      `<span>✅ Nenhum alerta crítico no momento</span>`;
    // duplicate for seamless loop
    S.tickerEl.innerHTML = parts + parts;
  }

  function setHeatmap(topDest) {
    if (!S.heatEl) return;
    const items = (topDest || []).slice(0, 12).map(([d, a]) => ({ d, p: a.p, c: a.c }));
    const max = Math.max(...items.map(x => x.p), 1);
    S.heatEl.innerHTML = items.map(it => {
      const k = Math.max(0.08, Math.min(0.92, it.p / max));
      const bg = `rgba(16,163,127,${(0.10 + 0.38 * k).toFixed(3)})`;
      const br = `rgba(16,163,127,${(0.12 + 0.22 * k).toFixed(3)})`;
      return `<div class="cell" style="background:${bg};border-color:${br}">
        <div class="d">${it.d}</div>
        <div class="v">${fN2(it.p / 1000)} t · ${it.c} CTs</div>
      </div>`;
    }).join('') || `<div style="grid-column:1/-1;color:var(--muted);font-size:11px;padding:10px 0;text-align:center">Sem destinos suficientes para heatmap</div>`;
  }

  function animateGauges() {
    const root = document.getElementById('gauges');
    if (!root) return;
    root.querySelectorAll('circle.gProg').forEach(c => {
      const dash = parseFloat(c.getAttribute('data-dash') || '0');
      const circ = parseFloat(c.getAttribute('data-circ') || '1');
      const t0 = performance.now();
      const dur = 900;
      const ease = (p) => 1 - Math.pow(1 - p, 3);
      const tick = () => {
        const p = Math.min(1, (performance.now() - t0) / dur);
        const v = dash * ease(p);
        c.setAttribute('stroke-dasharray', `${v.toFixed(2)} ${circ.toFixed(2)}`);
        if (p < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    });
  }

  function updateFromDashboard({ total, disp, desc, planej, patio, atras, forced, topDest }) {
    // reactive intensity: more alerts => denser network + faster pipeline
    const critCount = (forced || []).filter(x => x.is_critico).length;
    const atrCount = (atras || []).length;
    const base = 0.14;
    const heat = Math.min(1, (critCount * 2 + atrCount * 0.7) / Math.max(1, total));
    S.targetIntensity = base + 0.72 * heat;

    // pulse system state
    if (critCount > 0 || atrCount > 0) document.body.classList.add('alert');
    else document.body.classList.remove('alert');

    // pipeline counts
    const set = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
    set('pipe_DESCARGA', fN(desc?.length || 0));
    set('pipe_NO_PATIO', fN(patio?.length || 0));
    set('pipe_DISPONIVEL', fN(disp?.length || 0));
    set('pipe_PLANEJADO', fN(planej?.length || 0));

    // ticker
    const items = (forced || []).slice(0, 12).map(r => {
      const isCrit = !!r.is_critico;
      const icon = isCrit ? '⚡ ' : '📅 ';
      const pr = r.prazo ? ` · ${r.prazo}` : '';
      const od = `${r.origem || '—'}→${r.destino || '—'}`;
      const ctrc = (r.ctrc || r.cod || '—');
      return { t: `${icon}${ctrc} · ${od}${pr} · ${fN2(r.p_oper || 0)}kg`, icon: '' };
    });
    setTicker(items);

    // heatmap
    setHeatmap(topDest);

    // gauges animation restart (because innerHTML changed)
    animateGauges();
  }

  return { init, updateFromDashboard, animateGauges };
})();

