// Robust numeric parsing (pt-BR + dados “mistos”)
// - Corrige casos como "2.198" (milhar) -> 2198
(function () {
  const _oldToNum = (typeof toNum === 'function') ? toNum : null;
  window.toNum = function (v) {
    if (v === null || v === undefined) return 0;
    if (typeof v === 'number') return isFinite(v) ? v : 0;
    let s = String(v)?.trim();
    if (!s) return 0;
    s = s.replace(/[^0-9,.\-]/g, '');
    const hasComma = s.includes(','), hasDot = s.includes('.');
    if (hasComma && hasDot) {
      // "." milhar, "," decimal
      s = s.replace(/\./g, '').replace(',', '.');
    } else if (hasComma && !hasDot) {
      // "," decimal
      s = s.replace(',', '.');
    } else if (hasDot && !hasComma) {
      // Heurística pt-BR: se for padrão de milhar "1.234" ou "12.345.678"
      const thousandPattern = /^\-?\d{1,3}(\.\d{3})+$/;
      if (thousandPattern.test(s)) {
        s = s.replace(/\./g, '');
      }
    }
    const n = parseFloat(s);
    return isFinite(n) ? n : 0;
  };
})();

// Toast governance: de-dup por título + limite de toasts
(function () {
  const _oldToast = (typeof toast === 'function') ? toast : null;
  window.toast = function (title, msg, kind = 'ok') {
    const root = document.getElementById('toasts');
    if (!root) { if (_oldToast) return _oldToast(title, msg, kind); return; }

    const key = `${kind}::${String(title || '').slice(0, 32)}`;
    // Atualiza toast existente (evita empilhar "Tema" etc.)
    const existing = [...root.querySelectorAll('.toast')].find(t => t.dataset && t.dataset.key === key);
    if (existing) {
      try {
        existing.querySelector('.t').textContent = title || '';
        existing.querySelector('.s').textContent = msg || '';
        existing.classList.remove('bump'); void existing.offsetWidth; existing.classList.add('bump');
      } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
      // renova auto-dismiss
      try { clearTimeout(existing._t); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
      existing._t = setTimeout(() => { try { existing.remove(); } catch (e) { } }, 4200);
      return;
    }

    // limite (Apple-like: sem spam visual)
    while (root.children.length >= 2) {
      try { root.removeChild(root.firstElementChild); } catch (e) { break; }
    }

    const el = document.createElement('div');
    el.className = 'toast';
    el.dataset.key = key;
    const icon = kind === 'warn' ? '⚠' : kind === 'err' ? '⨯' : '✓';
    el.innerHTML = `
      <div class="ic">${icon}</div>
      <div class="tx"><div class="t">${title || ''}</div><div class="s">${sanitizeHTML(msg || '')}</div></div>
      <button class="x" aria-label="Fechar">FECHAR</button>
    `;
    el.querySelector('.x').onclick = () => el.remove();
    root.appendChild(el);
    el._t = setTimeout(() => { try { el.remove(); } catch (e) { } }, 4200);
  };
})();

