// Integridade do dataset (auditável + visível em Telemetria)
window.__integrity = window.__integrity || { ok: true, summary: '—', issues: [] };

function integrityCheck(db) {
  const issues = [];
  const req = ['ctrc', 'estoque', 'destino', 'status', 'tipo_op', 'dt_prev'];
  const numFields = ['p_oper', 'vl_nf', 'qtd_vol'];

  const total = Array.isArray(db) ? db.length : 0;
  if (!total) {
    window.__integrity = { ok: false, summary: 'Dataset vazio', issues: ['Dataset vazio'] };
    return window.__integrity;
  }

  // missing required
  const miss = {};
  for (const k of req) miss[k] = 0;

  let badDate = 0, nonZeroBad = 0;
  for (const r of db) {
    for (const k of req) {
      const v = r?.[k];
      if (v === null || v === undefined || String(v)?.trim() === '') miss[k]++;
    }
    // dt_prev parseable?
    const d = r?.dt_prev;
    if (d && !parseDateSafe(d)) badDate++;
    // num parse sanity
    for (const k of numFields) {
      const raw = r?.[k];
      if (raw !== '' && raw !== null && raw !== undefined) {
        const n = toNum(raw);
        if (!isFinite(n)) nonZeroBad++;
      }
    }
  }

  for (const [k, v] of Object.entries(miss)) {
    if (v > 0) {
      const pct = ((v / total) * 100).toFixed(1);
      issues.push(`${k.toUpperCase()}: ${v} faltando (${pct}%)`);
    }
  }
  if (badDate > 0) issues.push(`DT_PREV: ${badDate} inválidas`);
  if (nonZeroBad > 0) issues.push(`NUMÉRICOS: ${nonZeroBad} inválidos`);

  const ok = issues.length === 0;
  const summary = ok ? `OK · ${total.toLocaleString('pt-BR')} registros` : `Atenção · ${issues.length} apontamentos`;
  window.__integrity = { ok, summary, issues, total };

  // Telemetria
  const el = document.getElementById('teleIntegrity');
  if (el) el.textContent = summary;

  // Feedback (sem spam)
  toast('Integridade', summary, ok ? 'ok' : 'warn');
  if (!ok) {
    // coloca warning count
    try {
      __tele.warnings = issues.length;
      const w = document.getElementById('teleWarn');
      if (w) w.textContent = `${issues.length} · ver detalhes`;
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  }
  return window.__integrity;
}

// Date parsing helper (não quebra com formatos comuns)
function parseDateSafe(v) {
  if (!v) return null;
  if (v instanceof Date && !isNaN(v)) return v;
  const s = String(v)?.trim();
  // dd/mm/yyyy
  const m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/);
  if (m) {
    const dd = parseInt(m[1], 10), mm = parseInt(m[2], 10), yy = parseInt(m[3], 10);
    const yyyy = yy < 100 ? 2000 + yy : yy;
    const d = new Date(yyyy, mm - 1, dd);
    return isNaN(d) ? null : d;
  }
  const d2 = new Date(s);
  return isNaN(d2) ? null : d2;
}

