/* ──────────────────────────────────────────────────────
   IndexedDB (cache dataset + fila offline)
   ────────────────────────────────────────────────────── */
const __IDB = (function () {
  const DB_NAME = 'nexus_hub_pwa';
  const STORE = 'kv';
  let _db = null;

  function open() {
    if (_db) return Promise.resolve(_db);
    return new Promise((resolve, reject) => {
      if (!('indexedDB' in window)) return reject(new Error('IndexedDB indisponível'));
      const req = indexedDB.open(DB_NAME, 1);
      req.onupgradeneeded = () => {
        const db = req.result;
        if (!db.objectStoreNames.contains(STORE)) db.createObjectStore(STORE);
      };
      req.onsuccess = () => { _db = req.result; resolve(_db); };
      req.onerror = () => reject(req.error || new Error('Falha ao abrir IndexedDB'));
    });
  }

  async function get(key) {
    const db = await open();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE, 'readonly');
      const st = tx.objectStore(STORE);
      const rq = st.get(key);
      rq.onsuccess = () => resolve(rq.result);
      rq.onerror = () => reject(rq.error);
    });
  }

  async function set(key, val) {
    const db = await open();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORE, 'readwrite');
      const st = tx.objectStore(STORE);
      const rq = st.put(val, key);
      rq.onsuccess = () => resolve(true);
      rq.onerror = () => reject(rq.error);
    });
  }

  return { open, get, set };
})();

let PENDING_OPS = [];
let LAST_SYNC_TS = null;

// ─────────────────────────────────────────────────────────────
// Sync helpers: opId + ack (idempotência sem quebrar fluxo antigo)
// ─────────────────────────────────────────────────────────────
const NX_DEVICE_KEY = 'NX_DEVICE_ID';
const NX_OPSEQ_KEY = 'NX_OPSEQ';

function getDeviceId() {
  try {
    let id = localStorage.getItem(NX_DEVICE_KEY);
    if (!id) {
      id = 'dev_' + Math.random().toString(16).slice(2) + '_' + Date.now().toString(16);
      localStorage.setItem(NX_DEVICE_KEY, id);
    }
    return id;
  } catch (e) {
    return 'dev_' + Math.random().toString(16).slice(2);
  }
}

function nextOpId() {
  const dev = getDeviceId();
  let seq = 0;
  try { seq = parseInt(localStorage.getItem(NX_OPSEQ_KEY) || '0', 10) || 0; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  seq++;
  try { localStorage.setItem(NX_OPSEQ_KEY, String(seq)); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  return `${dev}:${Date.now().toString(36)}:${seq.toString(36)}`;
}

function ensureOpMeta(op) {
  if (!op || typeof op !== 'object') return op;
  if (!op.opId) op.opId = nextOpId();
  if (!op.ts) op.ts = Date.now();
  if (!op.deviceId) op.deviceId = getDeviceId();
  return op;
}

async function loadPendingOps() {
  try {
    const ops = await __IDB.get('pending_ops');
    if (Array.isArray(ops)) PENDING_OPS = ops;

    // Backfill: versões antigas não tinham opId
    let changed = false;
    if (Array.isArray(PENDING_OPS)) {
      PENDING_OPS.forEach(op => {
        if (op && typeof op === 'object' && !op.opId) {
          ensureOpMeta(op);
          changed = true;
        }
      });
    }

    const ls = await __IDB.get('last_sync');
    LAST_SYNC_TS = (typeof ls === 'number') ? ls : null;

    if (changed) await __IDB.set('pending_ops', PENDING_OPS);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  updateNetBadge();
}

async function savePendingOps() {
  try {
    await __IDB.set('pending_ops', PENDING_OPS);
    await __IDB.set('last_sync', LAST_SYNC_TS);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  updateNetBadge();
}

function queueOp(op) {
  try {
    ensureOpMeta(op);
    PENDING_OPS.push(op);
    savePendingOps();
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

async function persistDB() {
  try {
    if (!Array.isArray(window.DB) || !window.DB.length) return;
    const payload = { ts: Date.now(), filial: window.FILIAL || '', rows: window.DB };
    await __IDB.set('last_db', payload);
    await __IDB.set('last_filial', window.FILIAL || '');
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

async function peekLastDB() {
  try { return await __IDB.get('last_db'); } catch (e) { return null; }
}

window.exportPendingOps = function () {
  try {
    const blob = new Blob([JSON.stringify(PENDING_OPS, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `nexus_ops_${new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-')}.json`;
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 250);
    toast('Exportado', 'Pendências baixadas em JSON.');
  } catch (e) {
    toast('Falha', 'Não foi possível exportar as pendências.', 'warn');
  }
};

window.clearPendingOps = async function () {
  PENDING_OPS = [];
  LAST_SYNC_TS = null;
  await savePendingOps();
  toast('Fila limpa', 'Pendências removidas do dispositivo.');
};

window.flushPendingOps = async function (userInitiated = false) {
  const cfg = window.APP_CFG || {};
  const url = String(cfg.syncEndpoint || '')?.trim();

  if (!PENDING_OPS.length) {
    if (userInitiated) toast('Sem pendências', 'Nada para sincronizar.');
    updateNetBadge();
    return;
  }
  if (!navigator.onLine) {
    if (userInitiated) toast('Offline', 'Sem conexão para sincronizar.', 'warn');
    updateNetBadge();
    return;
  }
  if (!url) {
    if (userInitiated) toast('Endpoint vazio', 'Defina o endpoint no modal de Configurações.', 'warn');
    updateNetBadge();
    return;
  }

  try {
    // Garantir opId nas pendências (compatível com fila antiga)
    let changed = false;
    PENDING_OPS.forEach(op => {
      if (op && typeof op === 'object' && !op.opId) {
        ensureOpMeta(op);
        changed = true;
      }
    });
    if (changed) await savePendingOps();

    const payload = {
      app: 'NEXUS HUB',
      version: 'v5.2',
      filial: window.FILIAL || '',
      ts: Date.now(),
      client: {
        deviceId: getDeviceId(),
        tz: (Intl?.DateTimeFormat?.().resolvedOptions?.().timeZone) || '',
        ua: navigator.userAgent || ''
      },
      ops: PENDING_OPS
    };

    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);

    // ACK opcional: se o endpoint devolver JSON com {ack:[opId,...]}
    let ack = null;
    try {
      const ct = res.headers.get('content-type') || '';
      if (ct.includes('application/json')) {
        const j = await res.json();
        ack = j?.ack || j?.acked || j?.opIds || j?.op_ids || null;
      } else {
        // endpoint antigo pode responder texto simples "OK"
        const t = await res.text();
        try {
          const j = JSON.parse(t);
          ack = j?.ack || j?.acked || j?.opIds || j?.op_ids || null;
        } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
      }
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

    if (Array.isArray(ack) && ack.length) {
      const set = new Set(ack.map(String));
      PENDING_OPS = PENDING_OPS.filter(op => !set.has(String(op?.opId || '')));
      LAST_SYNC_TS = Date.now();
      await savePendingOps();
      const rest = PENDING_OPS.length;
      toast('Sincronizado', rest ? `ACK parcial · ${rest} pendência(s) ainda na fila.` : 'Pendências enviadas com sucesso.', 'success');
    } else {
      // Fluxo antigo (sem ACK): mantém comportamento de limpar fila quando HTTP OK
      PENDING_OPS = [];
      LAST_SYNC_TS = Date.now();
      await savePendingOps();
      toast('Sincronizado', 'Pendências enviadas com sucesso.', 'success');
    }
  } catch (err) {
    if (userInitiated) toast('Falha na sync', String(err?.message || err), 'warn');
  }
  updateNetBadge();
};

async function maybeEnableRestoreButton() {
  try {
    const payload = await peekLastDB();
    const btn = document.getElementById('btnRestore');
    if (!btn) return;
    if (payload && Array.isArray(payload.rows) && payload.rows.length) {
      btn.style.display = 'block';
      const dt = new Date(payload.ts || Date.now());
      btn.title = `Último dataset salvo em ${dt.toLocaleString()}`;
    } else {
      btn.style.display = 'none';
    }
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

window.restoreLastDataset = async function () {
  try {
    const payload = await peekLastDB();
    if (!payload || !Array.isArray(payload.rows) || !payload.rows.length) {
      toast('Sem cache', 'Nenhum dataset salvo localmente.');
      return;
    }

    // Restore
    window.DB = payload.rows;
    window.FILIAL = payload.filial || (await __IDB.get('last_filial')) || window.FILIAL || '';

    // Garantir UID
    try {
      window.DB.forEach((r, i) => { if (r && (r._uid === undefined || r._uid === null)) r._uid = i + 1; });
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

    // Aplicar recompute se existir (mantém lógica)
    try {
      if (typeof recomputeWithFilial === 'function') window.DB = recomputeWithFilial(window.DB, window.FILIAL);
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

    // Lançar app (sem precisar importar)
    try {
      document.getElementById('importScreen').style.display = 'none';
      document.getElementById('app').classList.add('visible');
    } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

    try { populateSelects(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try { updateHeader(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try { updateNavBadges(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try { renderDashboard(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try { renderEtapa(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    try { renderEst(); renderDesc(); renderPat(); renderAtras(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

    toast('Dataset restaurado', 'Carregado do cache local (modo offline).', 'success');
  } catch (e) {
    toast('Falha ao restaurar', 'Não foi possível carregar o cache local.', 'warn');
  }
};

/* ──────────────────────────────────────────────────────
   Configurações (modal)
   ────────────────────────────────────────────────────── */
function sysTheme() {
  try {
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark';
  } catch (e) { return 'dark'; }
}

function applyThemeMode(mode) {
  const cfg = window.APP_CFG || {};
  cfg.themeMode = mode || cfg.themeMode || 'dark';
  window.APP_CFG = cfg;
  saveAppCfg();

  const t = (cfg.themeMode === 'auto') ? sysTheme() : cfg.themeMode;
  try {
    if (typeof applyTheme === 'function') applyTheme(t);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function applyDensity(mode) {
  const cfg = window.APP_CFG || {};
  cfg.density = mode || cfg.density || 'compact';
  window.APP_CFG = cfg;
  saveAppCfg();
  try { document.documentElement.setAttribute('data-density', cfg.density); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function computeAutoScale() {
  const cfg = window.APP_CFG || {};
  const preset = cfg.scalePreset || 'exec1080';

  const w = window.innerWidth || 1200;
  const h = window.innerHeight || 800;

  // Padrão: sem ajuste
  if (preset === 'standard') return 1.00;

  // TV / Apresentação: um pouco maior para leitura à distância
  if (preset === 'tv') {
    if (w <= 720) return 1.00;
    if (w <= 1024) return 1.05;
    if (w <= 1366) return 1.08;
    if (w <= 1920) return 1.12;
    if (w <= 2560) return 1.18;
    return 1.22;
  }

  // Executivo 1080p: mais conteúdo na tela (equivalente a zoom-out em 4K)
  // Evita encolher em mobile/tablet: responsabilidade fica com o layout responsivo.
  if (w < 1100) return 1.00;

  const dpr = window.devicePixelRatio || 1;
  const effW = w * dpr;
  const effH = h * dpr;

  const baseW = 1920;
  const baseH = 1080;

  const s = Math.min(baseW / effW, baseH / effH, 1);
  return s;
}

function applyScale(scale, persist = true) {
  const cfg = window.APP_CFG || {};
  const s = Math.max(0.50, Math.min(1.40, Number(scale) || 1));
  try { document.documentElement.style.setProperty('--ui-scale', s.toFixed(2)); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  cfg.uiScale = s;
  window.APP_CFG = cfg;
  if (persist) saveAppCfg();
  try {
    const v = document.getElementById('setScaleVal');
    if (v) v.textContent = s.toFixed(2) + '×';
    const r = document.getElementById('setScale');
    if (r && document.activeElement !== r) r.value = s.toFixed(2);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function applyAutoScaleIfNeeded() {
  const cfg = window.APP_CFG || {};
  if (cfg.autoScale) {
    applyScale(computeAutoScale(), false);
  } else {
    applyScale(cfg.uiScale || 1, false);
  }
}

function applyFx(on) {
  const cfg = window.APP_CFG || {};
  cfg.fx = !!on;
  window.APP_CFG = cfg;
  saveAppCfg();
  try { document.body.classList.toggle('no-fx', !cfg.fx); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function applyTicker(on) {
  const cfg = window.APP_CFG || {};
  cfg.ticker = !!on;
  window.APP_CFG = cfg;
  saveAppCfg();
  try {
    const el = document.getElementById('alertTicker');
    if (el) el.style.display = cfg.ticker ? '' : 'none';
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
}

function applyCfgToUI() {
  const cfg = window.APP_CFG || {};
  applyDensity(cfg.density);
  applyFx(cfg.fx);
  applyTicker(cfg.ticker);
  applyThemeMode(cfg.themeMode);
  try { applyAccentTheme(cfg.accentTheme || (localStorage.getItem('nexus_accent') || 'industrial'), false); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  applyAutoScaleIfNeeded();
}

window.openSettings = function () {
  const bg = document.getElementById('settingsBg');
  if (!bg) return;
  bg.classList.add('open');
  bg.setAttribute('aria-hidden', 'false');

  const cfg = window.APP_CFG || {};

  // hydrate inputs
  try { document.getElementById('setTheme').value = cfg.themeMode || 'dark'; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setAccent').value = cfg.accentTheme || (localStorage.getItem('nexus_accent') || 'industrial'); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setDensity').value = cfg.density || 'compact'; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setScale').value = (cfg.uiScale || 1).toFixed(2); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setScaleVal').textContent = (cfg.uiScale || 1).toFixed(2) + '×'; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setAutoScale').value = cfg.autoScale ? 'on' : 'off'; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setScalePreset').value = cfg.scalePreset || 'exec1080'; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setFx').checked = !!cfg.fx; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setTicker').checked = !!cfg.ticker; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  try { document.getElementById('setWarnMult').value = Number(cfg.slaWarnMult || 1.2); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setCritMult').value = Number(cfg.slaCritMult || 1.6); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setPatioWarnDays').value = Number(cfg.patioWarnDays ?? 0); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setOtCost').value = Number(cfg.otCost || 0); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setCrew').value = Number(cfg.crew || 4); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setEmail').value = String(cfg.emailTo || ''); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setEndpoint').value = String(cfg.syncEndpoint || ''); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  try { document.getElementById('setPendCount').textContent = String(PENDING_OPS.length || 0); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  try { document.getElementById('setLastSync').textContent = LAST_SYNC_TS ? new Date(LAST_SYNC_TS).toLocaleString() : '—'; } catch (e) { if (window.__DEV) console.warn("[NX]", e); }

  // focus
  try {
    setTimeout(() => document.getElementById('setTheme')?.focus(), 50);
  } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
};

window.closeSettings = function () {
  const bg = document.getElementById('settingsBg');
  if (!bg) return;
  bg.classList.remove('open');
  bg.setAttribute('aria-hidden', 'true');
  toast('Configurações', 'Preferências salvas no dispositivo.');
};

(function bindSettingsUI() {
  function on(id, ev, fn) {
    const el = document.getElementById(id);
    if (!el) return;
    el.addEventListener(ev, fn);
  }

  on('setTheme', 'change', (e) => { applyThemeMode(e.target.value); });
  on('setAccent', 'change', (e) => { applyAccentTheme(e.target.value); });
  on('setDensity', 'change', (e) => { applyDensity(e.target.value); });
  on('setScale', 'input', (e) => {
    const cfg = window.APP_CFG || {};
    cfg.uiScale = Number(e.target.value) || 1;
    window.APP_CFG = cfg; saveAppCfg();
    applyScale(cfg.uiScale, false);
  });
  on('setAutoScale', 'change', (e) => {
    const cfg = window.APP_CFG || {};
    cfg.autoScale = (e.target.value === 'on');
    window.APP_CFG = cfg; saveAppCfg();
    applyAutoScaleIfNeeded();
  });
  on('setScalePreset', 'change', (e) => {
    const cfg = window.APP_CFG || {};
    cfg.scalePreset = String(e.target.value || 'exec1080');
    window.APP_CFG = cfg; saveAppCfg();
    applyAutoScaleIfNeeded();
  });

  on('setFx', 'change', (e) => { applyFx(e.target.checked); });
  on('setTicker', 'change', (e) => { applyTicker(e.target.checked); });

  on('setWarnMult', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.slaWarnMult = Number(e.target.value) || 1.2; window.APP_CFG = cfg; saveAppCfg(); refreshAllSafe(); });
  on('setCritMult', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.slaCritMult = Number(e.target.value) || 1.6; window.APP_CFG = cfg; saveAppCfg(); refreshAllSafe(); });
  on('setPatioWarnDays', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.patioWarnDays = Number(e.target.value) || 0; window.APP_CFG = cfg; saveAppCfg(); refreshAllSafe(); });
  on('setOtCost', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.otCost = Number(e.target.value) || 0; window.APP_CFG = cfg; saveAppCfg(); refreshAllSafe(); });
  on('setCrew', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.crew = Math.max(1, Number(e.target.value) || 4); window.APP_CFG = cfg; saveAppCfg(); refreshAllSafe(); });
  on('setEmail', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.emailTo = String(e.target.value || '')?.trim(); window.APP_CFG = cfg; saveAppCfg(); });
  on('setEndpoint', 'change', (e) => { const cfg = window.APP_CFG || {}; cfg.syncEndpoint = String(e.target.value || '')?.trim(); window.APP_CFG = cfg; saveAppCfg(); });

  // click outside to close
  const bg = document.getElementById('settingsBg');
  if (bg) {
    bg.addEventListener('click', (e) => { if (e.target === bg) closeSettings(); });
  }
})();

/* ──────────────────────────────────────────────────────
   SLA Preditivo (histórico local)
   ────────────────────────────────────────────────────── */
function parseDateTimeSafe(s) {
  if (!s) return null;
  const str = String(s)?.trim();
  if (!str || str === 'None') return null;

  // dd/mm/yyyy hh:mm(:ss)
  let m = str.match(/(\d{1,2})\/(\d{1,2})\/(\d{2,4})(?:\s+(\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
  if (m) {
    const dd = parseInt(m[1], 10), mm = parseInt(m[2], 10) - 1, yy = parseInt(m[3], 10);
    const hh = parseInt(m[4] || '0', 10), mi = parseInt(m[5] || '0', 10), ss = parseInt(m[6] || '0', 10);
    const y = (yy < 100) ? (2000 + yy) : yy;
    const d = new Date(y, mm, dd, hh, mi, ss);
    return isNaN(d.getTime()) ? null : d;
  }

  // yyyy-mm-dd hh:mm
  m = str.match(/(\d{4})-(\d{1,2})-(\d{1,2})(?:[ T](\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
  if (m) {
    const y = parseInt(m[1], 10), mm = parseInt(m[2], 10) - 1, dd = parseInt(m[3], 10);
    const hh = parseInt(m[4] || '0', 10), mi = parseInt(m[5] || '0', 10), ss = parseInt(m[6] || '0', 10);
    const d = new Date(y, mm, dd, hh, mi, ss);
    return isNaN(d.getTime()) ? null : d;
  }

  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

function fmtDurMin(min) {
  const m = Math.max(0, Number(min) || 0);
  const h = Math.floor(m / 60);
  const mm = Math.round(m % 60);
  if (h <= 0) return `${mm}m`;
  return `${h}h${String(mm).padStart(2, '0')}`;
}

let SLA_MODEL = { byFilial: {}, globalAvgMin: 0, globalP50Min: 0, globalP90Min: 0, sample: 0 };

function buildSlaHistory(rows) {
  const byFil = {};
  let gSum = 0, gCnt = 0;
  const gArr = [];

  const pct = (arr, p) => {
    if (!arr.length) return 0;
    const idx = (arr.length - 1) * p;
    const lo = Math.floor(idx), hi = Math.ceil(idx);
    if (lo === hi) return arr[lo];
    return arr[lo] + (arr[hi] - arr[lo]) * (idx - lo);
  };

  (rows || []).forEach(r => {
    const ini = parseDateTimeSafe(r?.ini_desc);
    const fim = parseDateTimeSafe(r?.fim_desc);
    if (!ini || !fim) return;
    const dur = (fim.getTime() - ini.getTime()) / 60000;
    if (!(dur > 0 && isFinite(dur))) return;

    const filial = (r.estoque && r.estoque !== 'None') ? r.estoque : (window.FILIAL || '—');
    if (!byFil[filial]) byFil[filial] = { sum: 0, cnt: 0, arr: [], avgMin: 0, p50Min: 0, p90Min: 0 };
    byFil[filial].sum += dur;
    byFil[filial].cnt += 1;
    byFil[filial].arr.push(dur);

    gSum += dur; gCnt += 1;
    gArr.push(dur);
  });

  Object.values(byFil).forEach(o => {
    o.avgMin = o.cnt ? (o.sum / o.cnt) : 0;
    o.arr.sort((a, b) => a - b);
    o.p50Min = pct(o.arr, 0.50);
    o.p90Min = pct(o.arr, 0.90);
    delete o.arr;
  });

  gArr.sort((a, b) => a - b);
  const gAvg = gCnt ? (gSum / gCnt) : 0;
  const gP50 = pct(gArr, 0.50);
  const gP90 = pct(gArr, 0.90);

  return { byFilial: byFil, globalAvgMin: gAvg, globalP50Min: gP50, globalP90Min: gP90, sample: gCnt };
}
function rebuildSlaModel() {
  try { SLA_MODEL = buildSlaHistory(window.DB || []); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
  return SLA_MODEL;
}

function estimateRiskCost(risk) {
  const cfg = window.APP_CFG || {};
  const costHr = Number(cfg.otCost || 0);
  const crew = Math.max(1, Number(cfg.crew || 1));
  if (!(costHr > 0)) return 0;

  let extraH = 0;
  if (risk && isFinite(risk.elapsedMin) && isFinite(risk.expectedMin)) {
    extraH = Math.max(0, (risk.elapsedMin - risk.expectedMin) / 60);
  } else if (risk && isFinite(risk.dias) && risk.dias < 0) {
    extraH = Math.abs(risk.dias) * 24;
  }
  return extraH * costHr * crew;
}

function slaRiskForRow(r) {
  if (!r) return null;
  const cfg = window.APP_CFG || {};
  const status = r.status_manual || r.status;

  // DESCARGA: comparar tempo decorrido vs histórico
  if (status === 'DESCARGA') {
    const ini = parseDateTimeSafe(r.ini_desc);
    if (!ini) return null;

    const now = Date.now();
    const elapsedMin = (now - ini.getTime()) / 60000;
    if (!(elapsedMin >= 0)) return null;

    const filial = (r.estoque && r.estoque !== 'None') ? r.estoque : (window.FILIAL || '—');
    const stats = SLA_MODEL.byFilial?.[filial] || {};
    const expectedMin = stats.p50Min || stats.avgMin || SLA_MODEL.globalP50Min || SLA_MODEL.globalAvgMin || 120;
    const p90Min = stats.p90Min || SLA_MODEL.globalP90Min || (expectedMin * 1.4);

    const warnM = Math.max(1.0, Number(cfg.slaWarnMult || 1.2));
    const critM = Math.max(warnM, Number(cfg.slaCritMult || 1.6));

    const warnAt = Math.max(p90Min, expectedMin * warnM);
    const critAt = Math.max(p90Min * critM, expectedMin * critM);

    if (elapsedMin >= critAt) {
      const risk = { level: 'crit', elapsedMin, expectedMin, p90Min, msg: `Descarga acima do histórico: ${fmtDurMin(elapsedMin)} (ref ${fmtDurMin(expectedMin)} · p90 ${fmtDurMin(p90Min)})` };
      risk.cost = estimateRiskCost(risk);
      return risk;
    }
    if (elapsedMin >= warnAt) {
      const risk = { level: 'warn', elapsedMin, expectedMin, p90Min, msg: `Descarga em risco: ${fmtDurMin(elapsedMin)} (ref ${fmtDurMin(expectedMin)} · p90 ${fmtDurMin(p90Min)})` };
      risk.cost = estimateRiskCost(risk);
      return risk;
    }
  }

  // NO PÁTIO: usar Dias/prazo
  if (status === 'NO PATIO') {
    const dias = Number(r.dias);
    const warnDays = Number(cfg.patioWarnDays ?? 0);

    if (isFinite(dias)) {
      if (dias < 0) {
        const risk = { level: 'crit', dias, msg: `NO PÁTIO com prazo vencido (${dias} dia${Math.abs(dias) === 1 ? '' : 's'})` };
        risk.cost = estimateRiskCost(risk);
        return risk;
      }
      if (dias <= warnDays) {
        const risk = { level: 'warn', dias, msg: `NO PÁTIO próximo do prazo (${dias} dia${Math.abs(dias) === 1 ? '' : 's'})` };
        risk.cost = estimateRiskCost(risk);
        return risk;
      }
    } else if (r.prazo === 'Atrasado') {
      return { level: 'crit', msg: `NO PÁTIO atrasado` };
    } else if (r.prazo === 'Hoje') {
      return { level: 'warn', msg: `NO PÁTIO para hoje` };
    }
  }

  // DISPONÍVEL: se atrasado (sem timestamp, regra simples)
  if (status === 'DISPONIVEL') {
    if (r.prazo === 'Atrasado') return { level: 'warn', msg: 'DISPONÍVEL com prazo vencido' };
  }

  return null;
}

/* ──────────────────────────────────────────────────────
   Command Center: Ações rápidas na tabela
   ────────────────────────────────────────────────────── */
function fmtNowBR() {
  const d = new Date();
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yy = d.getFullYear();
  const hh = String(d.getHours()).padStart(2, '0');
  const mi = String(d.getMinutes()).padStart(2, '0');
  return `${dd}/${mm}/${yy} ${hh}:${mi}`;
}

function rowByUid(uid) {
  const id = Number(uid);
  if (!isFinite(id) || !Array.isArray(window.DB)) return null;
  return window.DB.find(r => Number(r._uid) === id) || null;
}

function togglePriority(r) {
  r.manual_prio = !r.manual_prio;
  queueOp({ type: 'prio', uid: r._uid, value: r.manual_prio, ts: Date.now() });
  toast('Prioridade', r.manual_prio ? 'Marcado como prioridade.' : 'Prioridade removida.');
}

function nextStatusOf(status) {
  const m = { 'NO PATIO': 'DESCARGA', 'DESCARGA': 'DISPONIVEL', 'DISPONIVEL': 'PLANEJADO' };
  return m[status] || null;
}

function applyStatusChange(r, next) {
  const prev = r.status_manual || r.status;
  r.status = next;
  r.status_manual = next;

  if (next === 'DESCARGA') {
    if (!r.ini_desc || r.ini_desc === 'None') r.ini_desc = fmtNowBR();
    if (r.fim_desc === 'None') r.fim_desc = '';
  }
  if (next === 'DISPONIVEL') {
    if (!r.fim_desc || r.fim_desc === 'None') r.fim_desc = fmtNowBR();
  }
  if (next === 'PLANEJADO') {
    if (!r.mercadoria_planejada || r.mercadoria_planejada === 'None') r.mercadoria_planejada = 'SIM';
  }

  queueOp({ type: 'status', uid: r._uid, from: prev, to: next, ts: Date.now() });
}

function emailCharge(r) {
  const cfg = window.APP_CFG || {};
  const to = String(cfg.emailTo || '')?.trim();
  if (!to) {
    toast('E-mail não configurado', 'Defina o e-mail do gestor nas Configurações.', 'warn');
    return;
  }
  const subj = encodeURIComponent(`[NEXUS] Acelerar liberação — ${r.ctrc || r.cod || ('UID ' + r._uid)}`);
  const risk = slaRiskForRow(r);
  const head = `Filial: ${window.FILIAL || '—'}\nStatus: ${r.status_manual || r.status || '—'}\nOrigem/Destino: ${(r.origem || '—')} → ${(r.destino || '—')}\nPeso: ${fN2(r.p_oper / 1000)} t\nValor: R$ ${fM(r.vl_nf)}\n`;
  const tail = risk ? `\nRisco SLA: ${risk.msg}${risk.cost ? `\nCusto estimado (OT): R$ ${fM(risk.cost)}` : ''}\n` : '';
  const body = encodeURIComponent(`Solicito priorização / liberação.\n\n${head}${tail}\nEnviado via NEXUS HUB.`);
  window.open(`mailto:${encodeURIComponent(to)}?subject=${subj}&body=${body}`, '_blank');
}

function copyRowSummary(r) {
  const risk = slaRiskForRow(r);
  const txt = [
    `NEXUS HUB · Ação Rápida`,
    `Filial: ${window.FILIAL || '—'}`,
    `CTRC/COD: ${r.ctrc || r.cod || ('UID ' + r._uid)}`,
    `Status: ${r.status_manual || r.status || '—'}`,
    `Origem/Destino: ${(r.origem || '—')} → ${(r.destino || '—')}`,
    `Prazo: ${r.prazo || '—'} (Dias: ${r.dias ?? '—'})`,
    `Peso: ${fN2(r.p_oper / 1000)} t`,
    `Valor: R$ ${fM(r.vl_nf)}`,
    risk ? `Risco SLA: ${risk.msg}` : ''
  ].filter(Boolean).join('\n');

  navigator.clipboard?.writeText(txt).then(() => {
    toast('Copiado', 'Resumo da linha copiado.');
  }).catch(() => {
    toast('Falha ao copiar', 'Seu navegador bloqueou a cópia automática.', 'warn');
  });
}

function handleRowAction(act, uid) {
  const r = rowByUid(uid);
  if (!r) {
    toast('Não encontrado', 'Não foi possível localizar a linha (dataset mudou).', 'warn');
    return;
  }

  if (act === 'prio') return togglePriority(r);
  if (act === 'mail') return emailCharge(r);
  if (act === 'copy') return copyRowSummary(r);

  if (act === 'next') {
    const cur = (r.status_manual || r.status);
    const nxt = nextStatusOf(cur);
    if (!nxt) {
      toast('Sem próxima etapa', 'Este status não possui transição rápida.');
      return;
    }
    applyStatusChange(r, nxt);
    rebuildSlaModel();
    persistDB();
    refreshAllSafe();
    toast('Status atualizado', `${cur} → ${nxt}`, 'success');
    return;
  }
}

document.addEventListener('click', (e) => {
  const btn = e.target?.closest?.('[data-act]');
  if (!btn) return;
  const act = btn.getAttribute('data-act');
  const uid = btn.getAttribute('data-id');
  if (!act || !uid) return;
  handleRowAction(act, uid);
});

