/* ──────────────────────────────────────────────────────
   Heatmap por hora (gargalo operacional)
   ────────────────────────────────────────────────────── */
function renderHourHeatmap() {
  const el = document.getElementById('hourHeat');
  if (!el) return;

  const rows = Array.isArray(window.DB) ? window.DB : [];
  // usar INICIO_DESCARREGAMENTO
  const bins = new Array(24).fill(0).map(() => ({ c: 0, p: 0 }));
  let hasAny = false;

  rows.forEach(r => {
    const dt = parseDateTimeSafe(r?.ini_desc);
    if (!dt) return;
    const h = dt.getHours();
    if (!(h >= 0 && h < 24)) return;
    const p = Number(r.p_oper) || 0;
    bins[h].c += 1;
    bins[h].p += (p > 0 ? p : 0);
    hasAny = true;
  });

  if (!hasAny) {
    el.innerHTML = `<div style="grid-column:1/-1;color:var(--muted);font-size:11px;padding:8px 4px;text-align:center">
      Sem horários suficientes (INICIO_DESCARREGAMENTO vazio no dataset).
    </div>`;
    return;
  }

  const maxP = Math.max(1, ...bins.map(b => b.p));
  el.innerHTML = bins.map((b, h) => {
    const k = b.p / maxP;
    const alpha = Math.max(0.06, Math.min(0.85, k * 0.85));
    const bg = `rgba(240,180,41,${alpha.toFixed(3)})`;
    const t = fN2(b.p / 1000);
    const c = b.c;
    return `<div class="cell" style="background:${bg}">
      <div class="d">${String(h).padStart(2, '0')}h</div>
      <div class="v">${t} t · ${c} CTs</div>
    </div>`;
  }).join('');
}

/* ──────────────────────────────────────────────────────
   Alertas (ticker + lista)
   ────────────────────────────────────────────────────── */
function buildAlerts() {
  const rows = Array.isArray(window.DB) ? window.DB : [];
  const alerts = [];
  rows.forEach(r => {
    const risk = slaRiskForRow(r);
    if (r.manual_prio || r.is_critico || r.is_agend || (risk && risk.level)) {
      alerts.push({ r, risk });
    }
  });

  function score(a) {
    if (a.r.manual_prio) return 0;
    if (a.r.is_critico) return 1;
    if (a.r.is_agend) return 2;
    if (a.risk?.level === 'crit') return 3;
    if (a.risk?.level === 'warn') return 4;
    return 9;
  }

  alerts.sort((a, b) => score(a) - score(b));
  return alerts;
}

function renderAlertsList() {
  const host = document.getElementById('critList');
  if (!host) return;
  const alerts = buildAlerts().slice(0, 30);

  if (!alerts.length) {
    host.innerHTML = '<div style="color:var(--muted);font-size:11px;padding:20px;text-align:center">Nenhum alerta no momento</div>';
    return;
  }

  host.innerHTML = alerts.map(({ r, risk }) => {
    let badge = ''; let badgeCls = 'bb'; let cardCls = 'crit-card';
    if (r.manual_prio) { badge = '⚡ PRIORIDADE'; badgeCls = 'bo'; }
    else if (r.is_critico) { badge = '⚡ CRÍTICO'; badgeCls = 'br'; }
    else if (r.is_agend) { badge = '📅 AGEND.'; badgeCls = 'bo'; cardCls += ' agend'; }
    else if (risk?.level) {
      badge = (risk.level === 'crit') ? '⏱ SLA CRÍTICO' : '⏱ SLA RISCO';
      badgeCls = (risk.level === 'crit') ? 'br' : 'bo';
    }

    const prazoCls = (r.prazo === 'Atrasado' ? 'br' : r.prazo === 'Hoje' ? 'bo' : 'bb');
    const cost = risk?.cost ? ` · R$ ${fM(risk.cost)}` : '';
    const opBadgeColor = r.tipo_op === 'Entrega' ? '#10a37f' : r.tipo_op === 'Reembarque' ? '#64748b' : '#3b82f6';

    return `
      <div class="${cardCls}">
        <div class="crit-top">
          <div style="display:flex; align-items:center; gap:6px;">
            <span class="crit-ctrc">${r.ctrc || r.cod || ('UID ' + r._uid)}</span>
            <span style="font-size:8px; font-weight:700; color:${opBadgeColor}; border:1px solid ${opBadgeColor}; border-radius:3px; padding:1px 4px; line-height:1;">${(r.tipo_op || '').toUpperCase()}</span>
          </div>
          <span class="b ${badgeCls}" title="${risk ? risk.msg + cost : ''}">${badge}</span>
        </div>
        <div class="crit-bot">
          <span>${r.origem || '—'} → ${r.destino || '—'}</span>
          <span>${r.cidade || '—'}</span>
          <span class="b ${prazoCls}">${r.prazo || '—'}</span>
          <span>${fN2(r.p_oper)} kg</span>
          <span>R$ ${fM(r.vl_nf)}</span>
        </div>
      </div>
    `;
  }).join('');
}

function renderTicker() {
  const cfg = window.APP_CFG || {};
  const tk = document.getElementById('alertTicker');
  if (!tk) return;
  if (!cfg.ticker) {
    tk.style.display = 'none';
    return;
  }
  tk.style.display = '';

  const el = document.getElementById('tickerContent');
  if (!el) return;

  const alerts = buildAlerts().slice(0, 18);
  if (!alerts.length) {
    el.textContent = 'Nenhum alerta ativo';
    return;
  }

  el.innerHTML = alerts.map(({ r, risk }) => {
    const baseId = (r.ctrc || r.cod || ('UID ' + r._uid));
    const st = (r.status_manual || r.status || '—').replace('DISPONIVEL', 'DISP').replace('PLANEJADO', 'PLAN');
    const flag = r.manual_prio ? '⚡' : r.is_critico ? '⚡' : r.is_agend ? '📅' : (risk?.level === 'crit' ? '⏱' : '⏱');
    const extra = risk ? (risk.level === 'crit' ? 'SLA CRÍTICO' : 'SLA RISCO') : (r.is_critico ? 'CRÍTICO' : r.is_agend ? 'AGEND.' : 'PRIORIDADE');
    return `<span>${flag} ${baseId} · ${st} · ${extra}</span><span class="sep">•</span>`;
  }).join('');
}

