/* ──────────────────────────────────────────────────────
   Theming fix: Donut chart text (evita branco no branco no light)
   ────────────────────────────────────────────────────── */
(function () {
  if (typeof buildDonut !== 'function') return;

  function cssVar(name, fallback) {
    try {
      const v = getComputedStyle(document.documentElement).getPropertyValue(name);
      return (v && v?.trim()) ? v?.trim() : fallback;
    } catch (e) { return fallback; }
  }

  window.buildDonut = function (data) {
    const el = document.getElementById('donut');
    if (!el) { return; }

    const total = (data || []).reduce((a, b) => a + (b.v || 0), 0) || 1;
    const r = 62, cx = 90, cy = 90;
    const C = 2 * Math.PI * r;
    let acc = 0;

    const theme = (document.documentElement.getAttribute('data-theme') || 'dark');
    const baseStroke = (theme === 'light') ? 'rgba(2,6,23,.12)' : 'rgba(255,255,255,.06)';
    const mainTxt = cssVar('--txt', '#e7e7e7');
    const mutedTxt = cssVar('--muted2', 'rgba(231,231,231,.8)');

    const arcs = data.map((it, i) => {
      const frac = (it.v || 0) / total;
      const len = frac * C;
      const dash = `${len} ${C - len}`;
      const off = C * acc;
      acc += frac;
      return `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${it.c}" stroke-width="14"
         stroke-dasharray="${dash}" stroke-dashoffset="${-off}" stroke-linecap="round"/>`;
    }).join('');

    const pct = Math.round(((data[0]?.v || 0) / total) * 100);
    el.innerHTML = `
    <svg viewBox="0 0 180 180" width="100%" height="100%">
      <circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${baseStroke}" stroke-width="14"/>
      ${arcs}
      <circle cx="${cx}" cy="${cy}" r="${r - 18}" fill="none" stroke="${baseStroke}" stroke-width="1"/>
      <text x="${cx}" y="${cy + 6}" text-anchor="middle" font-size="24" fill="${mainTxt}" font-family="Share Tech Mono, monospace">${pct}%</text>
      <text x="${cx}" y="${cy + 28}" text-anchor="middle" font-size="10" fill="${sanitizeHTML(mutedTxt)}" font-family="Syne, sans-serif">DISPONÍVEL</text>
    </svg>`;
  };
})();


