// ── Browser Notifications ──────────────────────────────
async function requestNotifPermission() {
  if (!('Notification' in window)) {
    toast('Notificações', 'Seu browser não suporta notificações nativas.', 'warn');
    return false;
  }
  if (Notification.permission === 'granted') {
    toast('Notificações', 'Notificações já estão ativas. ✓');
    return true;
  }
  const perm = await Notification.requestPermission();
  if (perm === 'granted') {
    toast('Notificações ativadas', 'Você receberá alertas de CTs críticos mesmo fora desta aba. 🔔');
    // Demo notification
    new Notification('NEXUS HUB — Alertas ativos', {
      body: 'Você será notificado quando CTs críticos precisarem de atenção.',
      icon: 'icon-192.png', tag: 'nexus-welcome'
    });
    return true;
  }
  toast('Permissão negada', 'Notificações bloqueadas pelo browser.', 'warn');
  return false;
}

function notifyCritical(ct) {
  if (!ct || Notification.permission !== 'granted' || document.hasFocus()) return;
  new Notification(`⚡ CT Crítico — ${ct.ctrc || ct.cod || '—'}`, {
    body: `${ct.origem || '?'} → ${ct.destino || '?'} · ${fN2(ct.p_oper / 1000)} t · Prazo: ${ct.prazo}`,
    icon: 'icon-192.png',
    tag: 'nx_ct_' + (ct.ctrc || ct._uid)
  });
}

// Auto-notify on new critical CTs (called after renderDashboard)
let __lastCritSet = new Set();
function checkAndNotifyCrits() {
  try {
    if (Notification.permission !== 'granted') return;
    const crits = DB.filter(r => r.is_critico && r.prazo === 'Atrasado');
    crits.forEach(r => {
      const id = String(r.ctrc || r._uid);
      if (!__lastCritSet.has(id)) { notifyCritical(r); }
    });
    __lastCritSet = new Set(crits.map(r => String(r.ctrc || r._uid)));
  } catch (e) { if (window.__DEV) console.warn('[NX] notif:', e); }
}

// ── Focus Mode (Fullscreen para apresentações) ─────────
let __focusMode = false;
function toggleFocusMode() {
  __focusMode = !__focusMode;
  document.body.classList.toggle('nx-focus-mode', __focusMode);
  if (__focusMode) {
    try { document.documentElement.requestFullscreen?.(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    toast('Modo Foco', 'Pressione F11, ESC ou Ctrl+K → Modo Foco para sair. ⛶');
  } else {
    try { if (document.fullscreenElement) document.exitFullscreen?.(); } catch (e) { if (window.__DEV) console.warn("[NX]", e); }
    toast('Modo Normal', 'UI restaurada.');
  }
}
// Sync focus mode with fullscreen API
document.addEventListener('fullscreenchange', () => {
  if (!document.fullscreenElement && __focusMode) {
    __focusMode = false;
    document.body.classList.remove('nx-focus-mode');
  }
});
// F11 key shortcut
document.addEventListener('keydown', e => {
  if (e.key === 'F11') { e.preventDefault(); toggleFocusMode(); }
});

// ── URL State for Filters (deeplink support) ───────────
let __urlStateEnabled = true;

function pushFilterState(page, filters) {
  if (!__urlStateEnabled) return;
  try {
    const params = new URLSearchParams();
    Object.entries(filters).forEach(([k, v]) => { if (v) params.set(k, v); });
    const hash = page + (params.toString() ? '?' + params.toString() : '');
    history.replaceState(null, '', '#' + hash);
  } catch (e) { if (window.__DEV) console.warn('[NX] urlState:', e); }
}

function readFilterState() {
  try {
    const raw = location.hash.slice(1);
    if (!raw) return null;
    const [page, qs] = raw.split('?');
    const filters = qs ? Object.fromEntries(new URLSearchParams(qs)) : {};
    return { page, filters };
  } catch (e) { return null; }
}

function restoreFilterStateIfAny() {
  const state = readFilterState();
  if (!state || !state.page) return;
  try {
    const navEl = document.querySelector(`.nav .nt[data-page="${state.page}"]`);
    if (navEl) goPage(state.page, navEl);
    const { filters } = state;
    // Apply basic filter restoration
    if (filters.search) {
      const srchEl = document.getElementById(state.page + 'Srch');
      if (srchEl) { srchEl.value = filters.search; }
    }
    if (filters.dest) {
      const destEl = document.getElementById(state.page.replace('atrasados', 'atr') + 'Dest');
      if (destEl) destEl.value = filters.dest;
    }
    toast('Filtro restaurado', `Voltou para: ${state.page}${filters.search ? ' — ' + filters.search : ''}`);
  } catch (e) { if (window.__DEV) console.warn('[NX] restoreState:', e); }
}

