// ── Touch Swipe Gestures ──────────────────────────────────────
let touchStartX = 0;
let touchStartY = 0;
let touchEndX = 0;
let touchEndY = 0;

function handleSwipe() {
  const deltaX = touchEndX - touchStartX;
  const deltaY = touchEndY - touchStartY;
  const minSwipeDistance = 50;

  // Horizontal swipe
  if (Math.abs(deltaX) > Math.abs(deltaY) && Math.abs(deltaX) > minSwipeDistance) {
    if (deltaX > 0) {
      // Swipe right - open sidebar
      if (window.innerWidth <= 1023) {
        document.querySelector('.sb')?.classList.add('visible');
        document.querySelector('.sb-overlay')?.classList.add('visible');
      }
    } else {
      // Swipe left - close sidebar
      if (window.innerWidth <= 1023) {
        document.querySelector('.sb')?.classList.remove('visible');
        document.querySelector('.sb-overlay')?.classList.remove('visible');
      }
    }
  }

  // Vertical swipe down on top of page - refresh
  if (deltaY > minSwipeDistance && window.scrollY === 0 && deltaY > Math.abs(deltaX)) {
    refreshCurrentPage();
  }
}

function refreshCurrentPage() {
  const currentPage = window._currentPage || 'atrasados';
  toast('Atualizando...', '↻ Recarregando dados');

  // Show skeleton
  showSkeletonKPIs();

  // Reload page data
  setTimeout(() => {
    try {
      // Recalculate KPIs
      updateAllKPIs();

      // Refresh current table
      switch (currentPage) {
        case 'atrasados':
          if (window.__tabAtrasados) window.__tabAtrasados.setData();
          break;
        case 'pend':
          if (window.__tabPendentes) window.__tabPendentes.setData();
          break;
        case 'transit':
          if (window.__tabTransito) window.__tabTransito.setData();
          break;
        case 'entregues':
          if (window.__tabEntregues) window.__tabEntregues.setData();
          break;
      }

      hideSkeletonKPIs();
      toast('✓ Atualizado', 'Dados recarregados com sucesso');
    } catch (e) {
      hideSkeletonKPIs();
      toast('Erro', 'Falha ao atualizar: ' + e.message);
    }
  }, 800);
}

// Attach touch event listeners
document.addEventListener('touchstart', e => {
  touchStartX = e.changedTouches[0].screenX;
  touchStartY = e.changedTouches[0].screenY;
}, { passive: true });

document.addEventListener('touchend', e => {
  touchEndX = e.changedTouches[0].screenX;
  touchEndY = e.changedTouches[0].screenY;
  handleSwipe();
}, { passive: true });

// ── Apply Debounce to Search/Filter Inputs ───────────────────
function optimizeSearchInputs() {
  const searchInputs = document.querySelectorAll('input[type="search"], input[type="text"][id*="Srch"]');

  searchInputs.forEach(input => {
    const originalHandler = input.oninput;
    if (originalHandler) {
      input.oninput = debounce(originalHandler, 300);
    }

    // Also debounce any addEventListener('input')
    const events = getEventListeners?.(input)?.input || [];
    events.forEach((event, i) => {
      if (i === 0 && event.listener) { // Only first listener typically
        input.removeEventListener('input', event.listener);
        input.addEventListener('input', debounce(event.listener, 300));
      }
    });
  });
}

