// EXECUÇÃO ONE
// ══════════════════════════════════════════════════════════════
window.baseManhaData = [];

async function processBaseManhaUpload() {
  const fileInput = document.getElementById('uploadBaseManha');
  if (!fileInput.files || fileInput.files.length === 0) {
    if (typeof showToast === 'function') toastManager.info('Selecione o arquivo Base da Manhã (.xlsx)', 'warning');
    else alert('Selecione o arquivo Base da Manhã (.xlsx)');
    return;
  }
  const file = fileInput.files[0];
  showLoad('Lendo Base da Manhã...', 30);
  await sleep(50);
  try {
    const data = await file.arrayBuffer();
    showLoad('Processando ' + file.name + '...', 60);

    const canWorker = typeof Worker !== 'undefined' && typeof URL !== 'undefined' && typeof Blob !== 'undefined';
    if (canWorker) {
      const workerSrc = `
        self.importScripts('https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js');
        self.onmessage = function(e){
          try{
            const wb = XLSX.read(e.data.buffer, {type:'array'});
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, {defval:''});
            self.postMessage({ok:true, rows:rows});
          }catch(err){
            self.postMessage({ok:false, error: err.message||String(err)});
          }
        };
      `;
      const blob = new Blob([workerSrc], { type: 'application/javascript' });
      const url = URL.createObjectURL(blob);
      const wk = new Worker(url);

      wk.postMessage({ buffer: data }, [data]);
      await new Promise((resolve, reject) => {
        wk.onmessage = ({ data: res }) => {
          URL.revokeObjectURL(url); wk.terminate();
          if (!res.ok) { reject(new Error(res.error)); return; }
          const TODAY_BASE = new Date(); TODAY_BASE.setHours(0, 0, 0, 0);
          const TOMORROW_BASE = new Date(TODAY_BASE); TOMORROW_BASE.setDate(TODAY_BASE.getDate() + 1);

          let processed = res.rows.map(r => {
            let row = processXLSXRow(r, FILIAL, TODAY_BASE, TOMORROW_BASE);
            if (row) {
              if (row.status === 'PLANEJADO') {
                row.status = 'DISPONIVEL';
              }
            }
            return row;
          }).filter(Boolean);
          window.baseManhaData = aggregateDB(processed);
          resolve();
        };
        wk.onerror = (err) => { URL.revokeObjectURL(url); wk.terminate(); reject(err); };
      });
    } else {
      const wb = XLSX.read(data, { type: 'array' });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
      const TODAY_BASE = new Date(); TODAY_BASE.setHours(0, 0, 0, 0);
      const TOMORROW_BASE = new Date(TODAY_BASE); TOMORROW_BASE.setDate(TODAY_BASE.getDate() + 1);

      let processed = rows.map(r => {
        let row = processXLSXRow(r, FILIAL, TODAY_BASE, TOMORROW_BASE);
        if (row) {
          if (row.status === 'PLANEJADO') {
            row.status = 'DISPONIVEL';
          }
        }
        return row;
      }).filter(Boolean);
      window.baseManhaData = aggregateDB(processed);
    }

    hideLoad();
    renderExecucaoOne();
    if (typeof showToast === 'function') toastManager.info('Base da Manhã Carregada', 'success');
  } catch (e) {
    hideLoad();
    alert('Erro ao ler Base da Manhã: ' + e.message);
  }
}

function renderExecucaoOne() {
  if (!window.baseManhaData || window.baseManhaData.length === 0) return;

  const isPriority = document.getElementById('execOneFilterPriority').checked;
  document.getElementById('execOneFilterLabel').textContent = isPriority ? 'Prioridade' : 'Geral';

  let dataManha = window.baseManhaData;
  let dataAtual = DB || [];

  if (isPriority) {
    dataManha = dataManha.filter(r => r.prio_fluxo === 'Prioridade');
  }

  const codAtualMap = new Set(dataAtual.map(r => r.cod));
  // Count Planejado or Programado in base atual
  const planAtualSet = new Set(dataAtual.filter(r => r.status === 'PLANEJADO' || r.status === 'PROGRAMADO').map(r => r.cod));

  let resultData = dataManha.map(r => {
    // Consider patio, descarga, intermediario, disponivel
    let isEstoqueManha = ['NO PATIO', 'PATIO', 'DESCARGA', 'INTERMEDIARIO', 'DISPONIVEL'].includes(r.status);

    let programado = 0;
    let executado = 0;
    let totalPlano = 1;

    if (!codAtualMap.has(r.cod)) {
      executado = 1;
      programado = 1; // Se foi executado, então também estava programado
    } else if (isEstoqueManha && planAtualSet.has(r.cod)) {
      programado = 1;
    }

    return {
      ctrc: r.ctrc,
      cod: r.cod,
      destino: r.destino,
      region: String(r.destino || '').toUpperCase()?.trim(),
      totalPlano: totalPlano,
      programado: programado,
      executado: executado
    };
  });

  const _regionOf = (code) => {
    const k = String(code || '').toUpperCase()?.trim();
    return typeof REGION_MAP !== 'undefined' ? (REGION_MAP[k] || 'Outros') : 'Outros';
  };

  const byRegion = groupBy(resultData, r => _regionOf(r.destino));
  let tableData = [];

  let globalTotal = 0;
  let globalProg = 0;
  let globalExec = 0;

  for (const [region, rowsRegion] of byRegion.entries()) {
    const byDest = groupBy(rowsRegion, r => String(r.destino || '—').toUpperCase()?.trim() || '—');

    let children = [];
    let regTotal = 0;
    let regProg = 0;
    let regExec = 0;

    for (const [dest, rows] of byDest.entries()) {
      let destTotal = rows.reduce((s, x) => s + x.totalPlano, 0);
      let destProg = rows.reduce((s, x) => s + x.programado, 0);
      let destExec = rows.reduce((s, x) => s + x.executado, 0);

      let pProgPlano = destTotal > 0 ? (destProg / destTotal) : 0;
      let pExecPlano = destTotal > 0 ? (destExec / destTotal) : 0;
      let pExecProg = destProg > 0 ? (destExec / destProg) : 0;

      children.push({
        region: region,
        dest: dest,
        totalPlano: destTotal,
        programado: destProg,
        executado: destExec,
        pProgPlano: pProgPlano,
        pExecPlano: pExecPlano,
        pExecProg: pExecProg,
        _leaf: true
      });

      regTotal += destTotal;
      regProg += destProg;
      regExec += destExec;
    }

    let regProgPlano = regTotal > 0 ? (regProg / regTotal) : 0;
    let regExecPlano = regTotal > 0 ? (regExec / regTotal) : 0;
    let regExecProg = regProg > 0 ? (regExec / regProg) : 0;

    tableData.push({
      region: region,
      dest: region,
      totalPlano: regTotal,
      programado: regProg,
      executado: regExec,
      pProgPlano: regProgPlano,
      pExecPlano: regExecPlano,
      pExecProg: regExecProg,
      _children: children.sort((a, b) => b.totalPlano - a.totalPlano)
    });

    globalTotal += regTotal;
    globalProg += regProg;
    globalExec += regExec;
  }

  tableData.sort((a, b) => a.region.localeCompare(b.region));

  document.getElementById('kpiProgPlano').textContent = (globalTotal > 0 ? (globalProg / globalTotal) * 100 : 0).toFixed(1) + '%';
  document.getElementById('kpiExecPlano').textContent = (globalTotal > 0 ? (globalExec / globalTotal) * 100 : 0).toFixed(1) + '%';
  document.getElementById('kpiExecProg').textContent = (globalProg > 0 ? (globalExec / globalProg) * 100 : 0).toFixed(1) + '%';

  const pctFormatter = function (cell) {
    const val = cell.getValue();
    const pct = val * 100;
    let color = '';
    // Logística: Verde bom, Vermelho ruim
    if (pct >= 80) color = '#10a37f';
    else if (pct >= 50) color = '#f0b429';
    else color = '#f03d3d';

    return `<span style="font-weight:600; color:${color}">${pct.toFixed(1)}%</span>`;
  };

  if (!window._execOneTable) {
    const tableContainer = document.getElementById("execOneTable");
    if (tableContainer) {
      tableContainer.style.minHeight = "400px";
    }

    window._execOneTable = new Tabulator("#execOneTable", {
      data: tableData,
      layout: "fitColumns",
      height: "100%",
      minHeight: 400,
      dataTree: true,
      dataTreeStartExpanded: false,
      dataTreeChildIndent: 15,
      columns: [
        { title: "Região / Destino", field: "dest", widthGrow: 2 },
        { title: "Plano Manhã", field: "totalPlano", hozAlign: "center" },
        { title: "Programado", field: "programado", hozAlign: "center" },
        { title: "Executado", field: "executado", hozAlign: "center" },
        { title: "% Prog vs Plano", field: "pProgPlano", hozAlign: "center", formatter: pctFormatter },
        { title: "% Exec x Plano", field: "pExecPlano", hozAlign: "center", formatter: pctFormatter },
        { title: "% Exec x Prog", field: "pExecProg", hozAlign: "center", formatter: pctFormatter }
      ]
    });
  } else {
    window._execOneTable.setData(tableData);
  }
}

